// xlsx is ~130KB gzip and only used in import/export handlers — never on first
// paint. Load it on demand (one cached dynamic import) so it stays OUT of the
// boot chunk that every visitor downloads, including the customer QR-scan
// (?scan=1) and POS PIN (?pos=1) routes that can never import/export.
let _xlsxMod;
const loadXLSX=async()=>{ if(!_xlsxMod){ const m=await import("xlsx"); _xlsxMod=(m&&m.utils)?m:((m&&m.default)||m); } return _xlsxMod; };

const SUPA_URL = "https://niplvsfxynrufiyvbwme.supabase.co";
const SUPA_KEY = "sb_publishable_jpym6Xg4gOIPWDUDt5IntQ_7Bbh9KcZ";

async function sb(path, opts = {}) {
  const {headers:extraH, prefer, ...fetchOpts} = opts;
  const res = await fetch(`${SUPA_URL}/rest/v1/${path}`, {
    ...fetchOpts,
    headers: { "apikey": SUPA_KEY, "Authorization": `Bearer ${SUPA_KEY}`, "Content-Type": "application/json", "Prefer": prefer || "return=representation", ...extraH },
  });
  if (!res.ok) throw new Error(await res.text());
  const text = await res.text();
  return text ? JSON.parse(text) : [];
}

// === Production-grade helpers ============================================
// Money: round to 2 decimals using "banker's-safe" half-away-from-zero
const round2 = (n) => Math.round((+n||0)*100)/100;
// Currency formatter (Thai Baht, always 2 decimals)
const fmtTHB = (n) => `฿${(+n||0).toLocaleString("en-US",{minimumFractionDigits:2,maximumFractionDigits:2})}`;
// Today in Asia/Bangkok (YYYY-MM-DD) — avoids UTC off-by-one near midnight
const todayBkk = () => new Date().toLocaleDateString("en-CA",{timeZone:"Asia/Bangkok"});
// Current minutes-of-day in Asia/Bangkok (0–1439), regardless of the device timezone.
function bkkNowMinutes(){
  try{
    const p=new Intl.DateTimeFormat("en-GB",{timeZone:"Asia/Bangkok",hour:"2-digit",minute:"2-digit",hour12:false}).formatToParts(new Date());
    const h=+((p.find(x=>x.type==="hour")||{}).value||0);
    const m=+((p.find(x=>x.type==="minute")||{}).value||0);
    return (h%24)*60+m;
  }catch{const d=new Date();return d.getHours()*60+d.getMinutes();}
}
// Allowed stock-count window (Asia/Bangkok, minutes-of-day). Branch 16:00–23:30 · Central 12:00–16:00.
function stockCountWindow(isCentral){ return isCentral?{s:12*60,e:16*60,lbl:"12:00–16:00"}:{s:16*60,e:23*60+30,lbl:"16:00–23:30"}; }
const hhmmOfMin=m=>`${String(Math.floor(m/60)).padStart(2,"0")}:${String(m%60).padStart(2,"0")}`;
// Friendly error mapping (avoid leaking Postgres internals to cashiers)
function friendlyError(err){
  const raw=(err&&err.message)?err.message:String(err||"");
  if(/duplicate key/.test(raw))return "ข้อมูลซ้ำกับที่มีอยู่ในระบบ";
  if(/violates row-level security/.test(raw))return "ไม่มีสิทธิ์ทำรายการนี้ — กรุณาติดต่อแอดมิน";
  if(/violates foreign key/.test(raw))return "ข้อมูลที่อ้างอิงไม่ถูกต้อง — อาจมีรายการที่เกี่ยวข้องถูกลบไปแล้ว";
  if(/violates not-null/.test(raw))return "ข้อมูลที่จำเป็นยังไม่ครบ — ตรวจสอบฟอร์มอีกครั้ง";
  if(/violates check constraint/.test(raw))return "ข้อมูลไม่ถูกต้องตามกติกาของระบบ";
  if(/Failed to fetch|NetworkError/.test(raw))return "เชื่อมต่อเซิร์ฟเวอร์ไม่ได้ — ตรวจสอบอินเทอร์เน็ต";
  if(raw.length>120)return "ทำรายการไม่สำเร็จ ลองใหม่อีกครั้ง";
  return raw||"เกิดข้อผิดพลาด";
}
// Show friendly error + log raw to console in dev only
function showErr(prefix,err){console.error(prefix,err);alert(prefix+": "+friendlyError(err));}
// Detect image MIME from magic bytes (browser File). Returns 'image/jpeg' | 'image/png' | 'image/webp' | null
async function detectImageMime(file){
  const buf=await file.slice(0,12).arrayBuffer();
  const b=new Uint8Array(buf);
  if(b[0]===0xFF&&b[1]===0xD8&&b[2]===0xFF)return "image/jpeg";
  if(b[0]===0x89&&b[1]===0x50&&b[2]===0x4E&&b[3]===0x47)return "image/png";
  if(b[0]===0x47&&b[1]===0x49&&b[2]===0x46)return "image/gif";
  if(b[0]===0x52&&b[1]===0x49&&b[2]===0x46&&b[3]===0x46&&b[8]===0x57&&b[9]===0x45&&b[10]===0x42&&b[11]===0x50)return "image/webp";
  return null;
}
// Open print/PDF popup with blocker detection — caller falls back if returns null
function openPrintWindow(width=860,height=900){
  const w=window.open("","_blank",`width=${width},height=${height}`);
  if(!w){alert("เบราว์เซอร์บล็อกหน้าต่างพิมพ์ — กรุณาอนุญาต popup ในแถบที่อยู่ของเบราว์เซอร์ แล้วลองอีกครั้ง");return null;}
  return w;
}
// Print HTML WITHOUT opening a popup window — renders into a hidden iframe and prints
// that. Works even when called AFTER an await (no popup-blocker, no blank about:blank
// window). Use this where the print is triggered after async work (e.g. create-then-print).
function printHtml(html){
  try{
    const iframe=document.createElement("iframe");
    iframe.setAttribute("aria-hidden","true");
    iframe.style.cssText="position:fixed;left:-99999px;top:0;width:794px;height:1123px;border:0;opacity:0;pointer-events:none";
    document.body.appendChild(iframe);
    const cw=iframe.contentWindow,doc=cw.document;
    doc.open();doc.write(html);doc.close();
    let cleaned=false;const cleanup=()=>{if(cleaned)return;cleaned=true;setTimeout(()=>{try{document.body.removeChild(iframe);}catch{}},300);};
    try{cw.addEventListener("afterprint",cleanup);}catch{}
    let printed=false;const doPrint=()=>{if(printed)return;printed=true;try{cw.focus();cw.print();}catch{}};
    iframe.onload=()=>setTimeout(doPrint,200);
    setTimeout(doPrint,800);       // fallback if onload doesn't fire
    setTimeout(cleanup,60000);     // safety: never leak the iframe
    return true;
  }catch(e){return false;}
}
// แปะแถบปุ่ม "🖨 พิมพ์ / ✕ ปิดหน้าต่าง" ลอยบนสุดของทุกหน้าต่างพิมพ์/พรีวิว (ซ่อนตอนพิมพ์จริง) — เรียกหลัง document.close()
function addPrintClose(w){
  if(!w)return;
  const inject=()=>{try{
    const d=w.document;if(!d||!d.body||d.getElementById("fc-closebar"))return;
    if(d.head){const st=d.createElement("style");st.textContent="@media print{.fc-noprint{display:none!important}}";d.head.appendChild(st);}
    d.body.insertAdjacentHTML("afterbegin",`<div id="fc-closebar" class="fc-noprint" style="position:fixed;top:0;left:0;right:0;display:flex;gap:10px;justify-content:center;padding:9px;background:#f8fafc;border-bottom:1px solid #cbd5e1;z-index:99999;box-shadow:0 2px 6px rgba(0,0,0,.12)"><button onclick="window.print()" style="padding:9px 20px;border:none;border-radius:9px;background:#0D9488;color:#fff;font-weight:800;font-size:15px;cursor:pointer;font-family:sans-serif">🖨 พิมพ์</button><button onclick="window.close()" style="padding:9px 22px;border:none;border-radius:9px;background:#64748b;color:#fff;font-weight:800;font-size:15px;cursor:pointer;font-family:sans-serif">✕ ปิดหน้าต่าง</button></div><div class="fc-noprint" style="height:52px"></div>`);
  }catch(e){}};
  inject();try{w.addEventListener&&w.addEventListener("load",inject);}catch{}
}
// Random suffix for filenames so they're not enumerable by sequential ID
const randId=()=>Math.random().toString(36).slice(2,10)+Date.now().toString(36).slice(-4);
// HTML-escape user-content before injecting into print popup HTML (XSS guard)
const esc=(s)=>String(s==null?"":s).replace(/[&<>"']/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]));
// UUID v4 that also works on an insecure context (http:// on the LAN). crypto.randomUUID
// is gated to secure contexts (HTTPS/localhost) and is undefined on a plain-http LAN page,
// so we fall back to crypto.getRandomValues (available everywhere) then Math.random.
function uuidv4(){
  try{if(typeof crypto!=="undefined"&&crypto.randomUUID)return crypto.randomUUID();}catch{}
  try{if(typeof crypto!=="undefined"&&crypto.getRandomValues){const b=crypto.getRandomValues(new Uint8Array(16));b[6]=(b[6]&0x0f)|0x40;b[8]=(b[8]&0x3f)|0x80;const h=[...b].map(x=>x.toString(16).padStart(2,"0"));return `${h[0]}${h[1]}${h[2]}${h[3]}-${h[4]}${h[5]}-${h[6]}${h[7]}-${h[8]}${h[9]}-${h[10]}${h[11]}${h[12]}${h[13]}${h[14]}${h[15]}`;}}catch{}
  return "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g,c=>{const r=Math.random()*16|0;const v=c==="x"?r:(r&0x3|0x8);return v.toString(16);});
}
// Canonical PUBLIC base URL for CUSTOMER-facing links (table-scan QR codes that
// customers open on their own phone via mobile data). When the staff app is served
// over http:// on the LAN, window.location.origin is a private IP customers can't
// reach — so set PUBLIC_APP_URL to the live Vercel address and customer QRs always
// point there. Empty string → fall back to the current origin (default; no change).
const PUBLIC_APP_URL = "https://foodcost-eta.vercel.app";   // live public URL — customer-scan QR links always point here (so QRs printed from the http LAN page still open for customers on mobile data)
function publicBaseUrl(){
  const raw=PUBLIC_APP_URL||((typeof window!=="undefined")?window.location.origin+window.location.pathname:"");
  return raw.replace(/\/+$/,"")+"/";
}

