  const[open,setOpen]=useState(false);const[pos,setPos]=useState(null);const btnRef=useRef();
  useEffect(()=>{if(!open)return;const close=()=>setOpen(false);window.addEventListener("click",close);window.addEventListener("scroll",close,true);window.addEventListener("resize",close);return()=>{window.removeEventListener("click",close);window.removeEventListener("scroll",close,true);window.removeEventListener("resize",close);};},[open]);
