  const title=o.title||(danger?"ยืนยันการลบ":"ยืนยัน");
  const msg=o.message||"ต้องการดำเนินการนี้ใช่หรือไม่?";
  const ok=o.confirmLabel||(danger?"ลบ":"ยืนยัน");
