// PromptPay payload generator (anyId QR per Bank of Thailand spec)
function genPromptPayPayload(id,amount){
  if(!id)return"";
  // Sanitize: keep digits only
  const num=String(id).replace(/\D/g,"");
  if(num.length<10)return"";
  let target=num;
  if(num.length===10)target="0066"+num.slice(1);     // 10-digit phone
  else if(num.length===13)target=num;                  // 13-digit citizen ID
  else target=num;
  const tagPP="0016A000000677010111"+(num.length===13?"02"+String(target.length).padStart(2,'0')+target:"01"+String(target.length).padStart(2,'0')+target);
  // Build TLV
  function tlv(tag,val){return tag+String(val.length).padStart(2,'0')+val;}
  let p="";
  p+=tlv("00","01");
  p+=tlv("01",amount?"12":"11");
  p+=tlv("29",tagPP);
  p+=tlv("53","764");
  if(amount)p+=tlv("54",(+amount).toFixed(2));
  p+=tlv("58","TH");
  p+="6304";
  // CRC16 CCITT-FALSE
  let crc=0xFFFF;
  for(let i=0;i<p.length;i++){crc^=p.charCodeAt(i)<<8;for(let j=0;j<8;j++)crc=(crc&0x8000)?((crc<<1)^0x1021)&0xFFFF:(crc<<1)&0xFFFF;}
  return p+crc.toString(16).toUpperCase().padStart(4,'0');
}
function POSSettingsPanel({currentBranch}){
  const[settings,setSettings]=useState(null);const[loading,setLoading]=useState(true);const[saving,setSaving]=useState(false);
  async function load(){setLoading(true);try{const s=await api.getPOSSettings(currentBranch.id);setSettings((s&&s[0])||{branch_id:currentBranch.id,vat_enabled:false,vat_rate:7,vat_included:true,service_charge_enabled:false,service_charge_rate:10,promptpay_id:"",promptpay_name:"",show_qr_promptpay:false,receipt_header:"",receipt_footer:""});}catch(e){alert("โหลดไม่สำเร็จ: "+e.message);}setLoading(false);}
  useEffect(()=>{load();},[currentBranch.id]);
  async function save(){
    setSaving(true);
    try{
      const d={...settings,branch_id:currentBranch.id,updated_at:new Date().toISOString()};
      delete d.id;
      const res=await api.upsertPOSSettings(d);
      if(Array.isArray(res)&&res[0])setSettings(res[0]);
      alert("บันทึกการตั้งค่าเรียบร้อย");
    }catch(e){alert("บันทึกไม่สำเร็จ: "+e.message);}
    setSaving(false);
  }
  if(loading||!settings)return <Loading text="โหลดการตั้งค่า..."/>;
  function set(k,v){setSettings(s=>({...s,[k]:v}));}
  const qrPreview=settings.show_qr_promptpay&&settings.promptpay_id?genPromptPayPayload(settings.promptpay_id,100):"";
  return <div style={{maxWidth:780}}>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
      <h3 style={{fontFamily:"'Sarabun',sans-serif",fontSize:18,fontWeight:900,color:C.ink,margin:0}}>⚙️ ตั้งค่า POS — {currentBranch.name}</h3>
      <Btn onClick={save} icon={I.save} loading={saving} s={{padding:"9px 18px"}}>บันทึก</Btn>
    </div>

    {/* VAT */}
    <Card style={{padding:18,marginBottom:14}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12}}>
        <div>
          <div style={{fontFamily:"'Sarabun',sans-serif",fontSize:15,fontWeight:800,color:C.ink}}>📊 ภาษีมูลค่าเพิ่ม (VAT)</div>
          <div style={{fontSize:11,color:C.ink4,fontFamily:"'Sarabun',sans-serif",marginTop:2}}>กำหนดอัตราภาษีและวิธีคิด</div>
        </div>
        <label style={{position:"relative",display:"inline-block",width:48,height:26}}>
          <input type="checkbox" checked={!!settings.vat_enabled} onChange={e=>set('vat_enabled',e.target.checked)} style={{opacity:0,width:0,height:0}}/>
          <span style={{position:"absolute",cursor:"pointer",inset:0,background:settings.vat_enabled?C.brand:"#cbd5e1",borderRadius:26,transition:".2s"}}/>
          <span style={{position:"absolute",content:"",height:20,width:20,left:settings.vat_enabled?25:3,top:3,background:C.white,borderRadius:"50%",transition:".2s",boxShadow:"0 2px 4px rgba(0,0,0,.2)"}}/>
        </label>
      </div>
      {settings.vat_enabled&&<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
        <div>
          <div style={{fontSize:12,color:C.ink2,fontWeight:700,marginBottom:5,fontFamily:"'Sarabun',sans-serif"}}>อัตรา VAT (%)</div>
          <input type="text" inputMode="decimal" step="0.01" value={settings.vat_rate} onChange={e=>set('vat_rate',+e.target.value)} style={{...iS,fontSize:15,fontWeight:700}}/>
        </div>
        <div>
          <div style={{fontSize:12,color:C.ink2,fontWeight:700,marginBottom:5,fontFamily:"'Sarabun',sans-serif"}}>วิธีคิด VAT</div>
          <div style={{display:"flex",gap:0,borderRadius:10,overflow:"hidden",border:`1.5px solid ${C.line}`}}>
            {[{v:true,l:"รวมในราคา (Inclusive)"},{v:false,l:"บวกเพิ่ม (Exclusive)"}].map(o=><button key={String(o.v)} onClick={()=>set('vat_included',o.v)} style={{flex:1,padding:"10px 0",border:"none",background:settings.vat_included===o.v?`linear-gradient(135deg,${C.brand},${C.brandDark})`:C.white,color:settings.vat_included===o.v?C.white:C.ink3,fontFamily:"'Sarabun',sans-serif",fontSize:12,fontWeight:700,cursor:"pointer"}}>{o.l}</button>)}
          </div>
        </div>
      </div>}
    </Card>

    {/* Service Charge */}
    <Card style={{padding:18,marginBottom:14}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12}}>
        <div>
          <div style={{fontFamily:"'Sarabun',sans-serif",fontSize:15,fontWeight:800,color:C.ink}}>💼 Service Charge</div>
          <div style={{fontSize:11,color:C.ink4,fontFamily:"'Sarabun',sans-serif",marginTop:2}}>ค่าบริการที่จะคิดเพิ่มในบิล</div>
        </div>
        <label style={{position:"relative",display:"inline-block",width:48,height:26}}>
          <input type="checkbox" checked={!!settings.service_charge_enabled} onChange={e=>set('service_charge_enabled',e.target.checked)} style={{opacity:0,width:0,height:0}}/>
          <span style={{position:"absolute",cursor:"pointer",inset:0,background:settings.service_charge_enabled?C.brand:"#cbd5e1",borderRadius:26,transition:".2s"}}/>
          <span style={{position:"absolute",content:"",height:20,width:20,left:settings.service_charge_enabled?25:3,top:3,background:C.white,borderRadius:"50%",transition:".2s",boxShadow:"0 2px 4px rgba(0,0,0,.2)"}}/>
        </label>
      </div>
      {settings.service_charge_enabled&&<div>
        <div style={{fontSize:12,color:C.ink2,fontWeight:700,marginBottom:5,fontFamily:"'Sarabun',sans-serif"}}>อัตรา Service Charge (%)</div>
        <input type="text" inputMode="decimal" step="0.01" value={settings.service_charge_rate} onChange={e=>set('service_charge_rate',+e.target.value)} style={{...iS,fontSize:15,fontWeight:700,maxWidth:200}}/>
      </div>}
    </Card>

    {/* PromptPay */}
    <Card style={{padding:18,marginBottom:14}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12}}>
        <div>
          <div style={{fontFamily:"'Sarabun',sans-serif",fontSize:15,fontWeight:800,color:C.ink}}>📱 PromptPay QR</div>
          <div style={{fontSize:11,color:C.ink4,fontFamily:"'Sarabun',sans-serif",marginTop:2}}>แสดง QR PromptPay ในใบเสร็จลูกค้าสแกนจ่ายได้เลย</div>
        </div>
        <label style={{position:"relative",display:"inline-block",width:48,height:26}}>
          <input type="checkbox" checked={!!settings.show_qr_promptpay} onChange={e=>set('show_qr_promptpay',e.target.checked)} style={{opacity:0,width:0,height:0}}/>
          <span style={{position:"absolute",cursor:"pointer",inset:0,background:settings.show_qr_promptpay?C.brand:"#cbd5e1",borderRadius:26,transition:".2s"}}/>
          <span style={{position:"absolute",content:"",height:20,width:20,left:settings.show_qr_promptpay?25:3,top:3,background:C.white,borderRadius:"50%",transition:".2s",boxShadow:"0 2px 4px rgba(0,0,0,.2)"}}/>
        </label>
      </div>
      {settings.show_qr_promptpay&&<div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:8}}>
          <div>
            <div style={{fontSize:12,color:C.ink2,fontWeight:700,marginBottom:5,fontFamily:"'Sarabun',sans-serif"}}>เบอร์โทร / เลขบัตร ปชช</div>
            <input value={settings.promptpay_id||""} onChange={e=>set('promptpay_id',e.target.value)} placeholder="0812345678 หรือ 1234567890123" style={{...iS,fontSize:14,fontFamily:"monospace",letterSpacing:.5}}/>
          </div>
          <div>
            <div style={{fontSize:12,color:C.ink2,fontWeight:700,marginBottom:5,fontFamily:"'Sarabun',sans-serif"}}>ชื่อบัญชี (แสดงในใบเสร็จ)</div>
            <input value={settings.promptpay_name||""} onChange={e=>set('promptpay_name',e.target.value)} placeholder="เช่น ร้านในวันสุก" style={{...iS,fontSize:14}}/>
          </div>
        </div>
        {qrPreview&&<div style={{background:C.bg,borderRadius:10,padding:12,display:"flex",alignItems:"center",gap:14}}>
          <QRImg url={qrPreview} size={100}/>
          <div style={{fontSize:12,color:C.ink3,fontFamily:"'Sarabun',sans-serif"}}>
            <div style={{fontWeight:700,color:C.green,marginBottom:3}}>✅ QR ใช้งานได้</div>
            <div>QR ตัวอย่าง (จำลองยอด ฿100)</div>
            <div style={{fontSize:11,marginTop:3,color:C.ink4}}>QR จริงในใบเสร็จจะถูกสร้างตามยอดบิลแต่ละครั้ง</div>
          </div>
        </div>}
        {!qrPreview&&settings.promptpay_id&&<div style={{background:C.redLight,borderRadius:10,padding:10,fontSize:12,color:C.red,fontFamily:"'Sarabun',sans-serif"}}>⚠️ เบอร์/เลขบัตรไม่ถูกต้อง (ต้อง 10 หรือ 13 หลัก)</div>}
      </div>}
    </Card>

    {/* Receipt header/footer */}
    <Card style={{padding:18}}>
      <div style={{fontFamily:"'Sarabun',sans-serif",fontSize:15,fontWeight:800,color:C.ink,marginBottom:12}}>🧾 ข้อความใบเสร็จ</div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
        <div>
          <div style={{fontSize:12,color:C.ink2,fontWeight:700,marginBottom:5,fontFamily:"'Sarabun',sans-serif"}}>หัวใบเสร็จ (Header)</div>
          <textarea rows={3} value={settings.receipt_header||""} onChange={e=>set('receipt_header',e.target.value)} placeholder="เช่น ที่อยู่ร้าน, เลขผู้เสียภาษี" style={{...iS,fontSize:13,resize:"none",lineHeight:1.5}}/>
        </div>
        <div>
          <div style={{fontSize:12,color:C.ink2,fontWeight:700,marginBottom:5,fontFamily:"'Sarabun',sans-serif"}}>ท้ายใบเสร็จ (Footer)</div>
          <textarea rows={3} value={settings.receipt_footer||""} onChange={e=>set('receipt_footer',e.target.value)} placeholder="เช่น ขอบคุณที่ใช้บริการ, FB/Line ID" style={{...iS,fontSize:13,resize:"none",lineHeight:1.5}}/>
        </div>
      </div>
    </Card>
  </div>;
}

// ══════════════════════════════════════════════════════
// ── PROMOTION MANAGER ────────────────────────────────
// ══════════════════════════════════════════════════════
const WEEKDAYS=["อา","จ","อ","พ","พฤ","ศ","ส"];
function POSPromotionManager({currentBranch,menus}){
  const[promos,setPromos]=useState([]);const[loading,setLoading]=useState(true);
  const[showForm,setShowForm]=useState(false);const[editId,setEditId]=useState(null);const[saving,setSaving]=useState(false);
  const F0={name:"",description:"",type:"percent",discount_value:10,scope:"bill",scope_value:"",min_order:0,max_discount:"",start_date:"",end_date:"",start_time:"",end_time:"",weekdays:"",active:true};
  const[F,setF]=useState(F0);
  async function load(){setLoading(true);try{const p=await api.getPromotions(currentBranch.id);setPromos(p);}catch(e){alert("โหลดไม่สำเร็จ: "+e.message);}setLoading(false);}
  useEffect(()=>{load();},[currentBranch.id]);
  const cats=useMemo(()=>[...new Set(menus.map(m=>m.category))],[menus]);
  async function save(){
    if(!F.name.trim()||!F.discount_value)return;
    setSaving(true);
    try{
      const d={...F,branch_id:currentBranch.id,discount_value:+F.discount_value,min_order:+F.min_order||0,max_discount:F.max_discount?+F.max_discount:null,start_date:F.start_date||null,end_date:F.end_date||null,start_time:F.start_time||null,end_time:F.end_time||null,weekdays:F.weekdays||null,scope_value:F.scope==="bill"?null:F.scope_value};
      if(editId)await api.updatePromotion(editId,d);else await api.addPromotion(d);
      setF(F0);setEditId(null);setShowForm(false);await load();
    }catch(e){alert("บันทึกไม่สำเร็จ: "+e.message);}
    setSaving(false);
  }
  async function del(p){if(!await confirmDlg({title:"ลบโปรโมชั่น",message:`ต้องการลบ "${p.name}"?`,danger:true}))return;try{await api.deletePromotion(p.id);await load();}catch{alert("ลบไม่สำเร็จ");}}
  function startEdit(p){setF({name:p.name||"",description:p.description||"",type:p.type,discount_value:p.discount_value,scope:p.scope,scope_value:p.scope_value||"",min_order:p.min_order||0,max_discount:p.max_discount||"",start_date:p.start_date||"",end_date:p.end_date||"",start_time:p.start_time||"",end_time:p.end_time||"",weekdays:p.weekdays||"",active:p.active});setEditId(p.id);setShowForm(true);}
  async function toggle(p){try{await api.updatePromotion(p.id,{active:!p.active});await load();}catch{alert("ปรับสถานะไม่สำเร็จ");}}
  function toggleWeekday(d){const arr=(F.weekdays||"").split(",").filter(Boolean);const s=String(d);const next=arr.includes(s)?arr.filter(x=>x!==s):[...arr,s];setF(f=>({...f,weekdays:next.sort().join(",")}));}
  return <div>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
      <h3 style={{fontFamily:"'Sarabun',sans-serif",fontSize:18,fontWeight:900,color:C.ink,margin:0}}>🎁 โปรโมชั่น ({promos.length})</h3>
      <Btn onClick={()=>{setF(F0);setEditId(null);setShowForm(true);}} icon={I.plus} s={{padding:"8px 16px"}}>เพิ่มโปรโมชั่น</Btn>
    </div>
    {loading?<Loading text="โหลด..."/>:<>
      {promos.length===0&&!showForm&&<div style={{textAlign:"center",padding:50,color:C.ink4,fontFamily:"'Sarabun',sans-serif"}}><Ic d={I.tag} s={42} c={C.line}/><p style={{marginTop:10}}>ยังไม่มีโปรโมชั่น</p></div>}
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(min(320px,100%),1fr))",gap:12}}>
        {promos.map(p=>{
          const typeL={percent:"ส่วนลด %",amount:"ส่วนลด ฿",fixed_price:"ราคาพิเศษ"}[p.type]||p.type;
          const valL=p.type==="percent"?`${p.discount_value}%`:`฿${p.discount_value}`;
          return <Card key={p.id} style={{padding:0,overflow:"hidden",opacity:p.active?1:.5}}>
            <div style={{padding:"10px 14px",background:p.active?`linear-gradient(135deg,${C.brand}11,${C.brandLight})`:C.bg,borderBottom:`1px solid ${C.line}`,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontFamily:"'Sarabun',sans-serif",fontWeight:800,fontSize:14,color:C.ink,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{p.name}</div>
                <div style={{fontSize:11,color:C.ink4,fontFamily:"'Sarabun',sans-serif"}}>{typeL} · <b style={{color:C.brand}}>{valL}</b></div>
              </div>
              <div style={{display:"flex",gap:4}}>
                <button onClick={()=>toggle(p)} title={p.active?"ปิด":"เปิด"} style={{background:p.active?C.greenLight:C.lineLight,border:"none",borderRadius:7,padding:"5px 9px",cursor:"pointer",fontSize:11,fontWeight:700,color:p.active?C.green:C.ink3,fontFamily:"'Sarabun',sans-serif"}}>{p.active?"ON":"OFF"}</button>
                <button onClick={()=>startEdit(p)} style={{background:C.blueLight,border:"none",borderRadius:7,padding:"5px 7px",cursor:"pointer",display:"flex"}}><Ic d={I.pencil} s={12} c={C.blue}/></button>
                <button onClick={()=>del(p)} style={{background:C.redLight,border:"none",borderRadius:7,padding:"5px 7px",cursor:"pointer",display:"flex"}}><Ic d={I.trash} s={12} c={C.red}/></button>
              </div>
            </div>
            <div style={{padding:"10px 14px",fontSize:12,color:C.ink2,fontFamily:"'Sarabun',sans-serif",lineHeight:1.7}}>
              {p.description&&<div style={{marginBottom:4}}>{p.description}</div>}
              <div>📍 {p.scope==="bill"?"ทั้งบิล":p.scope==="category"?`หมวด: ${p.scope_value}`:`เมนู: ${menus.find(m=>m.id==p.scope_value)?.name||p.scope_value}`}</div>
              {p.min_order>0&&<div>💵 ขั้นต่ำ ฿{p.min_order}</div>}
              {(p.start_date||p.end_date)&&<div>📅 {p.start_date||"—"} ถึง {p.end_date||"—"}</div>}
              {(p.start_time||p.end_time)&&<div>🕐 {p.start_time||"00:00"} - {p.end_time||"23:59"}</div>}
              {p.weekdays&&<div>📆 {p.weekdays.split(",").map(d=>WEEKDAYS[+d]).join(", ")}</div>}
            </div>
          </Card>;
        })}
      </div>
    </>}
    {showForm&&<Modal title={editId?"✏️ แก้ไขโปรโมชั่น":"➕ เพิ่มโปรโมชั่น"} onClose={()=>{setShowForm(false);setEditId(null);setF(F0);}} wide>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
        <Inp label="ชื่อโปรโมชั่น *" value={F.name} onChange={e=>setF(f=>({...f,name:e.target.value}))} placeholder="เช่น ส่วนลด Happy Hour"/>
        <Inp label="คำอธิบาย" value={F.description} onChange={e=>setF(f=>({...f,description:e.target.value}))} placeholder="รายละเอียดเพิ่มเติม"/>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:12}}>
        <Field label="ประเภท">
          <select value={F.type} onChange={e=>setF(f=>({...f,type:e.target.value}))} style={{...iS,appearance:"none"}}>
            <option value="percent">ส่วนลด %</option>
            <option value="amount">ส่วนลด ฿ (จำนวนเงิน)</option>
            <option value="fixed_price">ราคาพิเศษ ฿ (set ราคา)</option>
          </select>
        </Field>
        <Inp label={F.type==="percent"?"% ส่วนลด *":"จำนวน ฿ *"} type="number" value={F.discount_value} onChange={e=>setF(f=>({...f,discount_value:e.target.value}))}/>
        <Inp label="เพดานส่วนลด ฿ (สำหรับ %)" type="number" value={F.max_discount} onChange={e=>setF(f=>({...f,max_discount:e.target.value}))} placeholder="ไม่จำกัด"/>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 2fr",gap:12}}>
        <Field label="ใช้กับ">
          <select value={F.scope} onChange={e=>setF(f=>({...f,scope:e.target.value,scope_value:""}))} style={{...iS,appearance:"none"}}>
            <option value="bill">ทั้งบิล</option>
            <option value="category">หมวดเมนู</option>
            <option value="menu">เมนูเฉพาะ</option>
          </select>
        </Field>
        {F.scope==="category"&&<Field label="หมวด"><select value={F.scope_value} onChange={e=>setF(f=>({...f,scope_value:e.target.value}))} style={{...iS,appearance:"none"}}><option value="">— เลือกหมวด —</option>{cats.map(c=><option key={c} value={c}>{c}</option>)}</select></Field>}
        {F.scope==="menu"&&<Field label="เมนู"><select value={F.scope_value} onChange={e=>setF(f=>({...f,scope_value:e.target.value}))} style={{...iS,appearance:"none"}}><option value="">— เลือกเมนู —</option>{menus.map(m=><option key={m.id} value={m.id}>{m.name}</option>)}</select></Field>}
        {F.scope==="bill"&&<Inp label="ยอดขั้นต่ำ ฿" type="number" value={F.min_order} onChange={e=>setF(f=>({...f,min_order:e.target.value}))}/>}
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr 1fr",gap:12}}>
        <Inp label="เริ่ม (วันที่)" type="date" value={F.start_date} onChange={e=>setF(f=>({...f,start_date:e.target.value}))}/>
        <Inp label="สิ้นสุด (วันที่)" type="date" value={F.end_date} onChange={e=>setF(f=>({...f,end_date:e.target.value}))}/>
        <Inp label="เริ่ม (เวลา)" type="time" value={F.start_time} onChange={e=>setF(f=>({...f,start_time:e.target.value}))}/>
        <Inp label="สิ้นสุด (เวลา)" type="time" value={F.end_time} onChange={e=>setF(f=>({...f,end_time:e.target.value}))}/>
      </div>
      <Field label={`เฉพาะวัน (เลือกได้หลายวัน) — ${F.weekdays?F.weekdays.split(",").map(d=>WEEKDAYS[+d]).join(", "):"ทุกวัน"}`}>
        <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
          {WEEKDAYS.map((w,d)=>{const sel=(F.weekdays||"").split(",").includes(String(d));return <button key={d} onClick={()=>toggleWeekday(d)} style={{padding:"7px 14px",borderRadius:8,border:`2px solid ${sel?C.brand:C.line}`,background:sel?C.brandLight:C.white,color:sel?C.brand:C.ink3,cursor:"pointer",fontFamily:"'Sarabun',sans-serif",fontWeight:700,fontSize:12}}>{w}</button>;})}
          {F.weekdays&&<button onClick={()=>setF(f=>({...f,weekdays:""}))} style={{padding:"7px 12px",borderRadius:8,border:"none",background:"transparent",color:C.ink4,cursor:"pointer",fontFamily:"'Sarabun',sans-serif",fontSize:12}}>ล้าง</button>}
        </div>
      </Field>
      <div style={{display:"flex",justifyContent:"flex-end",gap:8,paddingTop:14,borderTop:`1px solid ${C.line}`,marginTop:8}}>
        <Btn v="ghost" onClick={()=>{setShowForm(false);setEditId(null);setF(F0);}}>ยกเลิก</Btn>
        <Btn onClick={save} loading={saving} disabled={!F.name.trim()||!F.discount_value} icon={I.check}>{editId?"บันทึก":"เพิ่มโปรโมชั่น"}</Btn>
      </div>
    </Modal>}
  </div>;
}

// Find applicable promotions for a given context
function evalPromotions(promos,context){
  const{subtotal,items,now=new Date()}=context;
  const dow=now.getDay();
  const hhmm=`${String(now.getHours()).padStart(2,'0')}:${String(now.getMinutes()).padStart(2,'0')}`;
  const ymd=now.toLocaleDateString("en-CA",{timeZone:"Asia/Bangkok"});
  return (promos||[]).filter(p=>{
    if(!p.active)return false;
    if(p.start_date&&ymd<p.start_date)return false;
    if(p.end_date&&ymd>p.end_date)return false;
    // Time window: support overnight wrap (e.g. 22:00-02:00)
    if(p.start_time||p.end_time){
      const st=p.start_time?p.start_time.slice(0,5):"00:00";
      const et=p.end_time?p.end_time.slice(0,5):"23:59";
      const inWindow=st<=et?(hhmm>=st&&hhmm<=et):(hhmm>=st||hhmm<=et);
      if(!inWindow)return false;
    }
    if(p.weekdays&&p.weekdays.split(",").filter(Boolean).length>0&&!p.weekdays.split(",").includes(String(dow)))return false;
    if(p.scope==="bill"&&(+p.min_order||0)>subtotal)return false;
    if(p.scope==="category"){
      if(!p.scope_value)return false;
      if(!items.some(i=>{const m=context.menusById?.[i.menu_id];return m&&m.category===p.scope_value;}))return false;
    }
    if(p.scope==="menu"){
      if(!p.scope_value)return false;
      if(!items.some(i=>String(i.menu_id)===String(p.scope_value)))return false;
    }
    // For fixed_price ("set price"), require the relevant total to exceed the target,
    // otherwise the discount would be 0 and the promo is misleading.
    if(p.type==="fixed_price"){
      const fp=+p.discount_value||0;
      if(p.scope==="bill"){
        if(subtotal<=fp)return false;
      }else{
        let scopeTotal=0;
        items.forEach(i=>{const m=context.menusById?.[i.menu_id];const include=p.scope==="category"?(m&&m.category===p.scope_value):String(i.menu_id)===String(p.scope_value);if(include)scopeTotal+=i.price*i.qty;});
        if(scopeTotal<=fp)return false;
      }
    }
    return true;
  });
}
function calcPromoDiscount(promo,context){
  const{subtotal,items,menusById}=context;
  if(promo.scope==="bill"){
    let amt=promo.type==="percent"?subtotal*(+promo.discount_value)/100:promo.type==="amount"?+promo.discount_value:Math.max(0,subtotal-(+promo.discount_value));
    if(promo.max_discount&&amt>+promo.max_discount)amt=+promo.max_discount;
    return Math.min(amt,subtotal);
  }
  // category or menu scope
  let scopeTotal=0;
  items.forEach(i=>{
    const m=menusById?.[i.menu_id];const include=promo.scope==="category"?(m&&m.category===promo.scope_value):String(i.menu_id)===String(promo.scope_value);
    if(include)scopeTotal+=i.price*i.qty;
  });
  let amt=promo.type==="percent"?scopeTotal*(+promo.discount_value)/100:promo.type==="amount"?+promo.discount_value:Math.max(0,scopeTotal-(+promo.discount_value));
  if(promo.max_discount&&amt>+promo.max_discount)amt=+promo.max_discount;
  return Math.min(amt,scopeTotal);
}

// ══════════════════════════════════════════════════════
// ── POS BACK OFFICE (หลังบ้าน) ─────────────────────────
// ══════════════════════════════════════════════════════
function POSBackOffice({currentBranch,currentUser,printers,reloadPrinters,branches,zones=[],reloadZones,menus=[],reloadMenus,onExit}){
  const[section,setSection]=useState("tables");
  const[tables,setTables]=useState([]);const[loadingT,setLoadingT]=useState(true);
  const[shifts,setShifts]=useState([]);const[loadingS,setLoadingS]=useState(false);
  async function loadTables(){setLoadingT(true);try{const t=await api.getPOSTables(currentBranch.id);setTables(t);}catch{}setLoadingT(false);}
  async function loadShifts(){setLoadingS(true);try{const s=await api.getShifts(currentBranch.id,30);setShifts(s);}catch{}setLoadingS(false);}
  useEffect(()=>{loadTables();},[]);
  useEffect(()=>{if(section==="shifts")loadShifts();},[section]);
  const SECS=[
    {id:"tables",l:"ผังโต๊ะ",icon:I.table,c:C.brand},
    {id:"menu",l:"เมนู & หมวดหมู่",icon:I.food,c:"#0EA5E9"},
    {id:"sellers",l:"พนักงานขาย",icon:I.user,c:C.teal},
    {id:"printers",l:"เครื่องพิมพ์",icon:I.print,c:C.purple},
    {id:"settings",l:"ตั้งค่า POS",icon:I.settings,c:C.green},
    {id:"promotions",l:"โปรโมชั่น",icon:I.tag,c:C.yellow},
    {id:"shifts",l:"ประวัติกะ",icon:I.clock,c:C.blue},
  ];
  return <div style={{margin:"-20px -24px",display:"flex",flexDirection:"column",height:"calc(100vh - 150px)"}}>
    <div style={{padding:"0 16px",background:"linear-gradient(135deg,#0F172A,#1E293B)",borderBottom:`1px solid ${C.line}`,display:"flex",alignItems:"center",height:54,gap:2,flexShrink:0}}>
      <button onClick={onExit} style={{background:"rgba(255,255,255,0.1)",border:"none",color:C.white,padding:"7px 14px",borderRadius:9,cursor:"pointer",fontFamily:"'Sarabun',sans-serif",fontSize:12,fontWeight:700,marginRight:14,display:"flex",alignItems:"center",gap:6}}>← กลับ</button>
      <div style={{color:C.white,fontFamily:"'Sarabun',sans-serif",fontSize:15,fontWeight:900,marginRight:24}}>⚙️ จัดการหลังบ้าน</div>
      {SECS.map(s=>{const active=section===s.id;return <button key={s.id} onClick={()=>setSection(s.id)} style={{display:"flex",alignItems:"center",gap:6,padding:"0 14px",height:54,border:"none",background:active?"rgba(255,255,255,0.1)":"transparent",cursor:"pointer",fontSize:13,fontWeight:active?800:600,color:active?C.white:"rgba(255,255,255,0.5)",fontFamily:"'Sarabun',sans-serif",borderBottom:active?`3px solid ${s.c}`:"3px solid transparent",transition:"all .15s"}}><Ic d={s.icon} s={14} c={active?s.c:"rgba(255,255,255,0.5)"}/>{s.l}</button>;})}
    </div>
    <div style={{flex:1,overflow:"auto",padding:"20px 24px",background:C.bg}}>
      {section==="tables"&&(loadingT?<Loading text="โหลดโต๊ะ..."/>:<POSTableManage tables={tables} branch={currentBranch} zones={zones} reloadZones={reloadZones} onDone={loadTables}/>)}
      {section==="menu"&&<POSMenuTools currentBranch={currentBranch} variant="cards" onChanged={reloadMenus}/>}
      {section==="sellers"&&<POSSellerPanel currentBranch={currentBranch}/>}
      {section==="printers"&&<POSPrinterPanel printers={printers} reloadPrinters={reloadPrinters} branches={branches} currentUser={currentUser} menus={menus}/>}
      {section==="settings"&&<POSSettingsPanel currentBranch={currentBranch}/>}
      {section==="promotions"&&<POSPromotionManager currentBranch={currentBranch} menus={menus}/>}
      {section==="shifts"&&<POSShiftHistory shifts={shifts} loading={loadingS} reload={loadShifts}/>}
    </div>
  </div>;
}

// Manage this branch's cashier PINs + show the sell link. Staff are stored in
// pos_settings.sales_staff (jsonb array) so no extra table/RLS is needed.
function POSSellerPanel({currentBranch}){
  const lbl={display:"block",fontSize:12,fontWeight:600,color:C.ink2,marginBottom:5,fontFamily:"'Sarabun',sans-serif"};
  const[settings,setSettings]=useState(null);
  const[staff,setStaff]=useState([]);
  const[loading,setLoading]=useState(true);
  const[saving,setSaving]=useState(false);
  const[form,setForm]=useState({name:"",pin:""});
  const[editIdx,setEditIdx]=useState(null);
  const sellLink=(typeof window!=="undefined"?window.location.origin+window.location.pathname:"")+"?pos=1&branch="+currentBranch.id;
  async function load(){setLoading(true);try{const ps=await api.getPOSSettings(currentBranch.id);const s=ps&&ps[0]?ps[0]:{branch_id:currentBranch.id};setSettings(s);setStaff(Array.isArray(s.sales_staff)?s.sales_staff:[]);}catch(e){console.error("loadSellers",e);}setLoading(false);}
  useEffect(()=>{load();},[currentBranch.id]);
  async function persist(next){
    setSaving(true);
    try{
      const payload={...(settings||{}),branch_id:currentBranch.id,sales_staff:next};
      await api.upsertPOSSettings(payload);
      setSettings(payload);setStaff(next);return true;
    }catch(e){alert("บันทึกไม่สำเร็จ: "+(e&&e.message||e));return false;}
    finally{setSaving(false);}
  }
  async function submit(){
    const name=(form.name||"").trim();const pin=(form.pin||"").trim();
    if(!name)return alert("ใส่ชื่อพนักงาน");
    if(!/^\d{4}$/.test(pin))return alert("PIN ต้องเป็นตัวเลข 4 หลักเท่านั้น");
    if(staff.some((s,i)=>String(s.pin)===pin&&i!==editIdx))return alert("PIN นี้ถูกใช้แล้ว — เลือกเลขอื่น");
    const next=editIdx!=null?staff.map((s,i)=>i===editIdx?{...s,name,pin}:s):[...staff,{id:`s_${Date.now()}_${Math.floor(Math.random()*1000)}`,name,pin,active:true}];
    if(await persist(next)){setForm({name:"",pin:""});setEditIdx(null);}
  }
  async function toggleActive(idx){await persist(staff.map((s,i)=>i===idx?{...s,active:s.active===false}:s));}
  async function remove(idx){if(!await confirmDlg({title:"ลบพนักงานขาย",message:`ลบ "${staff[idx]?.name}" ออกจากระบบขาย?`}))return;await persist(staff.filter((_,i)=>i!==idx));}
  if(loading)return <Loading text="โหลดพนักงานขาย..."/>;
  return <div>
    <div style={{background:`linear-gradient(135deg,${C.brandLight},${C.tealLight})`,border:`1px solid ${C.brandBorder}`,borderRadius:14,padding:"14px 16px",marginBottom:18}}>
      <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:6}}><span style={{fontSize:18}}>🔗</span><span style={{fontFamily:"'Sarabun',sans-serif",fontSize:14,fontWeight:900,color:C.ink}}>ลิงก์ขายหน้าร้าน — {currentBranch.name}</span></div>
      <div style={{fontFamily:"'Sarabun',sans-serif",fontSize:12,color:C.ink3,lineHeight:1.6,marginBottom:10}}>ส่งลิงก์นี้ให้พนักงานสาขา — เปิดแล้วใส่ <b>PIN 4 หลัก</b> ก็เข้าขายได้เลย ไม่ต้อง login</div>
      <div style={{display:"flex",gap:14,flexWrap:"wrap",alignItems:"flex-start"}}>
        {/* QR code — สแกนด้วยกล้องหรือ Chrome เพื่อเปิดหน้าขายได้ทันที */}
        <div style={{flexShrink:0,background:C.white,borderRadius:12,padding:8,border:`1px solid ${C.line}`,display:"flex",flexDirection:"column",alignItems:"center",gap:4}}>
          <QRImg url={sellLink} size={130}/>
          <span style={{fontSize:10,color:C.ink4,fontFamily:"'Sarabun',sans-serif",fontWeight:600}}>สแกนเพื่อเปิดหน้าขาย</span>
        </div>
        <div style={{flex:1,minWidth:220,display:"flex",flexDirection:"column",gap:8}}>
          <input readOnly value={sellLink} onFocus={e=>e.target.select()} style={{...iS,fontSize:11,background:C.white,wordBreak:"break-all"}}/>
          <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
            <button onClick={()=>{try{navigator.clipboard.writeText(sellLink);posToast("คัดลอกลิงก์แล้ว ✅");}catch{window.prompt("คัดลอกลิงก์:",sellLink);}}} style={{flex:1,background:C.brand,color:C.white,border:"none",borderRadius:9,padding:"9px 14px",cursor:"pointer",fontFamily:"'Sarabun',sans-serif",fontSize:12.5,fontWeight:800,whiteSpace:"nowrap"}}>📋 คัดลอกลิงก์</button>
            <button onClick={()=>window.open(sellLink,"_blank")} style={{flex:1,background:C.teal,color:C.white,border:"none",borderRadius:9,padding:"9px 14px",cursor:"pointer",fontFamily:"'Sarabun',sans-serif",fontSize:12.5,fontWeight:800,whiteSpace:"nowrap"}}>🔗 เปิดลิงก์</button>
          </div>
          <div style={{fontFamily:"'Sarabun',sans-serif",fontSize:11,color:C.ink4,lineHeight:1.6}}>💡 <b>วิธีเปิดบนแท็บเล็ต Android:</b> เปิดกล้อง → ส่องที่ QR → แตะลิงก์ที่ขึ้นมา → เปิดใน Chrome</div>
        </div>
      </div>
    </div>
    <Card style={{padding:"14px 16px",marginBottom:16}}>
      <div style={{fontFamily:"'Sarabun',sans-serif",fontSize:13,fontWeight:800,color:C.ink,marginBottom:10}}>{editIdx!=null?"✏️ แก้ไขพนักงานขาย":"➕ เพิ่มพนักงานขาย"}</div>
      <div style={{display:"flex",gap:10,flexWrap:"wrap",alignItems:"flex-end"}}>
        <div style={{flex:"2 1 180px"}}><label style={lbl}>ชื่อพนักงาน</label><input value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))} placeholder="เช่น น้องเอ" style={iS}/></div>
        <div style={{flex:"1 1 120px"}}><label style={lbl}>PIN (4 หลัก)</label><input value={form.pin} onChange={e=>setForm(f=>({...f,pin:e.target.value.replace(/\D/g,"").slice(0,4)}))} inputMode="numeric" placeholder="0000" style={{...iS,letterSpacing:4,fontWeight:800}}/></div>
        <Btn onClick={submit} loading={saving} icon={I.check}>{editIdx!=null?"บันทึก":"เพิ่ม"}</Btn>
        {editIdx!=null&&<Btn v="ghost" onClick={()=>{setForm({name:"",pin:""});setEditIdx(null);}}>ยกเลิก</Btn>}
      </div>
    </Card>
    {staff.length===0?<div style={{textAlign:"center",padding:40,color:C.ink4,fontFamily:"'Sarabun',sans-serif"}}><Ic d={I.user} s={44} c={C.line}/><p style={{marginTop:10,fontSize:13}}>ยังไม่มีพนักงานขาย — เพิ่มด้านบนเพื่อให้เข้าขายด้วย PIN</p></div>
    :<div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(min(260px,100%),1fr))",gap:10}}>
      {staff.map((s,idx)=>{const inactive=s.active===false;return <Card key={s.id||idx} style={{padding:"12px 14px",opacity:inactive?.6:1}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:8}}>
          <div style={{minWidth:0}}>
            <div style={{fontFamily:"'Sarabun',sans-serif",fontSize:15,fontWeight:800,color:C.ink,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{s.name}</div>
            <div style={{fontFamily:"'Sarabun',sans-serif",fontSize:12,color:C.ink3,marginTop:2}}>PIN: <b style={{letterSpacing:2,color:C.brand}}>{s.pin}</b></div>
          </div>
          <Chip color={inactive?"gray":"green"}>{inactive?"ปิด":"ใช้งาน"}</Chip>
        </div>
        <div style={{display:"flex",gap:6,marginTop:10}}>
          <button onClick={()=>{setForm({name:s.name,pin:String(s.pin)});setEditIdx(idx);}} style={{flex:1,padding:"6px 0",border:`1px solid ${C.line}`,borderRadius:8,background:C.blueLight,color:C.blue,cursor:"pointer",fontSize:12,fontWeight:700,fontFamily:"'Sarabun',sans-serif"}}>แก้ไข</button>
          <button onClick={()=>toggleActive(idx)} style={{flex:1,padding:"6px 0",border:`1px solid ${C.line}`,borderRadius:8,background:inactive?C.greenLight:C.bg,color:inactive?C.green:C.ink3,cursor:"pointer",fontSize:12,fontWeight:700,fontFamily:"'Sarabun',sans-serif"}}>{inactive?"เปิด":"ปิด"}</button>
          <button onClick={()=>remove(idx)} style={{padding:"6px 10px",border:`1px solid ${C.line}`,borderRadius:8,background:C.redLight,color:C.red,cursor:"pointer",fontSize:12,fontWeight:700,fontFamily:"'Sarabun',sans-serif"}}>ลบ</button>
        </div>
      </Card>;})}
    </div>}
  </div>;
}

// ══════════════════════════════════════════════════════
// ── POS MENU & CATEGORY TOOLS (sale screen + back office)
// ══════════════════════════════════════════════════════
// Same management surface from two places: a dropdown on the sale screen and a
// section in the back office. Branch-level only — set availability & assign a
// (local) category; the price/recipe stays central. (Add-on options = next.)
function POSMenuTools({currentBranch,variant="dropdown",onChanged}){
  const[open,setOpen]=useState(false);
  const[active,setActive]=useState(null);  // 'menus' | 'cats' | 'options' | null
  const items=[
    {id:"menus",l:"เมนูทั้งหมด",icon:"🍔",sub:"สถานะ + จัดหมวด"},
    {id:"cats",l:"หมวดหมู่",icon:"📂",sub:"เพิ่ม/แก้/ลบหมวด"},
    {id:"options",l:"ตัวเลือกในเมนู",icon:"➕",sub:"add-on รายเมนู"},
  ];
  return <>
    {variant==="dropdown"
      ?<div style={{position:"relative"}}>
        <button onClick={()=>setOpen(o=>!o)} style={{display:"flex",alignItems:"center",gap:6,padding:"0 12px",height:46,border:"none",background:open?C.brandLight:"none",cursor:"pointer",fontSize:12,fontWeight:700,color:C.brand,fontFamily:"'Sarabun',sans-serif",borderBottom:"2.5px solid transparent"}}>🍔 จัดการเมนูและหมวดหมู่ <span style={{fontSize:9}}>▾</span></button>
        {open&&<><div onClick={()=>setOpen(false)} style={{position:"fixed",inset:0,zIndex:60}}/>
          <div style={{position:"absolute",top:"100%",left:0,zIndex:61,background:C.white,border:`1px solid ${C.line}`,borderRadius:12,boxShadow:"0 14px 40px rgba(15,23,42,.16)",minWidth:240,overflow:"hidden",marginTop:2}}>
            {items.map(it=><button key={it.id} onClick={()=>{setActive(it.id);setOpen(false);}} style={{display:"flex",alignItems:"center",gap:10,width:"100%",padding:"11px 14px",border:"none",borderBottom:`1px solid ${C.lineLight}`,background:C.white,cursor:"pointer",textAlign:"left",fontFamily:"'Sarabun',sans-serif"}} onMouseEnter={e=>e.currentTarget.style.background=C.brandLight} onMouseLeave={e=>e.currentTarget.style.background=C.white}>
              <span style={{fontSize:18}}>{it.icon}</span>
              <span style={{minWidth:0}}><span style={{display:"block",fontSize:13.5,fontWeight:800,color:C.ink}}>{it.l}</span><span style={{display:"block",fontSize:11,color:C.ink4}}>{it.sub}</span></span>
            </button>)}
          </div></>}
      </div>
      :<div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(min(220px,100%),1fr))",gap:12}}>
        {items.map(it=><button key={it.id} onClick={()=>setActive(it.id)} style={{display:"flex",alignItems:"center",gap:12,padding:"16px 16px",border:`1.5px solid ${C.line}`,borderRadius:14,background:C.white,cursor:"pointer",textAlign:"left",fontFamily:"'Sarabun',sans-serif"}} onMouseEnter={e=>{e.currentTarget.style.borderColor=C.brand;e.currentTarget.style.background=C.brandLight;}} onMouseLeave={e=>{e.currentTarget.style.borderColor=C.line;e.currentTarget.style.background=C.white;}}>
          <span style={{fontSize:26}}>{it.icon}</span>
          <span><span style={{display:"block",fontSize:15,fontWeight:800,color:C.ink}}>{it.l}</span><span style={{display:"block",fontSize:12,color:C.ink4,marginTop:2}}>{it.sub}</span></span>
        </button>)}
      </div>}
    {active==="menus"&&<POSMenuAvailManager currentBranch={currentBranch} onClose={()=>{setActive(null);onChanged&&onChanged();}}/>}
    {active==="cats"&&<POSLocalCatManager currentBranch={currentBranch} onClose={()=>{setActive(null);onChanged&&onChanged();}}/>}
    {active==="options"&&<POSOptionLibrary currentBranch={currentBranch} onClose={()=>{setActive(null);onChanged&&onChanged();}}/>}
  </>;
}

// "เมนูทั้งหมด" — branch sets availability (ขาย/วันนี้หมด/ซ่อน) + binds add-on
// options to each menu (chosen from the option library). Category assignment now
// lives in the หมวดหมู่ manager (one category per menu).
function POSMenuAvailManager({currentBranch,onClose}){
  const isCentral=currentBranch?.type==="central";
  const[menus,setMenus]=useState([]);const[lib,setLib]=useState([]);const[loading,setLoading]=useState(true);
  const[q,setQ]=useState("");const[busyId,setBusyId]=useState(null);
  const[bindMenu,setBindMenu]=useState(null);const[bindSel,setBindSel]=useState({});const[bindBusy,setBindBusy]=useState(false);
  const[bulkOpen,setBulkOpen]=useState(false);const[bulkGroups,setBulkGroups]=useState({});const[bulkMenus,setBulkMenus]=useState({});const[bulkBusy,setBulkBusy]=useState(false);
  async function load(){setLoading(true);try{const[ms,ps]=await Promise.all([api.getMenus(),api.getPOSSettings(currentBranch.id)]);setMenus(ms||[]);const s=ps&&ps[0]?ps[0]:null;setLib(Array.isArray(s&&s.option_library)?s.option_library:[]);}catch(e){console.error("menuMgr",e);}setLoading(false);}
  useEffect(()=>{load();},[currentBranch.id]);
  const visible=menus.filter(m=>{const vb=m.visible_branches||[];const okB=isCentral||vb.length===0||vb.includes(currentBranch.id);if(!okB)return false;if(q.trim()&&!m.name.toLowerCase().includes(q.toLowerCase()))return false;return true;});
  async function setAvail(m,status){setBusyId(m.id);const avail={...(m.availability||{})};if(!status)delete avail[currentBranch.id];else avail[currentBranch.id]=status;try{await api.updateMenu(m.id,{availability:avail});setMenus(ms=>ms.map(x=>x.id===m.id?{...x,availability:avail}:x));}catch(e){alert("บันทึกไม่สำเร็จ: "+e.message);}setBusyId(null);}
  const AVS=[{v:"",l:"ขาย",c:C.green},{v:"sold_out",l:"วันนี้หมด",c:"#92400E"},{v:"hidden",l:"ซ่อน",c:C.red}];
  function openBind(m){const sel={};const raw=((m.options_by_branch||{})[String(currentBranch.id)])||[];raw.forEach(b=>{const id=(typeof b==="string"||typeof b==="number")?b:(b&&b.id);if(id)sel[id]=true;});setBindSel(sel);setBindMenu(m);}
  async function saveBind(){
    if(!bindMenu)return;setBindBusy(true);
    const chosen=lib.filter(g=>bindSel[g.id]).map(g=>g.id);  // store group IDs (reference — library edits propagate live)
    const map={...(bindMenu.options_by_branch||{})};map[String(currentBranch.id)]=chosen;
    try{await api.updateMenu(bindMenu.id,{options_by_branch:map});setMenus(ms=>ms.map(x=>x.id===bindMenu.id?{...x,options_by_branch:map}:x));setBindMenu(null);}catch(e){alert("บันทึกไม่สำเร็จ: "+(e&&e.message||e));}
    setBindBusy(false);
  }
  // Bulk-bind: apply the SAME option group(s) to many menus at once → they all become consistent.
  async function applyBulk(){
    const groupIds=lib.filter(g=>bulkGroups[g.id]).map(g=>g.id);
    const menuIds=visible.filter(m=>bulkMenus[m.id]).map(m=>m.id);
    if(menuIds.length===0){alert("เลือกเมนูอย่างน้อย 1 เมนู");return;}
    if(groupIds.length===0&&!await confirmDlg({title:"ล้างตัวเลือก?",message:`ยังไม่ได้เลือกกลุ่มตัวเลือก — เมนูที่เลือก (${menuIds.length}) จะถูก “ล้างตัวเลือกออกทั้งหมด” ใช่ไหม?`,confirmLabel:"ล้างตัวเลือก",cancelLabel:"ยกเลิก",danger:true}))return;
    setBulkBusy(true);
    try{
      for(const mid of menuIds){const m=menus.find(x=>x.id===mid);if(!m)continue;const map={...(m.options_by_branch||{})};map[String(currentBranch.id)]=groupIds;await api.updateMenu(mid,{options_by_branch:map});}
      setMenus(ms=>ms.map(x=>menuIds.includes(x.id)?{...x,options_by_branch:{...(x.options_by_branch||{}),[String(currentBranch.id)]:groupIds}}:x));
      setBulkOpen(false);posToast(`✅ ผูกตัวเลือกให้ ${menuIds.length} เมนูเหมือนกันแล้ว`);
    }catch(e){alert("บันทึกไม่สำเร็จ: "+(e&&e.message||e));}
    setBulkBusy(false);
  }
  return <Modal title="🍔 เมนูทั้งหมด — สถานะ & ตัวเลือก" onClose={onClose} extraWide>
    {loading?<Loading text="โหลดเมนู..."/>:<>
      <div style={{display:"flex",gap:10,alignItems:"center",marginBottom:12,flexWrap:"wrap"}}>
        <input value={q} onChange={e=>setQ(e.target.value)} placeholder="ค้นหาเมนู..." style={{...iS,flex:1,minWidth:200}}/>
        <span style={{fontSize:12,color:C.ink4,fontFamily:"'Sarabun',sans-serif"}}>{visible.length} เมนู</span>
        <Btn v="teal" onClick={()=>{setBulkGroups({});setBulkMenus({});setBulkOpen(true);}} icon={I.plus} s={{padding:"7px 13px",fontSize:12}}>🔗 ผูกหลายเมนูพร้อมกัน</Btn>
      </div>
      {visible.length===0?<div style={{textAlign:"center",padding:40,color:C.ink4,fontFamily:"'Sarabun',sans-serif"}}>ไม่พบเมนู</div>
      :<div style={{display:"flex",flexDirection:"column",gap:8,maxHeight:"58vh",overflowY:"auto"}}>
        {visible.map(m=>{const cur=(m.availability||{})[currentBranch.id]||"";const nOpt=getMenuOptions(m,currentBranch.id,lib).length;return <div key={m.id} style={{display:"flex",alignItems:"center",gap:12,padding:"10px 12px",border:`1px solid ${C.line}`,borderRadius:12,background:C.white,flexWrap:"wrap",opacity:busyId===m.id?.6:1}}>
          <div style={{minWidth:140,flex:"1 1 140px"}}>
            <div style={{fontFamily:"'Sarabun',sans-serif",fontSize:14,fontWeight:800,color:C.ink}}>{m.name}</div>
            <div style={{fontFamily:"'Sarabun',sans-serif",fontSize:11.5,color:C.ink4}}>฿{(+m.price||0).toLocaleString()}{(m.local_categories||{})[currentBranch.id]?` · ${(m.local_categories||{})[currentBranch.id]}`:""}</div>
          </div>
          <div style={{display:"flex",gap:4}}>
            {AVS.map(a=><button key={a.v} onClick={()=>setAvail(m,a.v)} style={{padding:"5px 11px",borderRadius:8,border:`1.5px solid ${cur===a.v?a.c:C.line}`,background:cur===a.v?a.c:C.white,color:cur===a.v?C.white:C.ink3,cursor:"pointer",fontSize:11.5,fontWeight:700,fontFamily:"'Sarabun',sans-serif"}}>{a.l}</button>)}
          </div>
          <button onClick={()=>openBind(m)} style={{display:"flex",alignItems:"center",gap:5,padding:"6px 12px",borderRadius:8,border:`1.5px solid ${nOpt>0?C.teal:C.line}`,background:nOpt>0?C.tealLight:C.white,color:nOpt>0?C.teal:C.ink3,cursor:"pointer",fontSize:12,fontWeight:700,fontFamily:"'Sarabun',sans-serif",whiteSpace:"nowrap"}}>➕ ตัวเลือก{nOpt>0?` (${nOpt})`:""}</button>
        </div>;})}
      </div>}
    </>}
    {bindMenu&&<Modal title={`ผูกตัวเลือก — ${bindMenu.name}`} onClose={()=>setBindMenu(null)}>
      {lib.length===0?<div style={{padding:"24px 16px",textAlign:"center",color:C.ink3,fontFamily:"'Sarabun',sans-serif",fontSize:13,lineHeight:1.7}}>ยังไม่มีกลุ่มตัวเลือกในคลัง<br/>ไปสร้างที่ <b>"➕ ตัวเลือกในเมนู"</b> ก่อน แล้วกลับมาผูก</div>
      :<>
        <div style={{fontSize:12,color:C.ink3,fontFamily:"'Sarabun',sans-serif",marginBottom:10}}>เลือก<b>กลุ่มตัวเลือก</b>ที่จะผูกกับเมนูนี้ (ลูกค้า/พนักงานจะเห็นตอนสั่ง)</div>
        <div style={{display:"flex",flexDirection:"column",gap:6,maxHeight:"45vh",overflowY:"auto",marginBottom:14}}>
          {lib.map(g=>{const on=!!bindSel[g.id];const chTxt=(g.choices||[]).map(c=>c.name).join(", ");return <label key={g.id} style={{display:"flex",alignItems:"center",gap:10,padding:"10px 12px",borderRadius:10,cursor:"pointer",background:on?C.brandLight:C.white,border:`1.5px solid ${on?C.brandBorder:C.line}`}}>
            <input type="checkbox" checked={on} onChange={()=>setBindSel(s=>({...s,[g.id]:!s[g.id]}))} style={{accentColor:C.brand,width:17,height:17,flexShrink:0}}/>
            <span style={{flex:1,minWidth:0}}>
              <span style={{display:"block",fontFamily:"'Sarabun',sans-serif",fontSize:14,fontWeight:on?800:600,color:on?C.brand:C.ink}}>📦 {g.name} {g.required&&<span style={{fontSize:10,fontWeight:800,color:C.red}}>*บังคับ</span>}</span>
              {chTxt&&<span style={{display:"block",fontFamily:"'Sarabun',sans-serif",fontSize:11,color:C.ink4,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{chTxt}</span>}
            </span>
          </label>;})}
        </div>
        <div style={{display:"flex",justifyContent:"flex-end",gap:10,paddingTop:12,borderTop:`1px solid ${C.line}`}}>
          <Btn v="ghost" onClick={()=>setBindMenu(null)}>ยกเลิก</Btn>
          <Btn onClick={saveBind} loading={bindBusy} icon={I.check}>บันทึก</Btn>
        </div>
      </>}
    </Modal>}
    {bulkOpen&&<Modal title="🔗 ผูกตัวเลือกหลายเมนูพร้อมกัน" onClose={()=>setBulkOpen(false)} wide>
      {lib.length===0?<div style={{padding:"24px 16px",textAlign:"center",color:C.ink3,fontFamily:"'Sarabun',sans-serif",fontSize:13,lineHeight:1.7}}>ยังไม่มีกลุ่มตัวเลือกในคลัง<br/>ไปสร้างที่ <b>"➕ ตัวเลือกในเมนู"</b> ก่อน</div>
      :<>
        <div style={{fontSize:12.5,fontWeight:800,color:C.ink,fontFamily:"'Sarabun',sans-serif",marginBottom:8}}>1️⃣ เลือกกลุ่มตัวเลือก <span style={{fontSize:11,fontWeight:600,color:C.ink4}}>(เมนูที่เลือกจะได้กลุ่มชุดนี้เหมือนกันทั้งหมด)</span></div>
        <div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:16}}>
          {lib.map(g=>{const on=!!bulkGroups[g.id];return <button key={g.id} onClick={()=>setBulkGroups(s=>({...s,[g.id]:!s[g.id]}))} style={{padding:"7px 13px",borderRadius:20,border:`1.5px solid ${on?C.brand:C.line}`,background:on?C.brandLight:C.white,color:on?C.brand:C.ink3,cursor:"pointer",fontFamily:"'Sarabun',sans-serif",fontSize:12.5,fontWeight:700}}>{on?"✓ ":""}📦 {g.name}{g.required?" *":""}</button>;})}
        </div>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8,flexWrap:"wrap",gap:8}}>
          <div style={{fontSize:12.5,fontWeight:800,color:C.ink,fontFamily:"'Sarabun',sans-serif"}}>2️⃣ เลือกเมนูที่จะผูก</div>
          <div style={{display:"flex",gap:6}}>
            <button onClick={()=>setBulkMenus(Object.fromEntries(visible.map(m=>[m.id,true])))} style={{padding:"5px 11px",borderRadius:8,border:`1px solid ${C.line}`,background:C.white,color:C.ink2,cursor:"pointer",fontFamily:"'Sarabun',sans-serif",fontSize:11.5,fontWeight:700}}>เลือกทั้งหมด</button>
            <button onClick={()=>setBulkMenus({})} style={{padding:"5px 11px",borderRadius:8,border:`1px solid ${C.line}`,background:C.white,color:C.ink2,cursor:"pointer",fontFamily:"'Sarabun',sans-serif",fontSize:11.5,fontWeight:700}}>ล้าง</button>
          </div>
        </div>
        <div style={{display:"flex",flexDirection:"column",gap:5,maxHeight:"40vh",overflowY:"auto",marginBottom:14}}>
          {visible.map(m=>{const on=!!bulkMenus[m.id];const nOpt=getMenuOptions(m,currentBranch.id,lib).length;return <label key={m.id} style={{display:"flex",alignItems:"center",gap:10,padding:"8px 11px",borderRadius:9,cursor:"pointer",background:on?C.tealLight:C.white,border:`1.5px solid ${on?C.teal:C.line}`}}>
            <input type="checkbox" checked={on} onChange={()=>setBulkMenus(s=>({...s,[m.id]:!s[m.id]}))} style={{accentColor:C.teal,width:17,height:17,flexShrink:0}}/>
            <span style={{flex:1,fontFamily:"'Sarabun',sans-serif",fontSize:13.5,fontWeight:on?800:600,color:on?C.teal:C.ink}}>{m.name}</span>
            {nOpt>0&&<span style={{fontSize:10.5,color:C.ink4,fontFamily:"'Sarabun',sans-serif",whiteSpace:"nowrap"}}>มี {nOpt} กลุ่ม</span>}
          </label>;})}
        </div>
        <div style={{display:"flex",justifyContent:"flex-end",gap:10,paddingTop:12,borderTop:`1px solid ${C.line}`}}>
          <Btn v="ghost" onClick={()=>setBulkOpen(false)}>ยกเลิก</Btn>
          <Btn v="teal" onClick={applyBulk} loading={bulkBusy} icon={I.check} disabled={Object.values(bulkMenus).filter(Boolean).length===0}>ผูกให้ {Object.values(bulkMenus).filter(Boolean).length} เมนู</Btn>
        </div>
      </>}
    </Modal>}
  </Modal>;
}

// "หมวดหมู่" — manage categories AND assign menus into them. Click a category →
// tick the menus that belong to it. A menu lives in exactly ONE category, so menus
// already in another category are shown disabled here.
function POSLocalCatManager({currentBranch,onClose}){
  const isCentral=currentBranch?.type==="central";
  const[cats,setCats]=useState([]);const[menus,setMenus]=useState([]);const[loading,setLoading]=useState(true);
  const[newName,setNewName]=useState("");const[editId,setEditId]=useState(null);const[editName,setEditName]=useState("");const[busy,setBusy]=useState(false);
  const[selCat,setSelCat]=useState(null);const[q,setQ]=useState("");
  async function load(){setLoading(true);try{const[all,ms]=await Promise.all([api.getCats(),api.getMenus()]);setCats((all||[]).filter(c=>c.type==="menu"&&(isCentral?!c.branch_id:+c.branch_id===+currentBranch.id)));setMenus(ms||[]);}catch(e){console.error("catMgr",e);}setLoading(false);}
  useEffect(()=>{load();},[currentBranch.id]);
  const catOf=(m)=>(m.local_categories||{})[currentBranch.id]||"";
  const visibleMenus=menus.filter(m=>{const vb=m.visible_branches||[];const okB=isCentral||vb.length===0||vb.includes(currentBranch.id);if(!okB)return false;if(q.trim()&&!m.name.toLowerCase().includes(q.toLowerCase()))return false;return true;});
  async function add(){const n=newName.trim();if(!n)return;if(cats.some(c=>c.name===n))return alert("มีหมวดนี้แล้ว");setBusy(true);try{await api.addCat({type:"menu",name:n,branch_id:isCentral?null:currentBranch.id});setNewName("");await load();}catch(e){alert("เพิ่มไม่สำเร็จ: "+e.message);}setBusy(false);}
  async function rename(){const n=editName.trim();if(!n||!editId)return;const old=cats.find(c=>c.id===editId)?.name;setBusy(true);try{await api.updateCat(editId,{name:n});if(old&&old!==n){for(const m of menus.filter(x=>catOf(x)===old)){const lc={...(m.local_categories||{})};lc[currentBranch.id]=n;await api.updateMenu(m.id,{local_categories:lc});}}setEditId(null);setEditName("");if(selCat===old)setSelCat(n);await load();}catch(e){alert("บันทึกไม่สำเร็จ: "+e.message);}setBusy(false);}
  async function del(c){if(!await confirmDlg({title:"ลบหมวดหมู่",message:`ลบหมวด "${c.name}"? เมนูในหมวดนี้จะกลายเป็นไม่มีหมวด`}))return;setBusy(true);try{await api.deleteCat(c.id);if(selCat===c.name)setSelCat(null);await load();}catch(e){alert("ลบไม่สำเร็จ: "+e.message);}setBusy(false);}
  async function toggleMenu(m,catName){const lc={...(m.local_categories||{})};if(lc[currentBranch.id]===catName)delete lc[currentBranch.id];else lc[currentBranch.id]=catName;try{await api.updateMenu(m.id,{local_categories:lc});setMenus(ms=>ms.map(x=>x.id===m.id?{...x,local_categories:lc}:x));}catch(e){alert("บันทึกไม่สำเร็จ: "+e.message);}}
  return <Modal title="📂 จัดการหมวดหมู่ & จัดเมนูเข้าหมวด" onClose={onClose} extraWide>
    {loading?<Loading text="โหลดหมวดหมู่..."/>:<div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(min(260px,100%),1fr))",gap:16}}>
      {/* Left: categories */}
      <div>
        <div style={{display:"flex",gap:8,marginBottom:12}}>
          <input value={newName} onChange={e=>setNewName(e.target.value)} onKeyDown={e=>e.key==="Enter"&&add()} placeholder="ชื่อหมวดใหม่ เช่น ของทอด" style={{...iS,flex:1}}/>
          <Btn onClick={add} loading={busy} icon={I.plus}>เพิ่ม</Btn>
        </div>
        {cats.length===0?<div style={{textAlign:"center",padding:30,color:C.ink4,fontFamily:"'Sarabun',sans-serif",fontSize:13}}>ยังไม่มีหมวดหมู่ — เพิ่มด้านบน</div>
        :<div style={{display:"flex",flexDirection:"column",gap:6,maxHeight:"52vh",overflowY:"auto"}}>
          {cats.map(c=>{const n=menus.filter(m=>catOf(m)===c.name).length;const on=selCat===c.name;return <div key={c.id} style={{display:"flex",alignItems:"center",gap:8,padding:"9px 12px",border:`1.5px solid ${on?C.brand:C.line}`,borderRadius:10,background:on?C.brandLight:C.white}}>
            {editId===c.id?<>
              <input value={editName} onChange={e=>setEditName(e.target.value)} onKeyDown={e=>e.key==="Enter"&&rename()} autoFocus style={{...iS,flex:1}}/>
              <Btn onClick={rename} loading={busy} s={{padding:"5px 10px",fontSize:11}}>✓</Btn>
              <Btn v="ghost" onClick={()=>{setEditId(null);setEditName("");}} s={{padding:"5px 10px",fontSize:11}}>✕</Btn>
            </>:<>
              <button onClick={()=>setSelCat(c.name)} style={{flex:1,textAlign:"left",background:"none",border:"none",cursor:"pointer",fontFamily:"'Sarabun',sans-serif",fontSize:14,fontWeight:on?800:700,color:on?C.brand:C.ink}}>📂 {c.name} <span style={{fontSize:11,color:C.ink4,fontWeight:600}}>({n})</span></button>
              <button onClick={()=>{setEditId(c.id);setEditName(c.name);}} style={{background:C.blueLight,border:"none",borderRadius:7,padding:"5px 9px",cursor:"pointer",fontSize:11,fontWeight:700,color:C.blue,fontFamily:"'Sarabun',sans-serif"}}>แก้</button>
              <button onClick={()=>del(c)} style={{background:C.redLight,border:"none",borderRadius:7,padding:"5px 9px",cursor:"pointer",fontSize:11,fontWeight:700,color:C.red,fontFamily:"'Sarabun',sans-serif"}}>ลบ</button>
            </>}
          </div>;})}
        </div>}
      </div>
      {/* Right: assign menus to the selected category */}
      <div>
        {!selCat?<div style={{padding:"40px 16px",textAlign:"center",color:C.ink4,fontFamily:"'Sarabun',sans-serif",border:`1px dashed ${C.line}`,borderRadius:12}}><Ic d={I.tag} s={40} c={C.line}/><p style={{marginTop:8,fontSize:13}}>คลิกหมวดทางซ้าย แล้วเลือกเมนูที่จะเพิ่มเข้าหมวดนั้น</p></div>
        :<>
          <div style={{fontFamily:"'Sarabun',sans-serif",fontSize:14,fontWeight:900,color:C.ink,marginBottom:8}}>เมนูในหมวด "{selCat}"</div>
          <input value={q} onChange={e=>setQ(e.target.value)} placeholder="ค้นหาเมนู..." style={{...iS,marginBottom:8}}/>
          <div style={{display:"flex",flexDirection:"column",gap:5,maxHeight:"44vh",overflowY:"auto"}}>
            {visibleMenus.map(m=>{const cur=catOf(m);const here=cur===selCat;const elsewhere=cur&&cur!==selCat;return <label key={m.id} title={elsewhere?`อยู่ในหมวด "${cur}" แล้ว`:""} style={{display:"flex",alignItems:"center",gap:10,padding:"9px 12px",borderRadius:9,cursor:elsewhere?"not-allowed":"pointer",background:here?C.brandLight:C.white,border:`1px solid ${here?C.brandBorder:C.line}`,opacity:elsewhere?.55:1}}>
              <input type="checkbox" checked={here} disabled={elsewhere} onChange={()=>toggleMenu(m,selCat)} style={{accentColor:C.brand,width:16,height:16,flexShrink:0}}/>
              <span style={{flex:1,fontFamily:"'Sarabun',sans-serif",fontSize:13.5,fontWeight:here?800:600,color:here?C.brand:C.ink,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{m.name}</span>
              {elsewhere&&<span style={{fontSize:10.5,color:C.ink4,fontFamily:"'Sarabun',sans-serif",whiteSpace:"nowrap"}}>อยู่ใน {cur}</span>}
            </label>;})}
            {visibleMenus.length===0&&<div style={{padding:20,textAlign:"center",color:C.ink4,fontSize:12,fontFamily:"'Sarabun',sans-serif"}}>ไม่พบเมนู</div>}
          </div>
        </>}
      </div>
    </div>}
  </Modal>;
}

// "ตัวเลือกในเมนู" — the branch's option-GROUP library. Create a group (name +
// required), then add sub-choices (name + price) under it. Bind whole groups to
// menus at "เมนูทั้งหมด". Stored in pos_settings.option_library =
// [{id,name,required,choices:[{id,name,price}]}].
function POSOptionLibrary({currentBranch,onClose}){
  const lbl={display:"block",fontSize:12,fontWeight:600,color:C.ink2,marginBottom:5,fontFamily:"'Sarabun',sans-serif"};
  const[settings,setSettings]=useState(null);const[lib,setLib]=useState([]);
  const[loading,setLoading]=useState(true);const[busy,setBusy]=useState(false);
  const[gName,setGName]=useState("");const[gReq,setGReq]=useState(false);
  const[ci,setCi]=useState({});                 // {groupId:{name,price}}
  const[editG,setEditG]=useState(null);const[eg,setEg]=useState({name:"",required:false});
  async function load(){setLoading(true);try{const ps=await api.getPOSSettings(currentBranch.id);const s=ps&&ps[0]?ps[0]:{branch_id:currentBranch.id};setSettings(s);setLib(Array.isArray(s.option_library)?s.option_library:[]);}catch(e){console.error("optLib",e);}setLoading(false);}
  useEffect(()=>{load();},[currentBranch.id]);
  async function persist(next){setBusy(true);try{const payload={...(settings||{}),branch_id:currentBranch.id,option_library:next};await api.upsertPOSSettings(payload);setSettings(payload);setLib(next);return true;}catch(e){alert("บันทึกไม่สำเร็จ: "+(e&&e.message||e));return false;}finally{setBusy(false);}}
  async function addGroup(){const name=gName.trim();if(!name)return alert("ใส่ชื่อกลุ่มตัวเลือก");if(lib.some(g=>g.name===name))return alert("มีกลุ่มนี้แล้ว");if(await persist([...lib,{id:`g_${Date.now()}_${Math.floor(Math.random()*1000)}`,name,required:gReq,choices:[]}])){setGName("");setGReq(false);}}
  async function delGroup(g){if(!await confirmDlg({title:"ลบกลุ่มตัวเลือก",message:`ลบกลุ่ม "${g.name}" และตัวเลือกย่อยทั้งหมด?`}))return;await persist(lib.filter(x=>x.id!==g.id));}
  async function saveEditG(){const name=(eg.name||"").trim();if(!name)return;if(await persist(lib.map(g=>g.id===editG?{...g,name,required:!!eg.required}:g)))setEditG(null);}
  async function addChoice(g){const f=ci[g.id]||{};const name=(f.name||"").trim();const price=+f.price||0;if(!name)return alert("ใส่ชื่อตัวเลือกย่อย");const next=lib.map(x=>x.id===g.id?{...x,choices:[...(x.choices||[]),{id:`c_${Date.now()}_${Math.floor(Math.random()*1000)}`,name,price}]}:x);if(await persist(next))setCi(s=>({...s,[g.id]:{name:"",price:""}}));}
  async function delChoice(g,cid){await persist(lib.map(x=>x.id===g.id?{...x,choices:(x.choices||[]).filter(c=>c.id!==cid)}:x));}
  return <Modal title="➕ ตัวเลือกในเมนู (กลุ่ม add-on)" onClose={onClose} extraWide>
    {loading?<Loading text="โหลดตัวเลือก..."/>:<>
      {/* Add group */}
      <div style={{display:"flex",gap:8,alignItems:"flex-end",marginBottom:14,flexWrap:"wrap",background:C.bg,borderRadius:10,padding:"10px 12px",border:`1px dashed ${C.line}`}}>
        <div style={{flex:"2 1 160px"}}><label style={lbl}>ชื่อกลุ่มตัวเลือก</label><input value={gName} onChange={e=>setGName(e.target.value)} onKeyDown={e=>e.key==="Enter"&&addGroup()} placeholder="เช่น ขนาด, ระดับเผ็ด" style={iS}/></div>
        <div style={{flex:"0 0 auto"}}><label style={lbl}>การเลือก</label><div style={{display:"flex",gap:5}}>{[{v:false,l:"ไม่บังคับ"},{v:true,l:"บังคับเลือก"}].map(o=><button key={String(o.v)} onClick={()=>setGReq(o.v)} style={{padding:"8px 12px",borderRadius:8,border:`2px solid ${gReq===o.v?(o.v?C.red:C.green):C.line}`,background:gReq===o.v?(o.v?C.redLight:C.greenLight):C.white,color:gReq===o.v?(o.v?C.red:C.green):C.ink3,cursor:"pointer",fontSize:12,fontWeight:700,fontFamily:"'Sarabun',sans-serif",whiteSpace:"nowrap"}}>{o.l}</button>)}</div></div>
        <Btn onClick={addGroup} loading={busy} icon={I.plus}>เพิ่มกลุ่ม</Btn>
      </div>
      {/* Groups */}
      {lib.length===0?<div style={{textAlign:"center",padding:36,color:C.ink4,fontFamily:"'Sarabun',sans-serif"}}><div style={{fontSize:40,marginBottom:6}}>📦</div><p style={{fontSize:13}}>ยังไม่มีกลุ่มตัวเลือก — เพิ่มด้านบน</p></div>
      :<div style={{display:"flex",flexDirection:"column",gap:12}}>
        {lib.map(g=>{const cf=ci[g.id]||{};return <div key={g.id} style={{border:`1.5px solid ${C.line}`,borderRadius:12,overflow:"hidden"}}>
          <div style={{display:"flex",alignItems:"center",gap:8,padding:"10px 12px",background:C.bg,borderBottom:`1px solid ${C.line}`,flexWrap:"wrap"}}>
            {editG===g.id?<>
              <input value={eg.name} onChange={e=>setEg(s=>({...s,name:e.target.value}))} autoFocus style={{...iS,flex:"1 1 140px"}}/>
              <div style={{display:"flex",gap:5}}>{[{v:false,l:"ไม่บังคับ"},{v:true,l:"บังคับ"}].map(o=><button key={String(o.v)} onClick={()=>setEg(s=>({...s,required:o.v}))} style={{padding:"7px 11px",borderRadius:8,border:`2px solid ${eg.required===o.v?(o.v?C.red:C.green):C.line}`,background:eg.required===o.v?(o.v?C.redLight:C.greenLight):C.white,color:eg.required===o.v?(o.v?C.red:C.green):C.ink3,cursor:"pointer",fontSize:11.5,fontWeight:700,fontFamily:"'Sarabun',sans-serif"}}>{o.l}</button>)}</div>
              <Btn onClick={saveEditG} loading={busy} s={{padding:"6px 12px",fontSize:12}}>บันทึก</Btn>
              <Btn v="ghost" onClick={()=>setEditG(null)} s={{padding:"6px 12px",fontSize:12}}>ยกเลิก</Btn>
            </>:<>
              <span style={{fontFamily:"'Sarabun',sans-serif",fontSize:15,fontWeight:900,color:C.ink}}>📦 {g.name}</span>
              {g.required?<span style={{fontSize:10.5,fontWeight:800,color:C.red,background:C.redLight,borderRadius:8,padding:"2px 8px"}}>* บังคับเลือก</span>:<span style={{fontSize:10.5,fontWeight:700,color:C.ink4,background:C.white,borderRadius:8,padding:"2px 8px",border:`1px solid ${C.line}`}}>ไม่บังคับ</span>}
              <span style={{fontSize:11,color:C.ink4,fontFamily:"'Sarabun',sans-serif"}}>· {(g.choices||[]).length} ตัวเลือกย่อย</span>
              <div style={{marginLeft:"auto",display:"flex",gap:6}}>
                <button onClick={()=>{setEditG(g.id);setEg({name:g.name,required:!!g.required});}} style={{background:C.blueLight,border:"none",borderRadius:7,padding:"6px 11px",cursor:"pointer",fontSize:12,fontWeight:700,color:C.blue,fontFamily:"'Sarabun',sans-serif"}}>แก้กลุ่ม</button>
                <button onClick={()=>delGroup(g)} style={{background:C.redLight,border:"none",borderRadius:7,padding:"6px 11px",cursor:"pointer",fontSize:12,fontWeight:700,color:C.red,fontFamily:"'Sarabun',sans-serif"}}>ลบกลุ่ม</button>
              </div>
            </>}
          </div>
          <div style={{padding:"10px 12px"}}>
            {(g.choices||[]).length>0&&<div style={{display:"flex",flexDirection:"column",gap:5,marginBottom:8}}>
              {(g.choices||[]).map(c=><div key={c.id} style={{display:"flex",alignItems:"center",gap:10,padding:"7px 10px",border:`1px solid ${C.lineLight}`,borderRadius:8,background:C.white}}>
                <span style={{flex:1,fontFamily:"'Sarabun',sans-serif",fontSize:13.5,fontWeight:600,color:C.ink}}>{c.name}</span>
                <span style={{fontFamily:"'Sarabun',sans-serif",fontSize:13,fontWeight:800,color:(+c.price||0)>0?C.brand:C.ink4}}>{(+c.price||0)>0?`+฿${(+c.price).toLocaleString()}`:"ฟรี"}</span>
                <button onClick={()=>delChoice(g,c.id)} style={{background:C.redLight,border:"none",borderRadius:6,padding:"4px 9px",cursor:"pointer",fontSize:11,fontWeight:700,color:C.red,fontFamily:"'Sarabun',sans-serif"}}>ลบ</button>
              </div>)}
            </div>}
            <div style={{display:"flex",gap:8,alignItems:"flex-end",flexWrap:"wrap"}}>
              <div style={{flex:"2 1 130px"}}><input value={cf.name||""} onChange={e=>setCi(s=>({...s,[g.id]:{...cf,name:e.target.value}}))} onKeyDown={e=>e.key==="Enter"&&addChoice(g)} placeholder="ชื่อตัวเลือกย่อย เช่น ใหญ่" style={{...iS,fontSize:13}}/></div>
              <div style={{flex:"0 0 100px"}}><input value={cf.price||""} onChange={e=>setCi(s=>({...s,[g.id]:{...cf,price:e.target.value.replace(/[^\d.]/g,"")}}))} inputMode="decimal" placeholder="+฿0" style={{...iS,fontSize:13}}/></div>
              <Btn onClick={()=>addChoice(g)} loading={busy} icon={I.plus} s={{padding:"8px 14px",fontSize:12}}>เพิ่มตัวเลือกย่อย</Btn>
            </div>
          </div>
        </div>;})}
      </div>}
    </>}
  </Modal>;
}

function POSShiftHistory({shifts,loading,reload}){
  if(loading)return <Loading text="โหลดประวัติกะ..."/>;
  if(shifts.length===0)return <div style={{textAlign:"center",padding:60,color:C.ink4,fontFamily:"'Sarabun',sans-serif"}}><Ic d={I.clock} s={48} c={C.line}/><p style={{marginTop:12}}>ยังไม่มีประวัติกะ</p></div>;
  return <div>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
      <h3 style={{fontFamily:"'Sarabun',sans-serif",fontSize:18,fontWeight:900,color:C.ink,margin:0}}>ประวัติกะ ({shifts.length})</h3>
      <Btn v="ghost" onClick={reload} icon={I.refresh} s={{padding:"7px 14px",fontSize:12}}>รีเฟรช</Btn>
    </div>
    <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(min(320px,100%),1fr))",gap:12}}>
      {shifts.map(s=>{
        const isOpen=s.status==='open';
        return <Card key={s.id} style={{padding:0,overflow:"hidden"}}>
          <div style={{padding:"10px 14px",background:isOpen?C.greenLight:C.bg,borderBottom:`1px solid ${C.line}`,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <div style={{fontFamily:"'Sarabun',sans-serif",fontWeight:800,fontSize:14,color:C.ink}}>กะ #{s.id}</div>
            <Chip color={isOpen?"green":"gray"}>{isOpen?"เปิดอยู่":"ปิดแล้ว"}</Chip>
          </div>
          <div style={{padding:"12px 14px",fontFamily:"'Sarabun',sans-serif",fontSize:12,color:C.ink2,lineHeight:1.7}}>
            <div>👤 {s.username||'-'}</div>
            <div>🕐 เปิด: {fmtDT(s.opened_at)}</div>
            {s.closed_at&&<div>🕔 ปิด: {fmtDT(s.closed_at)}</div>}
            <div style={{marginTop:8,paddingTop:8,borderTop:`1px dashed ${C.line}`,display:"grid",gridTemplateColumns:"1fr 1fr",gap:6,fontSize:12}}>
              <div>เริ่มต้น: <b>฿{(+s.opening_cash||0).toLocaleString()}</b></div>
              <div>บิล: <b>{s.order_count||0}</b></div>
              <div>ขาย: <b style={{color:C.brand}}>฿{(+s.total_sales||0).toLocaleString()}</b></div>
              <div>เงินสด: <b style={{color:C.green}}>฿{(+s.total_cash||0).toLocaleString()}</b></div>
              {!isOpen&&<>
                <div>ปิดที่: <b>฿{(+s.closing_cash||0).toLocaleString()}</b></div>
                <div>ส่วนต่าง: <b style={{color:s.cash_diff===0?C.green:s.cash_diff>0?C.blue:C.red}}>{s.cash_diff>0?'+':''}฿{Math.abs(+s.cash_diff||0).toLocaleString()}</b></div>
              </>}
            </div>
            {s.notes&&<div style={{marginTop:8,padding:"6px 10px",background:C.yellowLight,borderRadius:7,fontSize:11,color:C.ink3}}>📝 {s.notes}</div>}
          </div>
        </Card>;
      })}
    </div>
  </div>;
}

// Printer panel (extracted from SettingsTab for back-office)
function POSPrinterPanel({printers,reloadPrinters,branches,currentUser,menus=[]}){
  const isAdmin=hasPerm(currentUser,"settings");
  const pF0={name:"",ip:"",port:9100,description:"",type:"kitchen",branch_id:null,active:true,conn:"ip",btName:""};
  const[pForm,setPForm]=useState(pF0);const[editPID,setEditPID]=useState(null);const[pSaving,setPSaving]=useState(false);
  const[testResults,setTestResults]=useState({});const[btScanning,setBtScanning]=useState(false);
  // Category routing state
  const[catEditP,setCatEditP]=useState(null);  // printer object being edited
  const[catSel,setCatSel]=useState(null);       // null=catch-all, [] or [names]=specific
  const[catMenuOverride,setCatMenuOverride]=useState({});  // menu_id → assigned printer_id (for override view)
  const[catSaving,setCatSaving]=useState(false);
  const[openCats,setOpenCats]=useState(()=>new Set());  // category names expanded to show per-menu checkboxes
  function toggleOpenCat(c){setOpenCats(prev=>{const n=new Set(prev);if(n.has(c))n.delete(c);else n.add(c);return n;});}
  // แสดงเฉพาะหมวดที่ "สาขาของเครื่องพิมพ์นี้สร้างไว้" (local_categories[branch]) เท่านั้น
  // สาขาไหนยังไม่ได้สร้างหมวด → ว่าง (ขึ้นข้อความให้ไปสร้างก่อน) · เครื่อง branch=null = รวมทุกสาขา
  const allCategories=useMemo(()=>{
    if(!catEditP)return [];
    const bid=catEditP.branch_id;
    const s=new Set();
    menus.forEach(m=>{
      const lc=m.local_categories||{};
      if(bid!=null){const v=lc[bid];if(v&&String(v).trim())s.add(String(v).trim());}
      else Object.values(lc).forEach(v=>{if(v&&String(v).trim())s.add(String(v).trim());});
    });
    return [...s].sort();
  },[menus,catEditP]);
  // เมนูในหมวด c (เทียบจาก local_categories ของสาขานั้น)
  const menusInCat=(c)=>menus.filter(m=>{const lc=m.local_categories||{};return (catEditP&&catEditP.branch_id!=null)?lc[catEditP.branch_id]===c:Object.values(lc).includes(c);});
  function openCatEdit(p){
    setCatEditP(p);
    setCatSel(p.categories===undefined||p.categories===null?null:[...p.categories]);
    // Build menu→printer override map for the menus visible
    const ov={};menus.forEach(m=>{if(m.printer_id)ov[m.id]=+m.printer_id;});
    setCatMenuOverride(ov);
    setOpenCats(new Set());
  }
  async function saveCatEdit(){
    if(!catEditP)return;
    setCatSaving(true);
    try{
      await api.updatePrinter(catEditP.id,{categories:catSel});
      // Save menu-level overrides
      const updates=[];
      menus.forEach(m=>{const newPid=catMenuOverride[m.id]||null;const oldPid=m.printer_id||null;if(String(newPid)!==String(oldPid))updates.push(api.updateMenu(m.id,{printer_id:newPid}));});
      await Promise.all(updates);
      await reloadPrinters();
      setCatEditP(null);
    }catch(e){alert("บันทึกไม่สำเร็จ: "+e.message);}
    setCatSaving(false);
  }
  async function testPrinter(p){
    const conn=getPConn(p);
    setTestResults(r=>({...r,[p.id]:{status:"testing"}}));
    if(conn.type==="bluetooth"){
      try{
        if(!navigator.bluetooth)throw new Error("เบราว์เซอร์ไม่รองรับ Bluetooth");
        const device=await navigator.bluetooth.requestDevice({filters:conn.btName?[{name:conn.btName}]:undefined,acceptAllDevices:!conn.btName,optionalServices:_BT_SVC});
        const server=await device.gatt.connect();await server.getPrimaryServices();device.gatt.disconnect();
        setTestResults(r=>({...r,[p.id]:{status:"ok",msg:"เชื่อมต่อ Bluetooth สำเร็จ: "+device.name}}));
      }catch(e){setTestResults(r=>({...r,[p.id]:{status:"fail",msg:e.message}}));}
      return;
    }
    // IP/Network printer: POST a real ESC-POS test page.
    // Raw thermal printers at port 9100 don't speak HTTP, so we treat AbortError after timeout
    // as success (TCP connection was accepted, bytes sent, printer printed but never replied).
    // Only TypeError "Failed to fetch" (immediate refused) is a true failure.
    const enc=new TextEncoder();
    const concat=arrs=>{const len=arrs.reduce((a,b)=>a+b.length,0);const out=new Uint8Array(len);let off=0;for(const a of arrs){out.set(a,off);off+=a.length;}return out;};
    const body=concat([
      new Uint8Array([0x1B,0x40]),                // ESC @  init
      new Uint8Array([0x1B,0x61,0x01]),           // center
      new Uint8Array([0x1B,0x21,0x30]),           // double height/width
      enc.encode("PRINTER TEST\n"),
      new Uint8Array([0x1B,0x21,0x00]),           // normal
      enc.encode("FOODCOST POS\n"),
      enc.encode((p.name||"")+"\n"),
      enc.encode(new Date().toISOString().replace("T"," ").slice(0,19)+"\n"),
      enc.encode("--------------------------------\n"),
      new Uint8Array([0x1B,0x45,0x01]),           // bold on
      enc.encode("Connection OK\n"),
      new Uint8Array([0x1B,0x45,0x00]),           // bold off
      new Uint8Array([0x0A,0x0A,0x0A,0x0A]),      // feed
      new Uint8Array([0x1D,0x56,0x42,0x00]),      // partial cut
    ]);
    const ctrl=new AbortController();const tid=setTimeout(()=>ctrl.abort(),5000);
    let connectedFast=false;
    const startedAt=Date.now();
    try{
      await fetch(`http://${p.ip}:${p.port||9100}/`,{method:"POST",mode:"no-cors",cache:"no-store",headers:{"Content-Type":"application/octet-stream"},body,signal:ctrl.signal});
      clearTimeout(tid);
      setTestResults(r=>({...r,[p.id]:{status:"ok",msg:"ส่งคำสั่งพิมพ์ทดสอบแล้ว — ตรวจที่เครื่องว่ามีกระดาษออกมาไหม"}}));
    }catch(e){
      clearTimeout(tid);
      const elapsed=Date.now()-startedAt;
      if(e.name==="AbortError"){
        // 5s timeout reached — TCP almost certainly accepted the connection (raw printer doesn't HTTP-reply)
        setTestResults(r=>({...r,[p.id]:{status:"ok",msg:"✅ ส่งคำสั่งพิมพ์แล้ว (เครื่องไม่ตอบ HTTP เป็นเรื่องปกติ) — ดูที่เครื่องว่ามีกระดาษออกมาไหม"}}));
      }else if(elapsed<300){
        // Quick TypeError = network refused
        setTestResults(r=>({...r,[p.id]:{status:"fail",msg:"เชื่อมต่อไม่ได้ — ตรวจ IP/Port หรือไฟเครื่องพิมพ์"}}));
      }else{
        setTestResults(r=>({...r,[p.id]:{status:"ok",msg:"ส่งคำสั่งไปแล้ว — ดูที่เครื่อง"}}));
      }
    }
  }
  async function scanBTPrinter(all=false){
    if(!navigator.bluetooth){alert("เบราว์เซอร์ไม่รองรับ Bluetooth ต้องใช้ Chrome/Edge");return;}
    setBtScanning(true);
    try{
      const opts=all?{acceptAllDevices:true,optionalServices:_BT_SVC}:{filters:[{namePrefix:"XP-"},{namePrefix:"Xprinter"},{namePrefix:"MTP"},{namePrefix:"MPT"},{namePrefix:"RPP"},{namePrefix:"BT Printer"},{namePrefix:"BT-Printer"},{namePrefix:"Printer"},{namePrefix:"POS"},{namePrefix:"Thermal"},{namePrefix:"SPP"},{namePrefix:"GP-"},{namePrefix:"Gprinter"},{namePrefix:"PT-"},{namePrefix:"MP-"},{namePrefix:"P80"},{namePrefix:"P58"},{namePrefix:"HOIN"},{namePrefix:"Goojprt"},{namePrefix:"GOOJPRT"},{namePrefix:"BlueTooth"},{namePrefix:"HC-"},{namePrefix:"ESC"},{namePrefix:"TP"},..._BT_SVC.map(s=>({services:[s]}))],optionalServices:_BT_SVC};
      const device=await navigator.bluetooth.requestDevice(opts);
      setPForm(f=>({...f,btName:device.name||"",conn:"bluetooth"}));
    }catch(e){
      if(e.name==="NotFoundError"&&!all){if(await confirmDlg({title:"ไม่พบเครื่องปริ้น",message:"ไม่พบอุปกรณ์ที่ตรงกับชื่อเครื่องปริ้น\nต้องการแสดงอุปกรณ์ Bluetooth ทั้งหมดไหม?",confirmLabel:"แสดงทั้งหมด",danger:false})){setBtScanning(false);scanBTPrinter(true);return;}}
      else if(e.name!=="NotFoundError"&&e.name!=="NotAllowedError")alert("เกิดข้อผิดพลาด: "+e.message);
    }
    setBtScanning(false);
  }
  async function savePrinter(){
    const isBT=pForm.conn==="bluetooth";
    if(!pForm.name||(isBT?!pForm.btName:!pForm.ip))return;
    setPSaving(true);
    try{
      const d={name:pForm.name,ip:isBT?"bluetooth":pForm.ip,port:isBT?0:+pForm.port||9100,type:pForm.type,branch_id:pForm.branch_id||null,active:true,description:isBT?JSON.stringify({c:"bt",n:pForm.btName}):pForm.description};
      if(editPID)await api.updatePrinter(editPID,d);else await api.addPrinter(d);
      await reloadPrinters();setPForm(pF0);setEditPID(null);
    }catch(e){alert("บันทึกไม่สำเร็จ: "+e.message);}
    setPSaving(false);
  }
  return <div>
    <div style={{background:"linear-gradient(135deg,#0F172A 0%,#1E293B 100%)",borderRadius:16,padding:"22px 26px",marginBottom:20,display:"flex",alignItems:"center",justifyContent:"space-between",boxShadow:"0 4px 24px rgba(15,23,42,0.18)"}}>
      <div style={{display:"flex",alignItems:"center",gap:14}}>
        <div style={{width:48,height:48,background:"linear-gradient(135deg,#6366F1,#8B5CF6)",borderRadius:14,display:"flex",alignItems:"center",justifyContent:"center"}}><Ic d={I.print} s={22} c="#fff" sw={1.5}/></div>
        <div>
          <h2 style={{fontFamily:"'Sarabun',sans-serif",fontSize:20,fontWeight:900,color:"#F8FAFC",margin:0}}>เครื่องพิมพ์</h2>
          <p style={{fontSize:12,color:"rgba(255,255,255,0.45)",margin:"3px 0 0",fontFamily:"'Sarabun',sans-serif"}}>Network/Bluetooth Printer — Xprinter / ESC-POS 80mm</p>
        </div>
      </div>
      <div style={{display:"flex",gap:8}}>
        {[{label:"เครื่องพิมพ์ทั้งหมด",count:printers.length,color:"#6366F1"}].map(s=><div key={s.label} style={{textAlign:"center",background:"rgba(255,255,255,0.07)",borderRadius:10,padding:"7px 14px",border:"1px solid rgba(255,255,255,0.1)"}}>
          <div style={{fontSize:18,fontWeight:900,color:s.color,lineHeight:1}}>{s.count}</div>
          <div style={{fontSize:10,color:"rgba(255,255,255,0.45)",fontFamily:"'Sarabun',sans-serif",marginTop:2}}>{s.label}</div>
        </div>)}
      </div>
    </div>
    {isAdmin&&<div style={{background:C.white,borderRadius:14,border:`1px solid ${C.line}`,marginBottom:20,overflow:"hidden",boxShadow:"0 2px 12px rgba(0,0,0,0.05)"}}>
      <div style={{padding:"14px 22px",borderBottom:`1px solid ${C.line}`,background:editPID?"#FFF7ED":"#F8FAFF",display:"flex",alignItems:"center",gap:10}}>
        <div style={{width:28,height:28,background:editPID?"#F59E0B22":"#6366F122",borderRadius:8,display:"flex",alignItems:"center",justifyContent:"center"}}><Ic d={editPID?I.pencil:I.plus} s={13} c={editPID?"#F59E0B":"#6366F1"}/></div>
        <span style={{fontFamily:"'Sarabun',sans-serif",fontSize:14,fontWeight:800,color:C.ink}}>{editPID?"แก้ไขเครื่องพิมพ์":"เพิ่มเครื่องพิมพ์ใหม่"}</span>
        {editPID&&<Chip color="yellow">กำลังแก้ไข</Chip>}
      </div>
      <div style={{padding:"18px 22px"}}>
        <div style={{display:"grid",gridTemplateColumns:"2fr 1.4fr 1fr",gap:12,marginBottom:12}}>
          <Inp label="ชื่อเครื่องพิมพ์ *" value={pForm.name} onChange={e=>setPForm(f=>({...f,name:e.target.value}))} placeholder="เช่น ครัวหลัก, บาร์"/>
          <div>
            <label style={{display:"block",fontSize:13,fontWeight:600,color:C.ink2,marginBottom:6,fontFamily:"'Sarabun',sans-serif"}}>ประเภทการเชื่อมต่อ</label>
            <div style={{display:"flex",gap:0,borderRadius:10,overflow:"hidden",border:`1.5px solid ${C.line}`}}>
              {[{v:"ip",label:"🌐 IP"},{v:"bluetooth",label:"📶 BT"}].map(o=><button key={o.v} onClick={()=>setPForm(f=>({...f,conn:o.v}))} style={{flex:1,padding:"9px 0",border:"none",background:pForm.conn===o.v?`linear-gradient(135deg,${C.brand},${C.brandDark})`:C.white,color:pForm.conn===o.v?C.white:C.ink3,fontFamily:"'Sarabun',sans-serif",fontSize:12,fontWeight:700,cursor:"pointer"}}>{o.label}</button>)}
            </div>
          </div>
                    <div><label style={{display:"block",fontSize:13,fontWeight:600,color:C.ink2,marginBottom:6,fontFamily:"'Sarabun',sans-serif"}}>สาขา</label><select value={pForm.branch_id||""} onChange={e=>setPForm(f=>({...f,branch_id:e.target.value?+e.target.value:null}))} style={{...iS,appearance:"none"}}><option value="">ทุกสาขา</option>{(branches||[]).map(b=><option key={b.id} value={b.id}>{b.name}</option>)}</select></div>
        </div>
        {pForm.conn==="ip"?<div style={{display:"grid",gridTemplateColumns:"1fr auto auto",gap:12,marginBottom:12,alignItems:"flex-end"}}>
          <Inp label="IP Address *" value={pForm.ip} onChange={e=>setPForm(f=>({...f,ip:e.target.value}))} placeholder="192.168.1.100"/>
          <Inp label="Port" type="number" value={pForm.port} onChange={e=>setPForm(f=>({...f,port:+e.target.value}))} placeholder="9100" style={{width:90}}/>
          <Inp label="หมายเหตุ" value={pForm.description} onChange={e=>setPForm(f=>({...f,description:e.target.value}))} placeholder="ครัวหลัก..."/>
        </div>:<div style={{marginBottom:12,background:C.bg,borderRadius:10,padding:"14px 16px",border:`1.5px dashed ${C.brand}44`}}>
          <div style={{fontSize:12,fontWeight:700,color:C.ink3,marginBottom:8,fontFamily:"'Sarabun',sans-serif"}}>อุปกรณ์ Bluetooth</div>
          {pForm.btName?<div style={{display:"flex",alignItems:"center",gap:10,marginBottom:8}}>
            <div style={{width:34,height:34,background:C.brandLight,borderRadius:9,display:"flex",alignItems:"center",justifyContent:"center",fontSize:17}}>📶</div>
            <div><div style={{fontWeight:800,fontSize:13,color:C.ink,fontFamily:"'Sarabun',sans-serif"}}>{pForm.btName}</div><div style={{fontSize:11,color:C.green,fontWeight:600}}>✅ จับคู่แล้ว</div></div>
            <button onClick={()=>setPForm(f=>({...f,btName:""}))} style={{marginLeft:"auto",background:C.redLight,border:"none",borderRadius:7,padding:"4px 9px",cursor:"pointer",color:C.red,fontSize:11,fontWeight:700,fontFamily:"'Sarabun',sans-serif"}}>ล้าง</button>
          </div>:<div style={{color:C.ink4,fontSize:12,fontFamily:"'Sarabun',sans-serif",marginBottom:8}}>ยังไม่ได้จับคู่อุปกรณ์</div>}
          <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
            <button onClick={()=>scanBTPrinter(false)} disabled={btScanning} style={{background:`linear-gradient(135deg,${C.brand},${C.brandDark})`,color:C.white,border:"none",borderRadius:9,padding:"8px 16px",cursor:btScanning?"not-allowed":"pointer",fontFamily:"'Sarabun',sans-serif",fontSize:12,fontWeight:700,opacity:btScanning?.6:1,display:"flex",alignItems:"center",gap:6}}>📶 {btScanning?"กำลังสแกน...":"สแกนเครื่องปริ้น"}</button>
            <button onClick={()=>scanBTPrinter(true)} disabled={btScanning} style={{background:C.white,color:C.ink2,border:`1.5px solid ${C.line}`,borderRadius:9,padding:"8px 14px",cursor:btScanning?"not-allowed":"pointer",fontFamily:"'Sarabun',sans-serif",fontSize:12,fontWeight:600,opacity:btScanning?.6:1}}>🔍 แสดงทั้งหมด</button>
          </div>
        </div>}
        <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
          {editPID&&<Btn v="ghost" onClick={()=>{setPForm(pF0);setEditPID(null);}}>ยกเลิก</Btn>}
          <Btn onClick={savePrinter} icon={I.check} disabled={!pForm.name||(pForm.conn==="bluetooth"?!pForm.btName:!pForm.ip)} loading={pSaving} s={{minWidth:160}}>{editPID?"บันทึกการแก้ไข":"เพิ่มเครื่องพิมพ์"}</Btn>
        </div>
      </div>
    </div>}
    <div style={{marginBottom:14,display:"flex",alignItems:"center",justifyContent:"space-between"}}>
      <h3 style={{fontFamily:"'Sarabun',sans-serif",fontSize:15,fontWeight:800,color:C.ink,margin:0}}>เครื่องพิมพ์ที่เชื่อมต่อ <span style={{fontSize:12,fontWeight:600,color:C.ink4}}>({printers.length} เครื่อง)</span></h3>
      <div style={{fontSize:11,color:C.ink4,fontFamily:"'Sarabun',sans-serif",background:C.blueLight,padding:"5px 12px",borderRadius:18,border:`1px solid #BFDBFE`}}>💡 ไปที่หน้า <b>เมนู</b> เพื่อกำหนดเครื่องพิมพ์ให้แต่ละเมนู</div>
    </div>
    {printers.length===0?<div style={{background:C.white,border:`2px dashed ${C.line}`,borderRadius:14,padding:"50px 20px",textAlign:"center"}}>
      <div style={{width:56,height:56,background:C.lineLight,borderRadius:18,display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 12px"}}><Ic d={I.print} s={26} c={C.ink4}/></div>
      <div style={{fontSize:15,fontWeight:700,color:C.ink3,fontFamily:"'Sarabun',sans-serif",marginBottom:6}}>ยังไม่มีเครื่องพิมพ์</div>
      <div style={{fontSize:12,color:C.ink4,fontFamily:"'Sarabun',sans-serif"}}>เพิ่มเครื่องพิมพ์แรกของคุณด้านบน</div>
    </div>:<div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(min(320px,100%),1fr))",gap:14}}>
      {printers.map(p=>{
        const typeConf={label:getPConn(p).type==="bluetooth"?"บลูทูธ":"เครือข่าย",emoji:"🖨️",color:C.ink3,bg:C.bg,border:C.line};
        return <div key={p.id} style={{background:C.white,border:`1px solid ${C.line}`,borderRadius:14,overflow:"hidden",boxShadow:"0 2px 8px rgba(0,0,0,0.05)"}}>
          <div style={{padding:"14px 18px 12px",borderBottom:`1px solid ${C.line}`,background:`linear-gradient(135deg,${typeConf.bg},${C.white})`,display:"flex",alignItems:"flex-start",gap:12}}>
            <div style={{width:42,height:42,background:typeConf.bg,border:`2px solid ${typeConf.border}`,borderRadius:12,display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,flexShrink:0}}>{typeConf.emoji}</div>
            <div style={{flex:1,minWidth:0}}>
              <div style={{fontWeight:800,fontSize:14,color:C.ink,fontFamily:"'Sarabun',sans-serif",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",marginBottom:4}}>{p.name}</div>
              <div style={{display:"inline-flex",alignItems:"center",gap:5,background:typeConf.bg,border:`1px solid ${typeConf.border}`,borderRadius:18,padding:"2px 10px"}}>
                <span style={{fontSize:11,fontWeight:700,color:typeConf.color,fontFamily:"'Sarabun',sans-serif"}}>{typeConf.label}</span>
              </div>
            </div>
            {isAdmin&&<div style={{display:"flex",gap:5,flexShrink:0}}>
              <button onClick={()=>openCatEdit(p)} title="หมวดหมู่ที่รับผิดชอบ" style={{background:"#FEF3C7",border:`1px solid #FDE68A`,borderRadius:8,padding:"5px 8px",cursor:"pointer",display:"flex",alignItems:"center",gap:4}}><span style={{fontSize:13}}>🍳</span><span style={{fontSize:11,color:"#92400E",fontFamily:"'Sarabun',sans-serif",fontWeight:700}}>หมวด</span></button>
              <button onClick={()=>{const pc=getPConn(p);setPForm({name:p.name,ip:pc.type==="bluetooth"?"":p.ip,port:p.port||9100,description:pc.type==="bluetooth"?"":p.description||"",type:p.type||"kitchen",branch_id:p.branch_id,active:p.active,conn:pc.type,btName:pc.btName||""});setEditPID(p.id);}} title="แก้ไข" style={{background:C.blueLight,border:`1px solid #BFDBFE`,borderRadius:8,padding:"5px 8px",cursor:"pointer",display:"flex",alignItems:"center",gap:4}}><Ic d={I.pencil} s={12} c={C.blue}/><span style={{fontSize:11,color:C.blue,fontFamily:"'Sarabun',sans-serif",fontWeight:700}}>แก้</span></button>
              <button onClick={async()=>{if(!await confirmDlg({title:"ลบเครื่องปริ้น",message:`ต้องการลบ "${p.name}" ใช่หรือไม่?`}))return;try{await api.deletePrinter(p.id);await reloadPrinters();}catch{alert("ลบไม่สำเร็จ");}}} title="ลบ" style={{background:C.redLight,border:`1px solid #FECACA`,borderRadius:8,padding:"5px 8px",cursor:"pointer",display:"flex",alignItems:"center",gap:4}}><Ic d={I.trash} s={12} c={C.red}/><span style={{fontSize:11,color:C.red,fontFamily:"'Sarabun',sans-serif",fontWeight:700}}>ลบ</span></button>
            </div>}
          </div>
          <div style={{padding:"12px 18px"}}>
            {(()=>{const tr=testResults[p.id];const dotColor=!tr?C.ink3:tr.status==="testing"?C.yellow:tr.status==="ok"?C.green:C.red;const pc=getPConn(p);const isBT=pc.type==="bluetooth";return<div style={{display:"flex",alignItems:"center",gap:10,padding:"9px 12px",background:"#F8FAFC",borderRadius:9,border:`1px solid ${tr?.status==="ok"?C.green:tr?.status==="fail"?C.red:C.line}`}}>
              <div style={{width:9,height:9,borderRadius:"50%",background:dotColor,boxShadow:`0 0 6px ${dotColor}88`,flexShrink:0,animation:tr?.status==="testing"?"pulse 1s infinite":"none"}}/>
              <div style={{flex:1,minWidth:0}}>
                <div style={{display:"flex",alignItems:"center",gap:6}}>
                  <span style={{fontSize:10,background:isBT?C.brandLight:C.blueLight,color:isBT?C.brand:C.blue,border:`1px solid ${isBT?C.brandBorder:"#BFDBFE"}`,borderRadius:5,padding:"1px 6px",fontWeight:700,fontFamily:"'Sarabun',sans-serif"}}>{isBT?"📶 BT":"🌐 IP"}</span>
                  <span style={{fontSize:12,fontWeight:800,color:C.ink,fontFamily:"monospace"}}>{isBT?pc.btName||"—":`${p.ip}:${p.port||9100}`}</span>
                </div>
                <div style={{fontSize:10,color:tr?.status==="ok"?C.green:tr?.status==="fail"?C.red:C.ink4,fontFamily:"'Sarabun',sans-serif",fontWeight:tr?600:400,marginTop:1}}>
                  {!tr&&(isBT?"กดทดสอบเพื่อจับคู่":"IP : Port")}
                  {tr?.status==="testing"&&"⏳ กำลังทดสอบ..."}
                  {tr?.status==="ok"&&`✅ ${tr.msg}`}
                  {tr?.status==="fail"&&`❌ ${tr.msg}`}
                </div>
              </div>
              <button onClick={()=>testPrinter(p)} disabled={testResults[p.id]?.status==="testing"} style={{padding:"5px 12px",borderRadius:7,border:`1.5px solid ${C.brand}`,background:testResults[p.id]?.status==="testing"?C.lineLight:C.brandLight,color:C.brand,cursor:testResults[p.id]?.status==="testing"?"not-allowed":"pointer",fontSize:11,fontWeight:700,fontFamily:"'Sarabun',sans-serif",whiteSpace:"nowrap"}}>{testResults[p.id]?.status==="testing"?"...":"🔌 ทดสอบ"}</button>
            </div>;})()}
            {/* Categories badge */}
            {(()=>{const cats=p.categories;const overrideCount=menus.filter(m=>+m.printer_id===p.id).length;return <div style={{marginTop:6,padding:"7px 11px",borderRadius:8,background:cats===null||cats===undefined?C.greenLight:cats.length===0?C.lineLight:"#FEF3C7",border:`1px solid ${cats===null||cats===undefined?"#86EFAC":cats.length===0?C.line:"#FDE68A"}`,fontSize:11,fontFamily:"'Sarabun',sans-serif",color:cats===null||cats===undefined?C.green:cats.length===0?C.ink4:"#92400E",display:"flex",alignItems:"center",gap:6,flexWrap:"wrap"}}>
              <span style={{fontWeight:800}}>🍳 รับผิดชอบ:</span>
              <span style={{fontWeight:600}}>{cats===null||cats===undefined?"ทุกหมวด (catch-all)":cats.length===0?"ไม่รับงานอัตโนมัติ":cats.join(", ")}</span>
              {overrideCount>0&&<span style={{marginLeft:"auto",background:C.purpleLight,color:C.purple,padding:"1px 8px",borderRadius:10,fontSize:10,fontWeight:700}}>+{overrideCount} เมนู (override)</span>}
            </div>;})()}
            {p.branch_id&&(branches||[]).find(b=>b.id===p.branch_id)&&<div style={{fontSize:11,color:C.ink3,fontFamily:"'Sarabun',sans-serif",marginTop:6,display:"flex",alignItems:"center",gap:5}}><Ic d={I.branch} s={12} c={C.ink4}/>สาขา: <b>{branches.find(b=>b.id===p.branch_id)?.name}</b></div>}
            {!p.branch_id&&<div style={{fontSize:11,color:C.teal,fontFamily:"'Sarabun',sans-serif",marginTop:6,display:"flex",alignItems:"center",gap:5}}><Ic d={I.shop} s={12} c={C.teal}/>ใช้งานได้ทุกสาขา</div>}
          </div>
        </div>;
      })}
    </div>}
    {/* Category routing modal */}
    {catEditP&&<Modal title={`🍳 หมวดหมู่ที่รับผิดชอบ — ${catEditP.name}`} onClose={()=>setCatEditP(null)} extraWide>
      <div>
        {/* Header: title + quick actions */}
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8,flexWrap:"wrap",gap:8}}>
          <div style={{fontSize:13,fontWeight:800,color:C.ink2,fontFamily:"'Sarabun',sans-serif"}}>📂 หมวดหมู่</div>
          <div style={{display:"flex",gap:6}}>
            <button onClick={()=>setCatSel(null)} style={{padding:"4px 10px",borderRadius:7,border:`1px solid ${catSel===null?C.green:C.line}`,background:catSel===null?C.greenLight:C.white,color:catSel===null?C.green:C.ink3,cursor:"pointer",fontSize:11,fontWeight:700,fontFamily:"'Sarabun',sans-serif"}}>ทุกหมวด (catch-all)</button>
            <button onClick={()=>setCatSel([...allCategories])} style={{padding:"4px 10px",borderRadius:7,border:`1px solid ${C.line}`,background:C.white,color:C.ink3,cursor:"pointer",fontSize:11,fontWeight:700,fontFamily:"'Sarabun',sans-serif"}}>เลือกทั้งหมด</button>
            <button onClick={()=>setCatSel([])} style={{padding:"4px 10px",borderRadius:7,border:`1px solid ${C.line}`,background:C.white,color:C.ink3,cursor:"pointer",fontSize:11,fontWeight:700,fontFamily:"'Sarabun',sans-serif"}}>ล้าง</button>
          </div>
        </div>
        {catSel===null
          ?<div style={{padding:"14px 16px",background:C.greenLight,borderRadius:10,border:`1.5px solid ${C.green}`,fontSize:13,color:C.green,fontFamily:"'Sarabun',sans-serif",fontWeight:600,lineHeight:1.7}}>
            ✅ <b>Catch-all</b> — เครื่องนี้รับงานพิมพ์ทุกหมวด<br/>
            <span style={{fontSize:11,fontWeight:400}}>ใช้เป็น "เครื่องสำรอง" — ระบบจะส่งงานมาที่นี่ถ้าไม่มีเครื่องอื่น match หมวดของเมนู</span>
          </div>
          :allCategories.length===0
            ?<div style={{padding:30,textAlign:"center",color:C.ink4,fontSize:13,fontFamily:"'Sarabun',sans-serif"}}>ยังไม่มีหมวดหมู่เมนู — เพิ่มหมวดในแท็บ "เมนู" ก่อน</div>
            :<>
              <div style={{display:"flex",flexDirection:"column",gap:8,maxHeight:"58vh",overflowY:"auto",paddingRight:2}}>
                {allCategories.map(c=>{
                  const has=catSel.includes(c);
                  const catMenus=menusInCat(c);
                  const isOpen=openCats.has(c);
                  const pinnedHereCount=catMenus.filter(m=>{const cur=catMenuOverride[m.id];return cur!=null&&+cur===+catEditP.id;}).length;
                  // ติ๊กครบทุกเมนู → หัวหมวดติ๊กอัตโนมัติ (รู้ว่าเลือกครบทั้งหมวด) · ติ๊กบางส่วน → ขีดครึ่ง (–)
                  const allHere=catMenus.length>0&&pinnedHereCount===catMenus.length;const checked=has||allHere;const indet=!checked&&pinnedHereCount>0;
                  const toggleCatMaster=()=>{if(checked){setCatSel(prev=>{const cur=prev===null?allCategories.slice():prev;return cur.filter(x=>x!==c);});setCatMenuOverride(prev=>{const n={...prev};catMenus.forEach(m=>{if(n[m.id]!=null&&+n[m.id]===+catEditP.id)n[m.id]=null;});return n;});}else{setCatSel(prev=>{const cur=prev===null?allCategories.slice():prev;return cur.includes(c)?cur:[...cur,c];});}};
                  return <div key={c} style={{border:`1.5px solid ${checked?C.brandBorder:(indet?`${C.brand}66`:C.line)}`,borderRadius:10,overflow:"hidden",background:checked?C.brandLight:C.white,transition:"all .15s",flexShrink:0}}>
                    {/* Category header */}
                    <div style={{display:"flex",alignItems:"center",gap:10,padding:"10px 12px"}}>
                      <input type="checkbox" checked={checked} ref={el=>{if(el)el.indeterminate=indet;}} onChange={toggleCatMaster} style={{accentColor:C.brand,width:17,height:17,cursor:"pointer",flexShrink:0}}/>
                      <div style={{flex:1,minWidth:0,cursor:"pointer"}} onClick={()=>toggleOpenCat(c)}>
                        <div style={{fontSize:14,fontFamily:"'Sarabun',sans-serif",fontWeight:checked?800:600,color:checked?C.brand:C.ink2,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{c}</div>
                        <div style={{fontSize:10.5,color:C.ink4,fontFamily:"'Sarabun',sans-serif"}}>{catMenus.length} เมนู{allHere?" · ✓ เลือกครบทั้งหมวด":pinnedHereCount>0?` · 📌 ปักหมุดเครื่องนี้ ${pinnedHereCount}`:""}</div>
                      </div>
                      <button onClick={()=>toggleOpenCat(c)} style={{display:"flex",alignItems:"center",gap:5,background:isOpen?C.brand:C.white,color:isOpen?C.white:C.ink3,border:`1px solid ${isOpen?C.brand:C.line}`,borderRadius:8,padding:"5px 10px",cursor:"pointer",fontSize:11,fontWeight:700,fontFamily:"'Sarabun',sans-serif",whiteSpace:"nowrap",flexShrink:0}}>
                        <span style={{fontSize:9}}>{isOpen?"▼":"▶"}</span> ระบุรายเมนู
                      </button>
                    </div>
                    {/* Expanded: per-menu checkboxes — ติ๊กเพื่อปักหมุดเมนูให้ออกเครื่องนี้ */}
                    {isOpen&&<div style={{borderTop:`1px dashed ${C.line}`,padding:"10px 12px",background:C.white}}>
                      {catMenus.length===0
                        ?<div style={{fontSize:11,color:C.ink4,fontFamily:"'Sarabun',sans-serif",textAlign:"center",padding:8}}>ไม่มีเมนูในหมวดนี้</div>
                        :<div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(min(240px,100%),1fr))",gap:6}}>
                          {catMenus.map(m=>{
                            const cur=catMenuOverride[m.id];
                            const pinnedHere=cur!=null&&+cur===+catEditP.id;
                            const pinnedOther=cur!=null&&+cur!==+catEditP.id;
                            const otherName=pinnedOther?(printers.find(pr=>+pr.id===+cur)?.name||"เครื่องอื่น"):"";
                            return <label key={m.id} style={{display:"flex",alignItems:"center",gap:8,padding:"7px 10px",borderRadius:8,cursor:"pointer",background:pinnedHere?C.brandLight:C.bg,border:`1px solid ${pinnedHere?C.brandBorder:C.line}`,transition:"all .12s"}}>
                              <input type="checkbox" checked={pinnedHere} onChange={()=>setCatMenuOverride(prev=>({...prev,[m.id]:pinnedHere?null:catEditP.id}))} style={{accentColor:C.brand,width:15,height:15,cursor:"pointer",flexShrink:0}}/>
                              <div style={{flex:1,minWidth:0}}>
                                <div style={{fontSize:12.5,fontFamily:"'Sarabun',sans-serif",fontWeight:pinnedHere?800:600,color:pinnedHere?C.brand:C.ink2,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{m.name}</div>
                                {pinnedOther&&<div style={{fontSize:9.5,color:"#B45309",fontFamily:"'Sarabun',sans-serif",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>📌 ปักหมุดที่ {otherName}</div>}
                              </div>
                            </label>;
                          })}
                        </div>}
                    </div>}
                  </div>;
                })}
              </div>
            </>}
      </div>
      <div style={{display:"flex",justifyContent:"flex-end",gap:8,paddingTop:14,borderTop:`1px solid ${C.line}`,marginTop:14}}>
        <Btn v="ghost" onClick={()=>setCatEditP(null)}>ยกเลิก</Btn>
        <Btn onClick={saveCatEdit} loading={catSaving} icon={I.check}>บันทึก</Btn>
      </div>
    </Modal>}
  </div>;
}

// ══════════════════════════════════════════════════════
// ── POS SALE MODE (โหมดขายหน้าร้าน) ────────────────────
// ══════════════════════════════════════════════════════
function POSSaleMode({menus,reloadMenus,currentBranch,currentUser,printers=[],shift,zones=[],posSettings,promotions=[],onUpdateShift,onCashDrawer,onCloseShift,onExitMode,saleOnly=false,reloadPosSettings,refreshTick=0,reloadZones}){
  const[posTab,setPosTab]=useState("tables");
  const[tables,setTables]=useState([]);const[activeOrders,setActiveOrders]=useState([]);
  const[loading,setLoading]=useState(true);
  const[selTable,setSelTable]=useState(null);const[selOrder,setSelOrder]=useState(null);
  const[showPrinters,setShowPrinters]=useState(false);
  const[showReceipt,setShowReceipt]=useState(false);
  const[showOrders,setShowOrders]=useState(false);   // today's-orders modal (re-added after the tab was replaced)
  const[printStation,setPS]=useState(isPrintStation());   // is THIS device the print station?
  const timerRef=useRef(null);
  const canEdit=hasPerm(currentUser,"pos");

  const printedRef=useRef(new Set(JSON.parse(sessionStorage.getItem("fc_printed_orders")||"[]")));
  const lastSigRef=useRef(new Map());
  const stationPrimedRef=useRef(false);   // skip the first batch so a station restart doesn't reprint open orders
  const wakeLockRef=useRef(null);         // screen wake lock so the print station's screen never sleeps
  function persistPrinted(){try{sessionStorage.setItem("fc_printed_orders",JSON.stringify([...printedRef.current]));}catch{}}
  // Only the designated print station auto-prints — and it prints EVERY new order
  // (staff + customer), since the iPads can't print themselves.
  function autoPrintNew(orders){
    if(!isPrintStation())return;
    // First pass after (re)becoming the station: record what's already open WITHOUT
    // printing, so a restart doesn't spew a reprint of every active order.
    if(!stationPrimedRef.current){
      orders.forEach(o=>{if(!o||!o.items)return;const sig=JSON.stringify(o.items.map(i=>[i.menu_id,i.qty,i.note||""]));lastSigRef.current.set(o.id,sig);printedRef.current.add(`${o.id}:init`);});
      persistPrinted();stationPrimedRef.current=true;return;
    }
    orders.forEach(o=>{
      if(!o||!o.items||o.items.length===0)return;
      if(o.status==="paid"||o.status==="cancelled")return;
      const sig=JSON.stringify(o.items.map(i=>[i.menu_id,i.qty,i.note||""]));
      const lastSig=lastSigRef.current.get(o.id);
      const isFirst=!printedRef.current.has(`${o.id}:init`);
      if(isFirst){
        const newItems=lastSig?(()=>{try{const old=JSON.parse(lastSig);const oldMap=new Map(old.map(([m,q,n])=>[`${m}|${n}`,q]));return o.items.filter(i=>{const k=`${i.menu_id}|${i.note||""}`;return!oldMap.has(k)||oldMap.get(k)<i.qty;}).map(i=>{const k=`${i.menu_id}|${i.note||""}`;const oldQ=oldMap.get(k)||0;return{...i,qty:i.qty-oldQ};});}catch{return o.items;}})():o.items;
        if(newItems.length>0){printKitchen(newItems,o.table_number,printers);}
        printedRef.current.add(`${o.id}:init`);persistPrinted();
      }else if(lastSig&&lastSig!==sig){
        try{
          const old=JSON.parse(lastSig);const oldMap=new Map(old.map(([m,q,n])=>[`${m}|${n}`,q]));
          const newItems=o.items.filter(i=>{const k=`${i.menu_id}|${i.note||""}`;return!oldMap.has(k)||oldMap.get(k)<i.qty;}).map(i=>{const k=`${i.menu_id}|${i.note||""}`;const oldQ=oldMap.get(k)||0;return{...i,qty:i.qty-oldQ};});
          if(newItems.length>0)printKitchen(newItems,o.table_number,printers);
        }catch{}
      }
      lastSigRef.current.set(o.id,sig);
    });
  }

  async function loadTables(){const t=await api.getPOSTables(currentBranch.id);setTables(t);}
  // Table editing from the floor plan (optimistic local update + persist)
  async function handleAddTable(d){try{await api.addPOSTable({...d,branch_id:currentBranch.id,status:"available",active:true});await loadTables();}catch(e){alert("เพิ่มโต๊ะไม่สำเร็จ: "+(e&&e.message||e));}}
  async function handleUpdateTable(id,d){setTables(p=>p.map(t=>t.id===id?{...t,...d}:t));try{await api.updatePOSTable(id,d);}catch(e){alert("แก้ไขโต๊ะไม่สำเร็จ: "+(e&&e.message||e));loadTables();}}
  async function handleDeleteTable(id){const prev=tables;setTables(p=>p.filter(t=>t.id!==id));try{await api.deletePOSTable(id);}catch(e){alert("ลบโต๊ะไม่สำเร็จ: "+(e&&e.message||e));setTables(prev);}}
  async function handleMoveTable(id,x,y){setTables(p=>p.map(t=>t.id===id?{...t,x,y}:t));try{await api.updatePOSTable(id,{x,y});}catch(e){console.error("move table save failed",e);}}
  // Zone rename/delete from the floor plan (rename cascades to tables; delete moves its tables to no-zone)
  async function handleRenameZone(oldName,newName,id){
    if(id)await api.updateZone(id,{name:newName});
    const affected=tables.filter(t=>t.zone===oldName);
    for(const t of affected)await api.updatePOSTable(t.id,{zone:newName});
    setTables(p=>p.map(t=>t.zone===oldName?{...t,zone:newName}:t));
    if(reloadZones)await reloadZones();
  }
  async function handleDeleteZone(name,id){
    const affected=tables.filter(t=>t.zone===name);
    for(const t of affected)await api.updatePOSTable(t.id,{zone:""});
    setTables(p=>p.map(t=>t.zone===name?{...t,zone:""}:t));
    if(id)await api.deleteZone(id);
    if(reloadZones)await reloadZones();
  }
  async function loadOrders(){const o=await api.getActiveOrders(currentBranch.id);setActiveOrders(o);autoPrintNew(o);}
  async function loadAll(){setLoading(true);try{await Promise.all([loadTables(),loadOrders()]);}catch(e){console.error(e);}setLoading(false);}

  useEffect(()=>{
    stationPrimedRef.current=false;   // re-prime on mount and whenever station mode flips
    loadAll();
    // The print station polls faster (6s) so kitchen tickets come out quickly; other devices stay light (20s).
    const period=printStation?6000:20000;
    timerRef.current=setInterval(()=>{if(!document.hidden)loadOrders();},period);
    const onVis=()=>{if(!document.hidden)loadOrders();};
    document.addEventListener("visibilitychange",onVis);
    return()=>{clearInterval(timerRef.current);document.removeEventListener("visibilitychange",onVis);};
  },[printStation]);// eslint-disable-line react-hooks/exhaustive-deps
  // Keep the print-station screen awake (Screen Wake Lock — works on Android Chrome over
  // https). The OS drops the lock whenever the page is hidden, so re-acquire on re-show.
  useEffect(()=>{
    if(!printStation)return;
    let cancelled=false;
    async function acquire(){
      try{
        if("wakeLock" in navigator && navigator.wakeLock?.request && document.visibilityState==="visible"){
          wakeLockRef.current=await navigator.wakeLock.request("screen");
        }
      }catch(e){/* unsupported / denied / not visible — manual screen-timeout is the fallback */}
    }
    function onVis(){if(document.visibilityState==="visible"&&!cancelled)acquire();}
    acquire();
    document.addEventListener("visibilitychange",onVis);
    return()=>{
      cancelled=true;
      document.removeEventListener("visibilitychange",onVis);
      try{wakeLockRef.current&&wakeLockRef.current.release&&wakeLockRef.current.release();}catch{}
      wakeLockRef.current=null;
    };
  },[printStation]);
  useEffect(()=>{if(refreshTick)loadAll();},[refreshTick]);// eslint-disable-line react-hooks/exhaustive-deps  (refresh button in the kiosk header)

  // QR-สั่งอาหาร tab removed — per-table QR is printed by tapping a table (one place only).
  const PTABS=[{id:"tables",l:"แผนผังโต๊ะ",icon:I.table}];  // "ออเดอร์วันนี้" replaced by the menu-management dropdown

  if(loading)return <Loading text="กำลังโหลดข้อมูล POS..."/>;

  return <div style={{margin:"-20px -24px",display:"flex",flexDirection:"column",height:"calc(100vh - 150px)"}}>
    {/* Shift indicator strip */}
    <div style={{padding:"6px 16px",background:`linear-gradient(135deg,${C.green},#059669)`,color:C.white,display:"flex",alignItems:"center",gap:14,fontSize:12,fontFamily:"'Sarabun',sans-serif",flexShrink:0}}>
      <span style={{fontSize:14}}>💵</span>
      <span style={{fontWeight:700}}>กะ #{shift.id}</span>
      <span style={{opacity:.85}}>เปิดเมื่อ {new Date(shift.opened_at).toLocaleTimeString("th-TH",{hour:'2-digit',minute:'2-digit'})}</span>
      <span style={{opacity:.85}}>· ทอนเริ่มต้น ฿{(+shift.opening_cash||0).toLocaleString()}</span>
      <span style={{opacity:.85,marginLeft:"auto"}}>{shift.username}</span>
    </div>
    <div style={{padding:"0 16px",background:C.white,borderBottom:`1px solid ${C.line}`,display:"flex",alignItems:"center",height:46,gap:2,flexShrink:0}}>
      {PTABS.map(t=>{const active=posTab===t.id;return <button key={t.id} onClick={()=>setPosTab(t.id)} style={{display:"flex",alignItems:"center",gap:6,padding:"0 12px",height:46,border:"none",background:"none",cursor:"pointer",fontSize:12,fontWeight:active?800:500,color:active?C.brand:C.ink3,fontFamily:"'Sarabun',sans-serif",borderBottom:active?`2.5px solid ${C.brand}`:"2.5px solid transparent",transition:"all .15s"}}><Ic d={t.icon} s={13} c={active?C.brand:C.ink4}/>{t.l}</button>;})}
      {canEdit&&<POSMenuTools currentBranch={currentBranch} variant="dropdown" onChanged={()=>{reloadMenus&&reloadMenus();reloadPosSettings&&reloadPosSettings();}}/>}
      <div style={{marginLeft:"auto",display:"flex",gap:6}}>
        <Btn v="ghost" onClick={()=>setShowOrders(true)} icon={I.order} s={{padding:"5px 10px",fontSize:12}}>📊 รายงาน</Btn>
        <Btn v="success" onClick={onCashDrawer} icon={I.cash} s={{padding:"5px 12px",fontSize:12}}>💰 เงินในลิ้นชัก</Btn>
        {canEdit&&!saleOnly&&<Btn v="danger" onClick={onCloseShift} s={{padding:"5px 10px",fontSize:12}}>🔚 ปิดกะ</Btn>}
        {!saleOnly&&<Btn v="ghost" onClick={loadAll} icon={I.refresh} s={{padding:"5px 10px",fontSize:12}}>รีเฟรช</Btn>}
        <Btn v="ghost" onClick={()=>setShowPrinters(true)} icon={I.print} s={{padding:"5px 10px",fontSize:12}}>🖨 เครื่องพิมพ์</Btn>
        <Btn v="ghost" onClick={()=>setShowReceipt(true)} icon={I.bill} s={{padding:"5px 10px",fontSize:12}}>🧾 จัดการใบเสร็จ</Btn>
        {!saleOnly&&<Btn v="ghost" onClick={onExitMode} s={{padding:"5px 10px",fontSize:12}}>← โหมด</Btn>}
      </div>
    </div>
    <div style={{flex:1,overflow:"hidden",display:"flex",flexDirection:"column"}}>
      {posTab==="tables"&&<POSTableMap tables={tables} activeOrders={activeOrders} zones={zones} onSelectTable={(t,o)=>{if(!canEdit)return;setSelTable(t);setSelOrder(o||null);}} onAddZone={canEdit?async(name)=>{if(zones.some(z=>String(z.name).toLowerCase()===name.toLowerCase())){alert("มีโซนนี้อยู่แล้ว");return;}const sortMax=zones.reduce((m,z)=>Math.max(m,z.sort_order||0),0);await api.addZone({branch_id:currentBranch.id,name,color:ZONE_COLORS[zones.length%ZONE_COLORS.length],sort_order:sortMax+1});if(reloadZones)await reloadZones();}:undefined} onAddTable={canEdit?handleAddTable:undefined} onUpdateTable={canEdit?handleUpdateTable:undefined} onDeleteTable={canEdit?handleDeleteTable:undefined} onMoveTable={canEdit?handleMoveTable:undefined} onRenameZone={canEdit?handleRenameZone:undefined} onDeleteZone={canEdit?handleDeleteZone:undefined}/>}
      {showOrders&&<SalesReportModal currentBranch={currentBranch} onClose={()=>setShowOrders(false)}/>}
    </div>
    {selTable&&<Modal title={`โต๊ะ ${selTable.table_number}${selTable.label?` — ${selTable.label}`:""}`} onClose={()=>{setSelTable(null);setSelOrder(null);loadAll();}} wide>
      <div style={{display:"flex",justifyContent:"flex-end",marginBottom:10}}>
        <button onClick={()=>printTableQR(selTable,currentBranch,printers)} style={{display:"flex",alignItems:"center",gap:6,padding:"7px 14px",borderRadius:9,border:`1px solid ${C.line}`,background:C.white,cursor:"pointer",fontSize:12,fontFamily:"'Sarabun',sans-serif",fontWeight:600,color:C.ink2}}>🖨 พิมพ์ QR โต๊ะนี้</button>
      </div>
      <POSOrderPanel table={selTable} existingOrder={selOrder} menus={menus} reloadMenus={reloadMenus} branch={currentBranch} currentUser={currentUser} shift={shift} posSettings={posSettings} promotions={promotions} onClose={()=>{setSelTable(null);setSelOrder(null);}} onDone={loadAll} printers={printers}/>
    </Modal>}
    {showPrinters&&<PrinterStatusModal currentBranch={currentBranch} menus={menus} reloadMenus={reloadMenus} onClose={()=>setShowPrinters(false)} printStation={printStation} onTogglePrintStation={(v)=>setPS(v)}/>}
    {showReceipt&&<ReceiptSettingsModal currentBranch={currentBranch} onClose={()=>setShowReceipt(false)} onSaved={reloadPosSettings}/>}
  </div>;
}

// ══════════════════════════════════════════════════════
// ── PRINTER STATUS + ADD-BY-IP (from the sale screen) ──
// ══════════════════════════════════════════════════════
// Lightweight printer panel for cashiers: see each printer online/offline and
// add a network printer by typing its IP. (Full routing/categories stay in the
// manager back office.)
function PrinterStatusModal({currentBranch,menus=[],reloadMenus,onClose,printStation=false,onTogglePrintStation}){
  const lbl={display:"block",fontSize:12,fontWeight:600,color:C.ink2,marginBottom:5,fontFamily:"'Sarabun',sans-serif"};
  const[printers,setPrinters]=useState([]);
  const[loading,setLoading]=useState(true);
  const[status,setStatus]=useState({});   // id -> 'testing'|'online'|'offline'|'bt'
  const[form,setForm]=useState({name:"",ip:"",port:9100});
  const[saving,setSaving]=useState(false);
  const[searched,setSearched]=useState(false);   // กด "ค้นหาเครื่องพิมพ์" แล้ว = แสดงทุกเครื่องในวง LAN (รวมที่เคยซ่อน/ลบ)
  const[searching,setSearching]=useState(false);
  const[rechecking,setRechecking]=useState(false);   // กำลังกด "เช็คสถานะใหม่" (รอ agent เช็คสด)
  const[settingsP,setSettingsP]=useState(null);      // เครื่องที่เปิดป๊อบอัพ "กำหนดการพิมพ์" อยู่ (null=ปิด)
  const[sName,setSName]=useState("");                // ชื่อที่กำลังแก้
  const[sCats,setSCats]=useState([]);                // หมวดที่เครื่องนี้รับ ([]=ยังไม่กำหนด/ไม่รับ · [ชื่อ]=เฉพาะหมวดนั้น) — ไม่มี catch-all แล้ว
  const[sOverride,setSOverride]=useState({});        // menu_id → printer_id (ปักหมุดเมนูเฉพาะให้ออกเครื่องนี้)
  const[sOpenCats,setSOpenCats]=useState(()=>new Set());  // หมวดที่กางดูรายเมนู
  const[sSaving,setSSaving]=useState(false);
  const[sRcpt,setSRcpt]=useState(false);            // เครื่องนี้เป็นเครื่องพิมพ์ใบเสร็จด้วยหรือไม่ (description.rcpt)
  const aliveRef=useRef(true);   // กันอัปเดต state หลังปิด modal (ระหว่างวนค้นหา 15 วินาที)
  useEffect(()=>()=>{aliveRef.current=false;},[]);
  const[station,setStation]=useState(printStation||isPrintStation());
  function toggleStation(){const v=!station;setStation(v);setPrintStation(v);onTogglePrintStation&&onTogglePrintStation(v);}
  async function load(){setLoading(true);try{const all=await api.getAllPrinters();if(aliveRef.current)setPrinters((all||[]).filter(p=>p.branch_id==null||+p.branch_id===+currentBranch.id));}catch(e){console.error("loadPrinters",e);}if(aliveRef.current)setLoading(false);}
  async function loadSilent(){try{const all=await api.getAllPrinters();if(aliveRef.current)setPrinters((all||[]).filter(p=>p.branch_id==null||+p.branch_id===+currentBranch.id));}catch(e){console.error("loadPrinters",e);}}
  async function findPrinters(){
    setSearched(true);setSearching(true);
    // สั่งให้ตัวพิมพ์ (agent) สแกนหาเครื่องใหม่ในวง LAN "ทันที" (ไม่รอรอบสแกนอัตโนมัติ 2 นาที)
    const at=Date.now();
    try{await Promise.all((printers||[]).map(p=>{let d={};try{d=JSON.parse(p.description||"{}");}catch{}return api.updatePrinter(p.id,{description:JSON.stringify({...d,scanReq:at})});}));}catch{}
    const beforeIds=new Set((printers||[]).map(p=>p.id));
    let foundNew=false;
    // ดึงซ้ำทุก 2 วิ จนกว่าจะเจอเครื่องใหม่ หรือครบ ~28 วิ (agent สแกน ~10 วิ) — หยุดทันทีถ้าปิด modal
    for(let i=0;i<14&&aliveRef.current;i++){
      await new Promise(r=>setTimeout(r,2000));
      let all=null;try{all=await api.getAllPrinters();}catch{}
      if(all&&aliveRef.current){
        const mine=all.filter(p=>p.branch_id==null||+p.branch_id===+currentBranch.id);
        setPrinters(mine);
        if(mine.some(p=>!beforeIds.has(p.id))){foundNew=true;break;}
      }
    }
    if(aliveRef.current){setSearching(false);if(foundNew)posToast("✅ พบเครื่องพิมพ์ใหม่ในเครือข่าย!","ok");}
  }
  useEffect(()=>{load();},[]);
  // เช็คสถานะเมื่อรายการโหลด/รีเฟรช (https = อ่าน description.on ที่ agent รายงาน · LAN = probe ตรง)
  useEffect(()=>{if(!loading)printers.forEach(p=>checkStatus(p));// eslint-disable-next-line
  },[loading,printers]);
  // รีเฟรชอัตโนมัติทุก 15 วิ ขณะเปิดหน้านี้ → จุดเขียว/แดงอัปเดตสดตามที่ตัวพิมพ์รายงาน
  useEffect(()=>{const t=setInterval(()=>{if(aliveRef.current&&!document.hidden)loadSilent();},30000);return ()=>clearInterval(t);// eslint-disable-next-line
  },[]);
  // เปิดผ่าน https (Vercel/iPad) → เบราว์เซอร์ต่อ http://printer:9100 ไม่ได้ (mixed content) → เช็ค/ทดสอบฝั่งเบราว์เซอร์ใช้ไม่ได้ จึงให้ตัวพิมพ์ (agent) จัดการแทน
  const isHttps=typeof location!=="undefined"&&location.protocol==="https:";
  async function checkStatus(p){
    const conn=getPConn(p);
    if(conn.type==="bluetooth"){setStatus(s=>({...s,[p.id]:"bt"}));return;}
    if(isHttps){   // iPad/https เช็คตรงไม่ได้ — อ่านสถานะที่ตัวพิมพ์ (agent) ping แล้วรายงานไว้ใน description.on (อัปเดตทุก 30 วิ)
      let d={};try{d=JSON.parse(p.description||"{}");}catch{}
      setStatus(s=>({...s,[p.id]:d.on===1?"online":"offline"}));return;
    }
    setStatus(s=>({...s,[p.id]:"testing"}));
    const ctrl=new AbortController();const tid=setTimeout(()=>ctrl.abort(),6000);
    try{
      await fetch(`http://${p.ip}:${p.port||9100}/`,{method:"POST",mode:"no-cors",cache:"no-store",headers:{"Content-Type":"application/octet-stream"},body:new Uint8Array([0x1B,0x40]),signal:ctrl.signal});
      clearTimeout(tid);setStatus(s=>({...s,[p.id]:"online"}));   // got a real (opaque) reply = definitely reachable (rare for raw printers)
    }catch(e){
      clearTimeout(tid);
      // no-cors hides the result. A network error = definitely can't reach it → OFFLINE (printer off /
      // wrong IP / คนละวง WiFi). A TIMEOUT is genuinely ambiguous — a silent reachable printer AND a
      // silently-dropped unreachable host both hang — so we say "ไม่ยืนยัน", NOT a fake "online".
      setStatus(s=>({...s,[p.id]:e.name==="AbortError"?"unknown":"offline"}));
    }
  }
  // ปุ่ม "เช็คสถานะใหม่": https → สั่งตัวพิมพ์ (agent) เช็คเดี๋ยวนี้ (เขียน pingReq) แล้วรอผล ~ไม่กี่วิ · LAN → probe ตรงเหมือนเดิม
  async function recheckStatus(){
    if(rechecking)return;
    if(!isHttps){printers.forEach(p=>checkStatus(p));return;}
    setRechecking(true);
    const before={};(printers||[]).forEach(p=>{try{before[p.id]=JSON.parse(p.description||"{}").onAt||0;}catch{}});   // จำเวลาเดิม เพื่อรู้ว่า agent อัปเดตแล้ว
    const at=Date.now();
    try{
      await Promise.all((printers||[]).filter(p=>p.ip&&getPConn(p).type!=="bluetooth").map(p=>{let d={};try{d=JSON.parse(p.description||"{}");}catch{}return api.updatePrinter(p.id,{description:JSON.stringify({...d,pingReq:at})});}));
    }catch(e){}
    // หยุดหมุน "ทันที" ที่ตัวพิมพ์ตอบกลับ (onAt ใหม่กว่าเดิม) — ไม่รอครบเวลา · เช็คทุก 0.8 วิ สูงสุด ~10 วิ
    for(let i=0;i<12&&aliveRef.current;i++){
      await new Promise(r=>setTimeout(r,800));
      let mine=null;try{const all=await api.getAllPrinters();mine=(all||[]).filter(p=>p.branch_id==null||+p.branch_id===+currentBranch.id);}catch{}
      if(mine&&aliveRef.current){
        setPrinters(mine);   // useEffect[printers] จะ re-derive จุดเขียว/แดง
        if(mine.some(p=>{try{return (JSON.parse(p.description||"{}").onAt||0)>(before[p.id]||0);}catch{return false;}}))break;
      }
    }
    if(aliveRef.current)setRechecking(false);
  }
  async function testPrint(p){
    const conn=getPConn(p);
    if(conn.type==="bluetooth"){
      setStatus(s=>({...s,[p.id]:"testing"}));
      try{await btPrint(buildTestPageESC(p.name),conn.btName);setStatus(s=>({...s,[p.id]:"online"}));posToast("🧾 ส่งหน้าทดสอบทางบลูทูธแล้ว — ดูว่ามีกระดาษออกไหม","ok");}
      catch(e){setStatus(s=>({...s,[p.id]:"offline"}));alert("❌ พิมพ์ทดสอบไม่สำเร็จ: "+(e.message||""));}
      return;
    }
    if(isHttps){   // iPad/https สั่งพิมพ์ตรงไม่ได้ → เรนเดอร์ไทยเป็นรูปภาพ (คมชัด) แล้วส่งให้ "ตัวพิมพ์ (agent)" พิมพ์ (~5 วิ) · ไม่แตะจุดสถานะ (ปล่อยให้เป็นเขียว/แดงตามที่ agent ping)
      try{
        const b64=await escposSlipRaster([
          {t:"ทดสอบพิมพ์ (รูปภาพ)",size:30,bold:true,align:"center"},
          {t:"ภาษาไทยคมชัด",size:24,align:"center"},
          {rule:true},
          {t:"ชาบูจัมโบ้ กุ้งเผา ผัดไทย",size:32,bold:true,align:"left"},
          {t:"ในวันเบาๆ + เพิ่มมาก",size:28,align:"left"},
          {rule:true},
          {t:fmtDT(),size:20,align:"center"},
        ],576);
        await api.updatePrinter(p.id,{description:cmdDesc(p,"pj",{at:Date.now(),b64})});
        posToast("🧾 ส่งทดสอบพิมพ์ (แบบรูปภาพ ไทยคมชัด) ไปตัวพิมพ์แล้ว — กระดาษจะออกใน ~5 วินาที","ok");
      }catch(e){alert("ส่งคำสั่งทดสอบไม่สำเร็จ: "+(e&&e.message||e));}
      return;
    }
    setStatus(s=>({...s,[p.id]:"testing"}));
    try{
      await sendESCPOSToIP(p.ip,p.port,buildTestPageESC(p.name));
      setStatus(s=>({...s,[p.id]:"online"}));
      posToast("🧾 ส่งหน้าทดสอบไป “"+(p.name||"เครื่องพิมพ์")+"” แล้ว — ถ้ามีกระดาษออก = เชื่อมต่อได้จริง","ok");
    }catch(e){
      setStatus(s=>({...s,[p.id]:"offline"}));
      alert("❌ “"+(p.name||"เครื่องพิมพ์")+"” พิมพ์ทดสอบไม่สำเร็จ\n"+(e.message||"")+"\n\nตรวจสอบ: ไฟเครื่องพิมพ์ · สายแลน · เลข IP · อยู่ WiFi วงเดียวกับเครื่องนี้ไหม");
    }
  }
  async function add(){
    const name=(form.name||"").trim();const ip=(form.ip||"").trim();
    if(!name)return alert("ใส่ชื่อเครื่องพิมพ์");
    if(!/^\d{1,3}(\.\d{1,3}){3}$/.test(ip))return alert("ใส่เลข IP ให้ถูกต้อง เช่น 192.168.1.50");
    setSaving(true);
    try{
      await api.addPrinter({name,ip,port:+form.port||9100,type:"kitchen",branch_id:currentBranch.id,active:true,description:""});
      setForm({name:"",ip:"",port:9100});
      await load();
    }catch(e){alert("เพิ่มไม่สำเร็จ: "+(e&&e.message||e));}
    setSaving(false);
  }
  // จุดสถานะ 2 สีเท่านั้น: เขียว = ออนไลน์ · แดง = ออฟไลน์ (ทุกสถานะที่ไม่ใช่ออนไลน์)
  const stView=(st)=>{
    if(st==="online")return{c:C.green,bg:C.greenLight,t:"🟢 ออนไลน์"};
    return{c:C.red,bg:C.redLight,t:"🔴 ออฟไลน์"};
  };
  const activePrinters=printers.filter(p=>p.active!==false);
  const isIgnored=(p)=>{try{return JSON.parse(p.description||"{}").ig===1;}catch{return false;}};
  const notAdded=printers.filter(p=>p.active===false);
  const discovered=searched?notAdded:notAdded.filter(p=>!isIgnored(p));   // กดค้นหาแล้วให้เห็นเครื่องที่เคยซ่อน/ลบด้วย
  // เพิ่มใช้งานเครื่องที่ค้นเจอ — รีเซ็ตชื่อเป็นค่าเริ่มต้น (เลข IP) เสมอ เผื่อเป็นเครื่องที่เคยลบแล้วชื่อเดิมค้างอยู่ · ผู้ใช้ค่อยตั้งชื่อใหม่ตามตำแหน่งจริง
  async function addDiscovered(p){try{await api.updatePrinter(p.id,{name:`เครื่องพิมพ์ ${p.ip||""}`.trim(),active:true,description:""});await load();posToast("✅ เพิ่มเครื่องพิมพ์เข้าระบบแล้ว — ตั้งชื่อตามจุดที่วางได้ที่ \"กำหนดการพิมพ์\"");}catch(e){alert("เพิ่มไม่สำเร็จ: "+(e&&e.message||e));}}
  async function ignoreDiscovered(p){try{await api.updatePrinter(p.id,{description:JSON.stringify({d:1,ig:1})});await load();}catch(e){alert("ไม่สำเร็จ: "+(e&&e.message||e));}}
  // แสดงเฉพาะหมวดที่ "สาขานี้สร้างไว้เอง" (local_categories[สาขา]) เท่านั้น — ไม่ดึงหมวดรวม (global)
  // เมนูที่ยังไม่ได้ตั้งหมวดของสาขานี้จะไม่ขึ้นในตัวเลือก และจะพิมพ์ออกเครื่อง "พิมพ์ทุกหมวด" (catch-all)
  const effCat=(m)=>{const lc=m.local_categories||{};const bid=currentBranch&&currentBranch.id;const v=lc[bid];return (v&&String(v).trim())?String(v).trim():null;};
  const branchCategories=useMemo(()=>{const s=new Set();(menus||[]).forEach(m=>{const e=effCat(m);if(e)s.add(e);});return [...s].sort();},[menus,currentBranch]);
  const menusInCat=(c)=>(menus||[]).filter(m=>effCat(m)===c);
  function openSettings(p){
    setSettingsP(p);setSName(p.name||"");setSCats(Array.isArray(p.categories)?[...p.categories]:[]);   // ไม่มี catch-all แล้ว — null/undefined → [] (ต้องเลือกหมวดเอง)
    let dd={};try{dd=JSON.parse(p.description||"{}");}catch{}setSRcpt(dd.rcpt===1);
    const ov={};(menus||[]).forEach(m=>{if(m.printer_id)ov[m.id]=+m.printer_id;});setSOverride(ov);setSOpenCats(new Set());
  }
  function toggleSOpenCat(c){setSOpenCats(prev=>{const n=new Set(prev);if(n.has(c))n.delete(c);else n.add(c);return n;});}
  async function saveSettings(){
    const p=settingsP;if(!p)return;
    const name=(sName||"").trim();if(!name)return alert("ใส่ชื่อเครื่องพิมพ์");
    setSSaving(true);
    try{
      // อ่าน description ล่าสุดก่อนรวม flag ใบเสร็จ (กันทับคำสั่งพิมพ์ tp/rp/qr/pj ที่อาจถูกเขียนมาระหว่างเปิดหน้าตั้งค่า)
      let fresh=p;try{const all=await api.getAllPrinters();const f=(all||[]).find(x=>+x.id===+p.id);if(f)fresh=f;}catch{}
      let dd={};try{dd=JSON.parse(fresh.description||"{}");}catch{}
      if(sRcpt)dd.rcpt=1;else delete dd.rcpt;
      await api.updatePrinter(p.id,{name,categories:sCats,description:JSON.stringify(dd)});
      const ups=[];(menus||[]).forEach(m=>{const nw=sOverride[m.id]||null;const ol=m.printer_id||null;if(String(nw)!==String(ol))ups.push(api.updateMenu(m.id,{printer_id:nw}));});
      if(ups.length)await Promise.all(ups);
      await load();if(reloadMenus)await reloadMenus();
      if(aliveRef.current){setSettingsP(null);posToast("บันทึกการกำหนดการพิมพ์แล้ว");}
    }catch(e){alert("บันทึกไม่สำเร็จ: "+(e&&e.message||e));}
    if(aliveRef.current)setSSaving(false);
  }
  return <Modal title="🖨 เครื่องพิมพ์ & สถานะการเชื่อมต่อ" onClose={onClose} wide>
    {loading?<Loading text="โหลดเครื่องพิมพ์..."/>:<>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10,flexWrap:"wrap",gap:8}}>
        <div style={{fontFamily:"'Sarabun',sans-serif",fontSize:13,color:C.ink3}}>เครื่องพิมพ์ของสาขา <b style={{color:C.ink}}>{currentBranch.name}</b> ({activePrinters.length})</div>
        <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
          <Btn v="info" onClick={findPrinters} disabled={searching} icon={I.search} s={{padding:"6px 12px",fontSize:12}}>{searching?"⟳ กำลังค้นหา...":"ค้นหาเครื่องพิมพ์"}</Btn>
          <Btn v="ghost" onClick={recheckStatus} disabled={rechecking} icon={I.refresh} s={{padding:"6px 12px",fontSize:12}}>{rechecking?"⟳ กำลังเช็ค...":"เช็คสถานะใหม่"}</Btn>
        </div>
      </div>
      {activePrinters.length===0?<div style={{textAlign:"center",padding:"28px 16px",color:C.ink4,fontFamily:"'Sarabun',sans-serif",background:C.bg,borderRadius:12,marginBottom:14}}><Ic d={I.print} s={40} c={C.line}/><p style={{marginTop:8,fontSize:13}}>ยังไม่มีเครื่องพิมพ์ที่ใช้งาน — เพิ่มจาก "พบในเครือข่าย" ด้านล่าง หรือใส่ IP เอง</p></div>
      :<div style={{display:"flex",flexDirection:"column",gap:8,marginBottom:16}}>
        {activePrinters.map(p=>{const conn=getPConn(p);const sv=stView(status[p.id]);const catLabel=(p.categories===undefined||p.categories===null)?"ทุกหมวด":(p.categories.length?p.categories.join(", "):"— ยังไม่กำหนด —");const ovCount=(menus||[]).filter(m=>+m.printer_id===+p.id).length;return <div key={p.id} style={{display:"flex",alignItems:"center",gap:12,padding:"11px 14px",border:`1px solid ${C.line}`,borderRadius:12,background:C.white,flexWrap:"wrap"}}>
          <span style={{width:11,height:11,borderRadius:"50%",background:sv.c,flexShrink:0,boxShadow:status[p.id]==="online"?`0 0 0 3px ${C.green}33`:"none"}}/>
          <div style={{minWidth:0,flex:1}}>
            <div style={{display:"flex",alignItems:"center",gap:7,flexWrap:"wrap"}}><span style={{fontFamily:"'Sarabun',sans-serif",fontSize:14,fontWeight:800,color:C.ink}}>{p.name}</span>{isReceiptPrinter(p)&&<span style={{fontSize:10,fontWeight:800,color:C.green,background:C.greenLight,border:`1px solid ${C.green}55`,borderRadius:20,padding:"1px 8px",fontFamily:"'Sarabun',sans-serif"}}>🧾 ใบเสร็จ</span>}</div>
            <div style={{fontFamily:"'Sarabun',sans-serif",fontSize:11.5,color:C.ink4}}>{conn.type==="bluetooth"?`บลูทูธ${conn.btName?" · "+conn.btName:""}`:`${p.ip||"-"}:${p.port||9100}`} · พิมพ์: {catLabel}{ovCount>0?` · +${ovCount} เมนู`:""}</div>
          </div>
          <span style={{fontSize:11.5,fontWeight:800,color:sv.c,background:sv.bg,border:`1px solid ${sv.c}44`,borderRadius:20,padding:"3px 12px",fontFamily:"'Sarabun',sans-serif",whiteSpace:"nowrap"}}>{sv.t}</span>
          <button onClick={()=>openSettings(p)} title="กำหนดหมวดหมู่/เมนู ที่พิมพ์ออกเครื่องนี้ + แก้ชื่อ" style={{background:C.blueLight,border:`1px solid ${C.blue}55`,borderRadius:8,padding:"6px 12px",cursor:"pointer",fontFamily:"'Sarabun',sans-serif",fontSize:12,fontWeight:700,color:C.blue,whiteSpace:"nowrap"}}>🖨️ กำหนดการพิมพ์</button>
          <button onClick={()=>testPrint(p)} title="พิมพ์หน้าทดสอบจริง — ยืนยันชัวร์ที่สุด" style={{background:C.brand,border:"none",borderRadius:8,padding:"6px 12px",cursor:"pointer",fontFamily:"'Sarabun',sans-serif",fontSize:12,fontWeight:800,color:C.white,whiteSpace:"nowrap"}}>🧾 ทดสอบพิมพ์</button>
          <button onClick={async()=>{if(await confirmDlg({title:`🗑 นำเครื่องพิมพ์ "${p.name}" ออก?`,message:`นำเครื่องพิมพ์ "${p.name}" (${p.ip||"-"}) ออกจากการใช้งาน?\n\n⚠️ เมนูที่ส่งมาเครื่องนี้จะไม่ถูกพิมพ์จนกว่าจะเพิ่มกลับ\n\n💡 นำกลับมาได้ทุกเมื่อด้วยปุ่ม "ค้นหาเครื่องพิมพ์"`,confirmLabel:"นำออก",cancelLabel:"ยกเลิก",danger:true})){try{await api.updatePrinter(p.id,{active:false,description:JSON.stringify({d:1,ig:1})});await load();posToast("นำเครื่องพิมพ์ออกแล้ว — กด \"ค้นหาเครื่องพิมพ์\" เพื่อนำกลับ");}catch(e){alert("ไม่สำเร็จ: "+(e&&e.message||e));}}}} title="นำเครื่องพิมพ์ออก (นำกลับได้ด้วยปุ่มค้นหา)" style={{background:C.redLight,border:`1px solid #FCA5A5`,borderRadius:8,padding:"6px 10px",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}><Ic d={I.trash} s={14} c={C.red}/></button>
        </div>;})}
      </div>}
      {settingsP&&<Modal title={`🖨️ กำหนดการพิมพ์ — ${settingsP.name}`} onClose={()=>setSettingsP(null)} extraWide>
        <label style={lbl}>ชื่อเครื่องพิมพ์ (แก้ไขได้)</label>
        <input value={sName} onChange={e=>setSName(e.target.value)} placeholder="เช่น ครัวร้อน · ครัวเย็น · แคชเชียร์" style={iS}/>
        <label style={{display:"flex",alignItems:"center",gap:11,margin:"13px 0 4px",padding:"11px 14px",borderRadius:10,border:`1.5px solid ${sRcpt?C.green:C.line}`,background:sRcpt?C.greenLight:C.white,cursor:"pointer"}}>
          <input type="checkbox" checked={sRcpt} onChange={e=>setSRcpt(e.target.checked)} style={{accentColor:C.green,width:19,height:19,cursor:"pointer",flexShrink:0}}/>
          <div style={{flex:1,minWidth:0}}>
            <div style={{fontSize:13.5,fontWeight:800,color:sRcpt?C.green:C.ink2,fontFamily:"'Sarabun',sans-serif"}}>🧾 ใช้เป็นเครื่องพิมพ์ใบเสร็จ</div>
            <div style={{fontSize:11,color:C.ink4,fontFamily:"'Sarabun',sans-serif",lineHeight:1.5}}>เช็คบิล/พิมพ์ใบเสร็จซ้ำ/แยกบิล จะพิมพ์ออกเครื่องนี้ · ติ๊กได้หลายเครื่อง — ใบเสร็จจะออกทุกเครื่องที่เลือก</div>
          </div>
        </label>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",margin:"15px 0 8px",flexWrap:"wrap",gap:8}}>
          <div style={{fontSize:13,fontWeight:800,color:C.ink2,fontFamily:"'Sarabun',sans-serif"}}>📂 หมวดหมู่ / เมนู ที่พิมพ์ออกเครื่องนี้</div>
          <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
            <button onClick={()=>setSCats([...branchCategories])} style={{padding:"4px 10px",borderRadius:7,border:`1px solid ${C.line}`,background:C.white,color:C.ink3,cursor:"pointer",fontSize:11,fontWeight:700,fontFamily:"'Sarabun',sans-serif"}}>เลือกทุกหมวด</button>
            <button onClick={()=>setSCats([])} style={{padding:"4px 10px",borderRadius:7,border:`1px solid ${C.line}`,background:C.white,color:C.ink3,cursor:"pointer",fontSize:11,fontWeight:700,fontFamily:"'Sarabun',sans-serif"}}>ล้าง</button>
          </div>
        </div>
        {branchCategories.length===0
            ?<div style={{padding:24,textAlign:"center",color:C.ink4,fontSize:13,fontFamily:"'Sarabun',sans-serif",lineHeight:1.6}}>ยังไม่มีหมวดหมู่ในสาขานี้ — ไปสร้างหมวดหมู่ที่หน้า "เมนู" ก่อน แล้วค่อยกลับมาเลือก</div>
            :<>
              <div style={{display:"flex",flexDirection:"column",gap:8,maxHeight:"50vh",overflowY:"auto",paddingRight:2}}>
                {branchCategories.map(c=>{const has=sCats.includes(c);const catMenus=menusInCat(c);const isOpen=sOpenCats.has(c);const pinHere=catMenus.filter(m=>{const cur=sOverride[m.id];return cur!=null&&+cur===+settingsP.id;}).length;
                  // ติ๊กครบทุกเมนู → หัวหมวดติ๊กให้อัตโนมัติ (รู้ว่าเลือกครบทั้งหมวด) · ติ๊กบางส่วน → ขีดครึ่ง (–) · ติ๊กหัวหมวด=เลือกทั้งหมวด · ปลด=ล้างทั้งหมวด
                  const allHere=catMenus.length>0&&pinHere===catMenus.length;const checked=has||allHere;const indet=!checked&&pinHere>0;
                  const toggleCatMaster=()=>{if(checked){setSCats(prev=>(prev||[]).filter(x=>x!==c));setSOverride(prev=>{const n={...prev};catMenus.forEach(m=>{if(n[m.id]!=null&&+n[m.id]===+settingsP.id)n[m.id]=null;});return n;});}else{setSCats(prev=>{const cur=prev===null?[]:prev;return cur.includes(c)?cur:[...cur,c];});}};
                  return <div key={c} style={{border:`1.5px solid ${checked?C.blue:(indet?`${C.blue}66`:C.line)}`,borderRadius:10,overflow:"hidden",background:checked?C.blueLight:C.white,flexShrink:0}}>
                  <div style={{display:"flex",alignItems:"center",gap:10,padding:"10px 12px"}}>
                    <input type="checkbox" checked={checked} ref={el=>{if(el)el.indeterminate=indet;}} onChange={toggleCatMaster} style={{accentColor:C.blue,width:18,height:18,cursor:"pointer",flexShrink:0}}/>
                    <div style={{flex:1,minWidth:0,cursor:"pointer"}} onClick={()=>toggleSOpenCat(c)}>
                      <div style={{fontSize:14,fontFamily:"'Sarabun',sans-serif",fontWeight:checked?800:600,color:checked?C.blue:C.ink2,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{c}</div>
                      <div style={{fontSize:10.5,color:C.ink4,fontFamily:"'Sarabun',sans-serif"}}>{catMenus.length} เมนู{allHere?" · ✓ เลือกครบทั้งหมวด":pinHere>0?` · 📌 เลือกเฉพาะ ${pinHere}`:""}</div>
                    </div>
                    <button onClick={()=>toggleSOpenCat(c)} style={{display:"flex",alignItems:"center",gap:5,background:isOpen?C.blue:C.white,color:isOpen?C.white:C.ink3,border:`1px solid ${isOpen?C.blue:C.line}`,borderRadius:8,padding:"5px 10px",cursor:"pointer",fontSize:11,fontWeight:700,fontFamily:"'Sarabun',sans-serif",whiteSpace:"nowrap",flexShrink:0}}><span style={{fontSize:9}}>{isOpen?"▼":"▶"}</span> เลือกเมนู</button>
                  </div>
                  {isOpen&&<div style={{borderTop:`1px dashed ${C.line}`,padding:"10px 12px",background:C.white}}>
                    {catMenus.length===0
                      ?<div style={{fontSize:11,color:C.ink4,fontFamily:"'Sarabun',sans-serif",textAlign:"center",padding:8}}>ไม่มีเมนูในหมวดนี้</div>
                      :<div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(min(220px,100%),1fr))",gap:6}}>
                        {catMenus.map(m=>{const cur=sOverride[m.id];const here=cur!=null&&+cur===+settingsP.id;const other=cur!=null&&+cur!==+settingsP.id;const otherName=other?(printers.find(pr=>+pr.id===+cur)?.name||"เครื่องอื่น"):"";return <label key={m.id} style={{display:"flex",alignItems:"center",gap:8,padding:"7px 10px",borderRadius:8,cursor:"pointer",background:here?C.blueLight:C.bg,border:`1px solid ${here?C.blue:C.line}`}}>
                          <input type="checkbox" checked={here} onChange={()=>setSOverride(prev=>({...prev,[m.id]:here?null:settingsP.id}))} style={{accentColor:C.blue,width:15,height:15,cursor:"pointer",flexShrink:0}}/>
                          <div style={{flex:1,minWidth:0}}>
                            <div style={{fontSize:12.5,fontFamily:"'Sarabun',sans-serif",fontWeight:here?800:600,color:here?C.blue:C.ink2,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{m.name}</div>
                            {other&&<div style={{fontSize:9.5,color:"#B45309",fontFamily:"'Sarabun',sans-serif",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>📌 เลือกไว้ที่ {otherName}</div>}
                          </div>
                        </label>;})}
                      </div>}
                  </div>}
                </div>;})}
              </div>
            </>}
        <div style={{display:"flex",justifyContent:"flex-end",gap:8,paddingTop:14,borderTop:`1px solid ${C.line}`,marginTop:14}}>
          <Btn v="ghost" onClick={()=>setSettingsP(null)}>ยกเลิก</Btn>
          <Btn v="success" onClick={saveSettings} loading={sSaving} icon={I.check}>บันทึก</Btn>
        </div>
      </Modal>}
      {(discovered.length>0||searched)&&<div style={{background:"#EFF6FF",border:`1px solid ${C.blue}44`,borderRadius:12,padding:"12px 14px",marginBottom:14}}>
        <div style={{fontSize:13,fontWeight:800,color:C.blue,fontFamily:"'Sarabun',sans-serif",marginBottom:searched?4:8}}>{searched?`🔍 ผลการค้นหาในเครือข่าย (${discovered.length})`:`🔍 พบในเครือข่าย (${discovered.length}) — แตะ "เพิ่มใช้งาน" เฉพาะเครื่องที่ต้องการ`}</div>
        {searched&&<div style={{fontSize:11,color:C.ink3,fontFamily:"'Sarabun',sans-serif",marginBottom:8,lineHeight:1.6}}>แสดงทุกเครื่องที่พบในวง LAN รวมเครื่องที่<b>เคยซ่อน/ลบ</b>ไปแล้ว · เครื่องที่ <b>เพิ่มในระบบแล้ว</b> อยู่ด้านบน (กดเพิ่มซ้ำไม่ได้) · เครื่องที่ปิดอยู่/ไม่ได้ต่อสายจะไม่แสดง</div>}
        {discovered.length===0?<div style={{fontSize:12.5,color:C.ink4,fontFamily:"'Sarabun',sans-serif",textAlign:"center",padding:"12px 6px",lineHeight:1.7,whiteSpace:"pre-line"}}>{searching?"⟳ กำลังค้นหาเครื่องพิมพ์ในวง LAN...":"ไม่พบเครื่องพิมพ์อื่นในเครือข่าย\n(เครื่องที่เพิ่มแล้วอยู่ด้านบน · เครื่องที่ปิดอยู่/ไม่ได้ต่อสายจะไม่แสดง)\n\nเพิ่งเสียบเครื่องใหม่? ตัวพิมพ์สแกนเองทุก ~2 นาที — รอสักครู่แล้วกด \"ค้นหาเครื่องพิมพ์\" อีกครั้ง"}</div>
        :<div style={{display:"flex",flexDirection:"column",gap:8}}>
          {discovered.map(p=>{const ig=isIgnored(p);return <div key={p.id} style={{display:"flex",alignItems:"center",gap:10,padding:"10px 12px",border:`1px solid ${C.blue}33`,borderRadius:10,background:C.white,flexWrap:"wrap"}}>
            <div style={{minWidth:0,flex:1}}>
              <div style={{fontFamily:"'Sarabun',sans-serif",fontSize:13.5,fontWeight:700,color:C.ink}}>{p.ip}:{p.port||9100}{ig&&<span style={{marginLeft:8,fontSize:10.5,fontWeight:700,color:C.ink4,background:C.bg,border:`1px solid ${C.line}`,borderRadius:20,padding:"1px 8px",whiteSpace:"nowrap"}}>เคยซ่อนไว้</span>}</div>
              <div style={{fontFamily:"'Sarabun',sans-serif",fontSize:11,color:C.ink4}}>พบเครื่องพิมพ์ในวง LAN — ยังไม่ได้ใช้งาน</div>
            </div>
            <button onClick={()=>addDiscovered(p)} style={{background:`linear-gradient(135deg,${C.green},#059669)`,border:"none",borderRadius:8,padding:"7px 14px",cursor:"pointer",fontFamily:"'Sarabun',sans-serif",fontSize:12.5,fontWeight:800,color:C.white,whiteSpace:"nowrap"}}>➕ เพิ่มใช้งาน</button>
            {!ig&&<button onClick={()=>ignoreDiscovered(p)} title="ไม่ใช้เครื่องนี้ (ซ่อนออกจากรายการ)" style={{background:C.bg,border:`1px solid ${C.line}`,borderRadius:8,padding:"7px 10px",cursor:"pointer",fontFamily:"'Sarabun',sans-serif",fontSize:12,fontWeight:700,color:C.ink3,whiteSpace:"nowrap"}}>🙈 ซ่อน</button>}
          </div>;})}
        </div>}
      </div>}
      <div style={{background:C.bg,border:`1px dashed ${C.line}`,borderRadius:12,padding:"14px 16px"}}>
        <div style={{fontFamily:"'Sarabun',sans-serif",fontSize:13,fontWeight:800,color:C.ink,marginBottom:10}}>➕ เพิ่มเครื่องพิมพ์ (เครือข่าย / IP) ด้วยตัวเอง</div>
        <div style={{display:"flex",gap:10,flexWrap:"wrap",alignItems:"flex-end"}}>
          <div style={{flex:"2 1 160px"}}><label style={lbl}>ชื่อเครื่องพิมพ์</label><input value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))} placeholder="เช่น ครัวร้อน" style={iS}/></div>
          <div style={{flex:"2 1 150px"}}><label style={lbl}>เลข IP</label><input value={form.ip} onChange={e=>setForm(f=>({...f,ip:e.target.value.replace(/[^\d.]/g,"")}))} inputMode="decimal" placeholder="192.168.1.50" style={iS}/></div>
          <div style={{flex:"1 1 90px"}}><label style={lbl}>พอร์ต</label><input value={form.port} onChange={e=>setForm(f=>({...f,port:e.target.value.replace(/\D/g,"")}))} inputMode="numeric" placeholder="9100" style={iS}/></div>
          <Btn onClick={add} loading={saving} icon={I.plus}>เพิ่ม</Btn>
        </div>
        <div style={{fontFamily:"'Sarabun',sans-serif",fontSize:11,color:C.ink4,marginTop:8,lineHeight:1.6}}>💡 ใช้เครื่องพิมพ์ความร้อนที่ต่อ LAN/WiFi · พอร์ตมาตรฐานคือ 9100 · ตั้งหมวดหมู่/เลือกเมนูให้แต่ละเครื่องได้ที่ "จัดการหลังบ้าน → เครื่องพิมพ์"</div>
      </div>
    </>}
  </Modal>;
}

// ══════════════════════════════════════════════════════
// ── SALES REPORT (รายงานยอดขาย: เลือกวัน · ปิด/ยังไม่ปิดบิล · ดูแต่ละบิล) ─
// ══════════════════════════════════════════════════════
function BillDetailCard({order,onBack}){
  const o=order;
  const items=o.items||[];
  const stL={pending:"รอยืนยัน",confirmed:"กำลังทำ",bill_requested:"เรียกบิล",paid:"ชำระแล้ว",cancelled:"ยกเลิก"};
  const stC={pending:C.yellow,confirmed:C.green,bill_requested:C.brand,paid:C.green,cancelled:C.ink4};
  const m=(n)=>"฿"+(+n||0).toLocaleString(undefined,{maximumFractionDigits:0});
  const paid=o.status==="paid";
  const Row=({l,v,c,big,plus})=><div style={{display:"flex",justifyContent:"space-between",alignItems:"baseline",fontSize:big?17:13,fontFamily:"'Sarabun',sans-serif",marginBottom:big?0:6,fontWeight:big?900:500,color:c||C.ink2}}><span>{l}</span><span style={{fontWeight:big?900:700,color:big?C.ink:(c||C.ink)}}>{plus||""}{v}</span></div>;
  return <div>
    <button onClick={onBack} style={{display:"flex",alignItems:"center",gap:6,padding:"7px 14px",borderRadius:9,border:`1px solid ${C.line}`,background:C.white,cursor:"pointer",fontSize:12.5,fontWeight:700,color:C.ink2,fontFamily:"'Sarabun',sans-serif",marginBottom:14}}>← กลับไปรายการบิล</button>
    <div style={{maxWidth:460,margin:"0 auto",background:C.white,borderRadius:14,border:`1px solid ${C.line}`,overflow:"hidden",boxShadow:"0 2px 10px rgba(0,0,0,0.04)"}}>
      <div style={{padding:"14px 18px",background:C.bg,borderBottom:`1px solid ${C.line}`,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <div>
          <div style={{fontSize:20,fontWeight:900,color:C.ink,fontFamily:"'Sarabun',sans-serif"}}>โต๊ะ {o.table_number}</div>
          <div style={{fontSize:11.5,color:C.ink4,fontFamily:"'Sarabun',sans-serif",marginTop:3}}>บิล #{o.id} · {fmtDT(o.created_at)}</div>
        </div>
        <span style={{fontSize:12,fontWeight:800,color:stC[o.status]||C.ink3,background:`${stC[o.status]||C.ink3}22`,padding:"4px 12px",borderRadius:20,fontFamily:"'Sarabun',sans-serif"}}>{stL[o.status]||o.status}</span>
      </div>
      <div style={{padding:"14px 18px"}}>
        {items.length===0?<div style={{color:C.ink4,fontFamily:"'Sarabun',sans-serif",fontSize:13,textAlign:"center",padding:"10px 0"}}>ไม่มีรายการอาหาร</div>:items.map((i,idx)=>{
          const disc=+i.item_discount||0;
          return <div key={idx} style={{marginBottom:idx<items.length-1?11:0,paddingBottom:idx<items.length-1?11:0,borderBottom:idx<items.length-1?`1px dashed ${C.lineLight}`:"none"}}>
            <div style={{display:"flex",justifyContent:"space-between",fontSize:13.5,fontFamily:"'Sarabun',sans-serif",gap:10}}>
              <span style={{color:C.ink}}><span style={{color:C.brand,fontWeight:800}}>{i.qty}x</span> {i.name}</span>
              <span style={{color:C.ink,fontWeight:700,whiteSpace:"nowrap"}}>{m((+i.price||0)*(+i.qty||0)-disc)}</span>
            </div>
            {i.options&&i.options.length>0&&<div style={{fontSize:11.5,color:C.ink4,fontFamily:"'Sarabun',sans-serif",marginTop:3,paddingLeft:4}}>+ {optionsText(i.options)}</div>}
            {i.note&&<div style={{fontSize:11.5,color:C.ink4,fontStyle:"italic",fontFamily:"'Sarabun',sans-serif",marginTop:3,paddingLeft:4}}>* {i.note}</div>}
            {disc>0&&<div style={{fontSize:11.5,color:C.green,fontFamily:"'Sarabun',sans-serif",marginTop:3,paddingLeft:4}}>ลด {i.item_discount_type==="percent"?i.item_discount_value+"%":m(i.item_discount_value)}</div>}
          </div>;
        })}
      </div>
      <div style={{padding:"14px 18px",borderTop:`1px solid ${C.line}`,background:C.bg}}>
        <Row l="ยอดรวม" v={m(o.subtotal)}/>
        {+o.discount>0&&<Row l="ส่วนลดรวม" v={m(o.discount)} c={C.green} plus="-"/>}
        {+o.promo_amount>0&&<Row l={stripEmoji(o.promo_name||"โปรโมชั่น")} v={m(o.promo_amount)} c={C.green} plus="-"/>}
        {+o.service_charge>0&&<Row l="ค่าบริการ (Service)" v={m(o.service_charge)} plus="+"/>}
        {+o.vat>0&&<Row l={`VAT ${o.vat_rate||7}%${o.vat_included?" (รวมในราคา)":""}`} v={m(o.vat)} plus={o.vat_included?"":"+"}/>}
        <div style={{borderTop:`1px solid ${C.line}`,margin:"8px 0 0",paddingTop:10}}><Row l="รวมทั้งสิ้น" v={m(o.total)} big/></div>
        {paid&&o.payment_method==="cash"&&o.cash_received&&<div style={{marginTop:8}}><Row l="รับเงิน" v={m(o.cash_received)}/><Row l="เงินทอน" v={m(Math.max(0,(+o.cash_received)-(+o.total||0)))}/></div>}
        {paid&&<div style={{marginTop:8,paddingTop:8,borderTop:`1px dashed ${C.lineLight}`,fontSize:12.5,fontFamily:"'Sarabun',sans-serif",color:C.ink3,display:"flex",justifyContent:"space-between"}}><span>ชำระโดย</span><span style={{fontWeight:700,color:C.ink}}>{PAY_LABEL[o.payment_method]||o.payment_method||"-"}</span></div>}
      </div>
    </div>
  </div>;
}

function SalesReportModal({currentBranch,onClose}){
  const isoKey=(d)=>`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;  // machine key (ISO) — do NOT shadow the global BE fmtD
  const todayStr=isoKey(new Date());
  const[date,setDate]=useState(todayStr);
  const[filter,setFilter]=useState("all");
  const[orders,setOrders]=useState([]);
  const[loading,setLoading]=useState(true);
  const[bill,setBill]=useState(null);
  const aliveRef=useRef(true);
  useEffect(()=>()=>{aliveRef.current=false;},[]);
  useEffect(()=>{
    let cancel=false;setLoading(true);setBill(null);
    (async()=>{
      try{
        const start=new Date(date+"T00:00:00");const end=new Date(start.getTime()+86400000);
        const o=await api.getPOSOrdersByDay(currentBranch.id,start.toISOString(),end.toISOString());
        if(!cancel&&aliveRef.current)setOrders(Array.isArray(o)?o:[]);
      }catch(e){if(!cancel&&aliveRef.current)setOrders([]);}
      if(!cancel&&aliveRef.current)setLoading(false);
    })();
    return()=>{cancel=true;};
  },[date,currentBranch.id]);

  const paid=orders.filter(o=>o.status==="paid");
  const unpaid=orders.filter(o=>o.status!=="paid"&&o.status!=="cancelled");
  const cancelled=orders.filter(o=>o.status==="cancelled");
  const rev=paid.reduce((s,o)=>s+(+o.total||0),0);
  const avg=paid.length?rev/paid.length:0;
  const payBreak=Object.entries(paid.reduce((mm,o)=>{const k=o.payment_method||"other";if(!mm[k])mm[k]={sum:0,n:0};mm[k].sum+=(+o.total||0);mm[k].n+=1;return mm;},{})).sort((a,b)=>b[1].sum-a[1].sum);
  const baseList=filter==="paid"?paid:filter==="unpaid"?unpaid:[...paid,...unpaid];
  const list=baseList.slice().sort((a,b)=>new Date(b.created_at)-new Date(a.created_at));
  const m=(n)=>(+n||0).toLocaleString(undefined,{maximumFractionDigits:0});

  const isToday=date===todayStr;
  const shiftDay=(delta)=>{const d=new Date(date+"T00:00:00");d.setDate(d.getDate()+delta);const ns=isoKey(d);if(ns<=todayStr)setDate(ns);};
  const stC={pending:C.yellow,confirmed:C.green,bill_requested:C.brand,paid:C.green,cancelled:C.ink4};
  const stL={pending:"รอยืนยัน",confirmed:"กำลังทำ",bill_requested:"เรียกบิล",paid:"ชำระแล้ว",cancelled:"ยกเลิก"};
  const navBtn={width:34,height:34,borderRadius:9,border:`1px solid ${C.line}`,background:C.white,cursor:"pointer",fontSize:13,color:C.ink2,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0};

  return <Modal title="📊 รายงานยอดขาย" onClose={onClose} extraWide>
    {/* ── เลือกวัน ── */}
    <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:14,flexWrap:"wrap"}}>
      <button onClick={()=>shiftDay(-1)} style={navBtn} title="วันก่อนหน้า">◀</button>
      <input type="date" value={date} max={todayStr} onChange={e=>e.target.value&&setDate(e.target.value)} style={{padding:"8px 11px",borderRadius:9,border:`1px solid ${C.line}`,fontSize:13,fontFamily:"'Sarabun',sans-serif",color:C.ink,background:C.white}}/>
      <button onClick={()=>shiftDay(1)} disabled={isToday} style={{...navBtn,opacity:isToday?.4:1,cursor:isToday?"default":"pointer"}} title="วันถัดไป">▶</button>
      {!isToday&&<button onClick={()=>setDate(todayStr)} style={{padding:"8px 13px",borderRadius:9,border:`1px solid ${C.brand}`,background:`${C.brand}12`,color:C.brand,cursor:"pointer",fontSize:12.5,fontWeight:800,fontFamily:"'Sarabun',sans-serif"}}>วันนี้</button>}
      <span style={{marginLeft:"auto",fontSize:13,fontWeight:700,color:C.ink2,fontFamily:"'Sarabun',sans-serif"}}>{fmtD(date)}{isToday?" · วันนี้":""}</span>
    </div>

    {loading?<div style={{padding:"40px 0"}}><Loading text="กำลังโหลดรายงาน..."/></div>
    :bill?<BillDetailCard order={bill} onBack={()=>setBill(null)}/>
    :<>
      {/* ── สรุปยอด ── */}
      <div style={{display:"flex",gap:12,marginBottom:14,flexWrap:"wrap"}}>
        {[{l:"💰 ยอดขาย (ปิดบิลแล้ว)",v:`฿${m(rev)}`,c:C.green},
          {l:"🧾 บิลปิดแล้ว",v:paid.length,c:C.blue},
          {l:"⏳ ยังไม่ปิดบิล",v:unpaid.length,c:C.yellow},
          {l:"📈 เฉลี่ย/บิล",v:`฿${m(avg)}`,c:C.brand}].map(s=><div key={s.l} style={{flex:"1 1 140px",background:C.white,borderRadius:12,padding:"12px 16px",border:`1px solid ${C.line}`}}><div style={{fontSize:11.5,color:C.ink4,fontFamily:"'Sarabun',sans-serif"}}>{s.l}</div><div style={{fontSize:20,fontWeight:900,color:s.c,fontFamily:"'Sarabun',sans-serif"}}>{s.v}</div></div>)}
      </div>
      {payBreak.length>0&&<div style={{background:C.bg,borderRadius:12,padding:"12px 16px",marginBottom:14,border:`1px solid ${C.line}`}}>
        <div style={{fontSize:12.5,fontWeight:800,color:C.ink,fontFamily:"'Sarabun',sans-serif",marginBottom:8}}>💳 แยกตามวิธีชำระเงิน</div>
        <div style={{display:"flex",flexDirection:"column",gap:6}}>
          {payBreak.map(([k,v])=><div key={k} style={{display:"flex",justifyContent:"space-between",alignItems:"center",fontSize:12.5,fontFamily:"'Sarabun',sans-serif"}}><span style={{color:C.ink2}}>{PAY_LABEL[k]||k} <span style={{color:C.ink4}}>· {v.n} บิล</span></span><span style={{fontWeight:800,color:C.ink}}>฿{m(v.sum)}</span></div>)}
        </div>
      </div>}
      {/* ── ตัวกรอง: ทั้งหมด / ปิดบิลแล้ว / ยังไม่ปิดบิล ── */}
      <div style={{display:"flex",gap:6,marginBottom:12,flexWrap:"wrap",alignItems:"center"}}>
        {[{id:"all",l:"ทั้งหมด",n:paid.length+unpaid.length},{id:"paid",l:"ปิดบิลแล้ว",n:paid.length},{id:"unpaid",l:"ยังไม่ปิดบิล",n:unpaid.length}].map(t=>{const on=filter===t.id;return <button key={t.id} onClick={()=>setFilter(t.id)} style={{padding:"7px 14px",borderRadius:20,border:`1px solid ${on?C.brand:C.line}`,background:on?C.brand:C.white,color:on?C.white:C.ink2,cursor:"pointer",fontSize:12.5,fontWeight:on?800:600,fontFamily:"'Sarabun',sans-serif"}}>{t.l} ({t.n})</button>;})}
        {cancelled.length>0&&<span style={{marginLeft:"auto",fontSize:11.5,color:C.ink4,fontFamily:"'Sarabun',sans-serif"}}>ยกเลิก {cancelled.length} บิล</span>}
      </div>
      {/* ── รายการบิล (กดเข้าดูรายละเอียด) ── */}
      {list.length===0?<div style={{textAlign:"center",padding:"40px 0",color:C.ink4}}><Ic d={I.order} s={46} c={C.line}/><p style={{marginTop:12,fontFamily:"'Sarabun',sans-serif"}}>ไม่มีบิลในวันนี้</p></div>
      :<div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(min(260px,100%),1fr))",gap:10}}>
        {list.map(o=><button key={o.id} onClick={()=>setBill(o)} style={{textAlign:"left",background:C.white,borderRadius:12,border:`1px solid ${C.line}`,overflow:"hidden",cursor:"pointer",padding:0,fontFamily:"'Sarabun',sans-serif",transition:"box-shadow .15s,border-color .15s"}} onMouseEnter={e=>{e.currentTarget.style.boxShadow="0 4px 14px rgba(0,0,0,0.08)";e.currentTarget.style.borderColor=C.brand;}} onMouseLeave={e=>{e.currentTarget.style.boxShadow="none";e.currentTarget.style.borderColor=C.line;}}>
          <div style={{padding:"9px 12px",background:C.bg,borderBottom:`1px solid ${C.line}`,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <span style={{fontWeight:800,fontSize:14,color:C.ink}}>โต๊ะ {o.table_number}</span>
            <span style={{fontSize:11,fontWeight:700,color:stC[o.status]||C.ink3,background:`${stC[o.status]||C.ink3}22`,padding:"2px 8px",borderRadius:20}}>{stL[o.status]||o.status}</span>
          </div>
          <div style={{padding:"9px 12px"}}>
            {(o.items||[]).slice(0,3).map((i,idx)=><div key={idx} style={{display:"flex",justifyContent:"space-between",fontSize:12,marginBottom:2,gap:8}}><span style={{color:C.ink2,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{i.qty}x {i.name}</span><span style={{color:C.brand,fontWeight:700,whiteSpace:"nowrap"}}>฿{m((+i.price||0)*(+i.qty||0))}</span></div>)}
            {(o.items||[]).length>3&&<div style={{fontSize:11,color:C.ink4}}>+อีก {o.items.length-3} รายการ</div>}
            {(o.items||[]).length===0&&<div style={{fontSize:11.5,color:C.ink4}}>ไม่มีรายการ</div>}
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:6,paddingTop:6,borderTop:`1px solid ${C.lineLight}`}}>
              <span style={{fontSize:11,color:C.ink4}}>{new Date(o.created_at).toLocaleTimeString("th-TH",{hour:'2-digit',minute:'2-digit'})}</span>
              <span style={{fontSize:14,fontWeight:900,color:C.ink}}>฿{m(o.total)}</span>
            </div>
            <div style={{fontSize:11,color:C.brand,fontWeight:700,marginTop:6,textAlign:"right"}}>ดูรายละเอียด →</div>
          </div>
        </button>)}
      </div>}
    </>}
  </Modal>;
}

// ══════════════════════════════════════════════════════
// ── POS TAB (top-level wrapper: mode + shift) ────────
// ══════════════════════════════════════════════════════
function POSTab({menus,currentBranch,currentUser,printers=[],branches=[],reloadPrinters,reloadMenus,saleOnly=false,onExit,refreshTick=0,closeShiftSignal=0,onShiftState}){
  // saleOnly = PIN-cashier kiosk: jump straight to the sale screen, no chooser,
  // no back office; "exit" logs the cashier out (back to the PIN gate).
  const[mode,setMode]=useState(saleOnly?'sale':null);  // null | 'sale' | 'manage'
  const[shift,setShift]=useState(null);
  const[loadingShift,setLoadingShift]=useState(false);
  const[showCashDrawer,setShowCashDrawer]=useState(false);
  const[showCloseShift,setShowCloseShift]=useState(false);
  const[zones,setZones]=useState([]);
  const[posSettings,setPosSettings]=useState(null);
  const[promotions,setPromotions]=useState([]);
  async function loadZones(){try{const z=await api.getZones(currentBranch.id);setZones(z);}catch(e){console.error("loadZones",e);}}
  async function loadPosSettings(){try{const s=await api.getPOSSettings(currentBranch.id);setPosSettings(s&&s[0]?s[0]:{branch_id:currentBranch.id,vat_enabled:false,vat_rate:7,vat_included:true,service_charge_enabled:false,service_charge_rate:10});}catch{setPosSettings({branch_id:currentBranch.id,vat_enabled:false,vat_rate:7,vat_included:true,service_charge_enabled:false,service_charge_rate:10});}}
  async function loadPromotions(){try{const p=await api.getPromotions(currentBranch.id);setPromotions(p);}catch{setPromotions([]);}}
  useEffect(()=>{loadZones();loadPosSettings();loadPromotions();},[currentBranch.id]);

  useEffect(()=>{
    if(mode!=='sale'){setShift(null);return;}
    setLoadingShift(true);
    api.getActiveShift(currentBranch.id).then(s=>{
      setShift(s&&s.length?s[0]:null);
      setLoadingShift(false);
    }).catch(e=>{setLoadingShift(false);alert("โหลดข้อมูลกะไม่สำเร็จ: "+e.message);});
  },[mode,currentBranch.id]);
  // รายงานสถานะ "มีกะเปิดอยู่ไหม" ให้ตัวห่อหุ้ม (kiosk bar) ใช้โชว์/ซ่อนปุ่มปิดกะ + รับสัญญาณกดปิดกะจากบาร์ด้านบน
  useEffect(()=>{if(onShiftState)onShiftState(mode==='sale'&&!!shift);},[mode,shift]);// eslint-disable-line
  useEffect(()=>{if(closeShiftSignal>0&&mode==='sale'&&shift)setShowCloseShift(true);},[closeShiftSignal]);// eslint-disable-line

  const canManage=!saleOnly&&hasPerm(currentUser,"settings");
  // Where "exit" goes: kiosk cashier → logout to PIN gate; normal user → mode chooser.
  const exitSale=()=>{if(saleOnly){onExit&&onExit();}else{setMode(null);}};
  if(mode===null)return <POSModeSelect onSelect={setMode} canManage={canManage}/>;
  if(mode==='manage'){
    if(!canManage){setMode(null);return null;}
    return <POSBackOffice currentBranch={currentBranch} currentUser={currentUser} printers={printers} reloadPrinters={reloadPrinters} branches={branches} zones={zones} reloadZones={loadZones} menus={menus} reloadMenus={reloadMenus} onExit={()=>{setMode(null);loadZones();loadPosSettings();loadPromotions();}}/>;
  }
  // mode === 'sale'
  if(loadingShift)return <Loading text="ตรวจสอบกะการขาย..."/>;
  if(!shift)return <OpenShiftModal currentBranch={currentBranch} currentUser={currentUser} onDone={s=>setShift(s)} onCancel={exitSale}/>;
  return <>
    <POSSaleMode menus={menus} reloadMenus={reloadMenus} currentBranch={currentBranch} currentUser={currentUser} printers={printers} shift={shift} zones={zones} posSettings={posSettings} promotions={promotions} onUpdateShift={setShift} onCashDrawer={()=>setShowCashDrawer(true)} onCloseShift={()=>setShowCloseShift(true)} onExitMode={exitSale} saleOnly={saleOnly} reloadPosSettings={loadPosSettings} refreshTick={refreshTick} reloadZones={loadZones}/>
    {showCashDrawer&&<CashDrawerModal shift={shift} currentBranch={currentBranch} currentUser={currentUser} onClose={()=>setShowCashDrawer(false)}/>}
    {showCloseShift&&<CloseShiftModal shift={shift} currentBranch={currentBranch} currentUser={currentUser} onClose={()=>setShowCloseShift(false)} onClosed={()=>{setShowCloseShift(false);setShowCashDrawer(false);setShift(null);if(!saleOnly)setMode(null);}}/>}
  </>;
}

// ══════════════════════════════════════════════════════
// ── POS PIN GATE (cashier sell link: ?pos=1&branch=ID) ─
// ══════════════════════════════════════════════════════
// Branch staff open the branch's sell link, type their 4-digit PIN, and drop
// straight into the sale screen. PINs are defined per-branch in POS back office
// (stored in pos_settings.sales_staff). No username/password, no main app.
function POSPinGate({branchId}){
  const[branch,setBranch]=useState(null);
  const[staff,setStaff]=useState([]);
  const[menus,setMenus]=useState([]);
  const[printers,setPrinters]=useState([]);
  const[loading,setLoading]=useState(true);
  const[err,setErr]=useState("");
  const[pin,setPin]=useState("");
  const[seller,setSeller]=useState(null);
  const[shake,setShake]=useState(false);
  const[tick,setTick]=useState(0);
  const[posRefreshTick,setPosRefreshTick]=useState(0);   // kiosk header → triggers POSSaleMode.loadAll
  const[shiftOpen,setShiftOpen]=useState(false);         // มีกะเปิดอยู่ไหม (POSTab รายงานมา) → โชว์ปุ่มปิดกะบนแถบบน
  const[closeShiftReq,setCloseShiftReq]=useState(0);     // กดปุ่มปิดกะบนแถบบน → ส่งสัญญาณให้ POSTab เปิดหน้าปิดกะ
  useEffect(()=>{
    let alive=true;setLoading(true);setErr("");
    (async()=>{
      try{
        const[bs,ps,ms,prs]=await Promise.all([api.getBranches(),api.getPOSSettings(branchId),api.getMenus(),api.getAllPrinters()]);
        if(!alive)return;
        const b=(bs||[]).find(x=>+x.id===+branchId);
        if(!b){setErr("ไม่พบสาขานี้ — ลิงก์อาจไม่ถูกต้อง");setLoading(false);return;}
        if(b.active===false){setErr("สาขานี้ถูกปิดใช้งาน");setLoading(false);return;}
        if(b.type==="central"){setErr("ครัวกลางไม่ได้เปิดขายหน้าร้าน");setLoading(false);return;}
        const settings=ps&&ps[0]?ps[0]:null;
        setBranch(b);setStaff(Array.isArray(settings?.sales_staff)?settings.sales_staff:[]);
        setMenus(ms||[]);setPrinters(prs||[]);
      }catch(e){if(alive)setErr(e&&e.message||String(e));}
      if(alive)setLoading(false);
    })();
    return()=>{alive=false;};
  },[branchId,tick]);
  useEffect(()=>{
    if(pin.length<4)return;
    const code=pin.slice(0,4);
    const found=(staff||[]).find(s=>s&&s.active!==false&&String(s.pin)===code);
    if(found){setSeller(found);setPin("");}
    else{setShake(true);setTimeout(()=>{setShake(false);setPin("");},480);}
  // eslint-disable-next-line react-hooks/exhaustive-deps
  },[pin]);
  const isMobile=useIsMobile();
  if(loading)return <><style>{globalStyle}</style><div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",background:`linear-gradient(135deg,${C.brandLight},#FEF3C7)`}}><Loading text="กำลังโหลด..."/></div></>;
  if(err)return <><style>{globalStyle}</style><div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",background:`linear-gradient(135deg,${C.redLight},#FEF3C7)`,padding:20,fontFamily:"'Sarabun',sans-serif"}}>
    <div style={{background:C.white,borderRadius:18,padding:"32px 28px",maxWidth:380,width:"100%",textAlign:"center",boxShadow:"0 20px 60px rgba(0,0,0,.12)"}}>
      <div style={{fontSize:48,marginBottom:10}}>⚠️</div>
      <div style={{fontSize:16,fontWeight:900,color:C.red,marginBottom:8}}>เปิดหน้าขายไม่ได้</div>
      <div style={{fontSize:13,color:C.ink3,marginBottom:16,lineHeight:1.6}}>{err}</div>
      <button onClick={()=>setTick(t=>t+1)} style={{background:C.brand,color:C.white,border:"none",borderRadius:10,padding:"10px 20px",cursor:"pointer",fontFamily:"'Sarabun',sans-serif",fontSize:14,fontWeight:800}}>ลองอีกครั้ง</button>
    </div>
  </div></>;
  // Authenticated → kiosk sale screen
  if(seller){
    const synthUser={id:null,username:seller.name||"พนักงานขาย",name:seller.name||"พนักงานขาย",role:"staff",perms:["pos"]};
    return <><style>{globalStyle}</style>
      <div style={{minHeight:"100vh",display:"flex",flexDirection:"column",background:C.bg}}>
        <div style={{display:"flex",alignItems:"center",gap:12,padding:isMobile?"10px 14px":"12px 22px",background:"linear-gradient(135deg,#0F172A,#1E293B)",color:"#F8FAFC",flexShrink:0,boxShadow:"0 2px 10px rgba(15,23,42,.25)"}}>
          <div style={{width:34,height:34,borderRadius:10,background:`linear-gradient(135deg,${C.brand},${C.brandDark})`,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}><Ic d={I.shop} s={18} c="#fff"/></div>
          <div style={{minWidth:0,flex:1,display:"flex",alignItems:"center",gap:10}}>
            <div style={{minWidth:0}}>
              <div style={{fontFamily:"'Sarabun',sans-serif",fontSize:14,fontWeight:900,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>🛒 ขายหน้าร้าน · {branch.name}</div>
              <div style={{fontFamily:"'Sarabun',sans-serif",fontSize:11,color:"#94A3B8"}}>พนักงาน: {seller.name}</div>
            </div>
            <button onClick={()=>setPosRefreshTick(t=>t+1)} title="รีเฟรชข้อมูลโต๊ะ/ออเดอร์" style={{background:"rgba(255,255,255,0.1)",border:"1px solid rgba(255,255,255,0.2)",borderRadius:8,padding:"6px 12px",cursor:"pointer",color:"#E2E8F0",fontFamily:"'Sarabun',sans-serif",fontSize:12,fontWeight:800,flexShrink:0,display:"inline-flex",alignItems:"center",gap:5,whiteSpace:"nowrap"}}><Ic d={I.refresh} s={13} c="#E2E8F0"/>รีเฟรช</button>
          </div>
          {shiftOpen&&<button onClick={()=>setCloseShiftReq(n=>n+1)} title="ปิดกะการขาย & พิมพ์สรุปยอด" style={{background:"linear-gradient(135deg,#EF4444,#DC2626)",border:"none",borderRadius:11,padding:isMobile?"10px 18px":"12px 26px",cursor:"pointer",color:"#fff",fontFamily:"'Sarabun',sans-serif",fontSize:isMobile?14.5:16,fontWeight:900,flexShrink:0,display:"inline-flex",alignItems:"center",gap:7,boxShadow:"0 3px 12px rgba(239,68,68,.4)",whiteSpace:"nowrap"}}>🔚 ปิดกะ</button>}
        </div>
        <div style={{flex:1,padding:isMobile?"14px 12px":"20px 24px",minWidth:0,minHeight:0}}>
          <POSTab menus={menus} reloadMenus={async()=>{try{setMenus(await api.getMenus());}catch{}}} currentBranch={branch} currentUser={synthUser} printers={printers} branches={[]} reloadPrinters={async()=>{try{setPrinters(await api.getAllPrinters());}catch{}}} saleOnly onExit={()=>{setSeller(null);setPin("");}} refreshTick={posRefreshTick} closeShiftSignal={closeShiftReq} onShiftState={setShiftOpen}/>
        </div>
      </div>
    </>;
  }
  // PIN pad
  const keys=["1","2","3","4","5","6","7","8","9","del","0","ok"];
  return <><style>{globalStyle}</style>
    <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",background:`linear-gradient(135deg,${C.brandLight} 0%,#FEF3C7 50%,${C.blueLight} 100%)`,padding:16,fontFamily:"'Sarabun',sans-serif"}}>
      <div style={{background:C.white,borderRadius:24,padding:isMobile?"28px 22px":"36px 32px",width:"100%",maxWidth:360,boxShadow:"0 30px 80px rgba(15,23,42,.18)",animation:shake?"shakeX .45s":"mIn .4s cubic-bezier(.34,1.56,.64,1)"}}>
        <div style={{textAlign:"center",marginBottom:22}}>
          <div style={{width:60,height:60,background:`linear-gradient(135deg,${C.brand},${C.brandDark})`,borderRadius:18,display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 12px",boxShadow:`0 10px 26px ${C.brand}44`}}><Ic d={I.shop} s={28} c="#fff"/></div>
          <h1 style={{fontSize:18,fontWeight:900,color:C.ink,margin:"0 0 2px"}}>ขายหน้าร้าน</h1>
          <p style={{fontSize:13,color:C.ink3,margin:0}}>{branch.name}</p>
        </div>
        <div style={{fontSize:12.5,color:C.ink3,textAlign:"center",marginBottom:12,fontWeight:600}}>ใส่ PIN พนักงานขาย 4 หลัก</div>
        <div style={{display:"flex",justifyContent:"center",gap:12,marginBottom:22}}>
          {[0,1,2,3].map(i=><div key={i} style={{width:16,height:16,borderRadius:"50%",background:i<pin.length?C.brand:C.lineLight,border:`2px solid ${i<pin.length?C.brand:C.line}`,transition:"all .15s"}}/>)}
        </div>
        {staff.length===0&&<div style={{background:C.yellowLight,border:`1px solid ${C.yellow}55`,borderRadius:10,padding:"10px 12px",fontSize:11.5,color:"#92400E",textAlign:"center",marginBottom:16,lineHeight:1.6}}>⚠️ สาขานี้ยังไม่ได้กำหนดพนักงานขาย<br/>ให้ผู้จัดการเพิ่มที่ "หลังบ้าน → พนักงานขาย"</div>}
        <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10}}>
          {keys.map(k=>{
            if(k==="del")return <button key={k} onClick={()=>setPin(p=>p.slice(0,-1))} style={{padding:"16px 0",borderRadius:14,border:`1.5px solid ${C.line}`,background:C.bg,cursor:"pointer",fontSize:18,fontFamily:"'Sarabun',sans-serif",fontWeight:800,color:C.ink3}}>⌫</button>;
            if(k==="ok")return <button key={k} disabled style={{padding:"16px 0",borderRadius:14,border:"none",background:"transparent",cursor:"default"}}/>;
            return <button key={k} onClick={()=>setPin(p=>(p+k).slice(0,4))} style={{padding:"16px 0",borderRadius:14,border:`1.5px solid ${C.line}`,background:C.white,cursor:"pointer",fontSize:22,fontFamily:"'Sarabun',sans-serif",fontWeight:800,color:C.ink,transition:"all .1s"}} onMouseDown={e=>{e.currentTarget.style.background=C.brandLight;e.currentTarget.style.borderColor=C.brand;}} onMouseUp={e=>{e.currentTarget.style.background=C.white;e.currentTarget.style.borderColor=C.line;}} onMouseLeave={e=>{e.currentTarget.style.background=C.white;e.currentTarget.style.borderColor=C.line;}}>{k}</button>;
          })}
        </div>
      </div>
    </div>
  </>;
}


// BranchSelector with auto-load branches
function BranchSelectorWithLoad({user,onSelect,onLogout}){
  const[branches,setBranches]=useState([]);const[loading,setLoading]=useState(true);
  useEffect(()=>{api.getBranches().then(b=>setBranches(b)).finally(()=>setLoading(false));},[]);
  if(loading)return <><style>{globalStyle}</style><div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center"}}><Loading text="กำลังโหลดรายการสาขา..."/></div></>;
  return <BranchSelector branches={branches} onSelect={onSelect} user={user} onLogout={onLogout}/>;
}

const globalStyle=`@import url('https://fonts.googleapis.com/css2?family=Sarabun:wght@400;500;600;700;800;900&display=swap');*{margin:0;padding:0;box-sizing:border-box}html,body{max-width:100vw;overflow-x:hidden}body{background:${C.bg};font-family:'Sarabun',sans-serif;-webkit-text-size-adjust:100%;-webkit-tap-highlight-color:transparent}@keyframes mIn{from{opacity:0;transform:scale(.94) translateY(10px)}to{opacity:1;transform:scale(1) translateY(0)}}@keyframes spin{from{transform:rotate(0deg)}to{transform:rotate(360deg)}}@keyframes slideInLeft{from{transform:translateX(-100%)}to{transform:translateX(0)}}@keyframes shakeX{0%,100%{transform:translateX(0)}20%,60%{transform:translateX(-9px)}40%,80%{transform:translateX(9px)}}*{scrollbar-color:${C.ink4} ${C.lineLight};scrollbar-width:auto}::-webkit-scrollbar{width:12px;height:12px}::-webkit-scrollbar-track{background:${C.lineLight};border-radius:999px}::-webkit-scrollbar-thumb{background:${C.ink4};border-radius:999px;border:2px solid ${C.lineLight};min-height:40px}::-webkit-scrollbar-thumb:hover{background:${C.brand};border-color:${C.brandLight}}::-webkit-scrollbar-thumb:active{background:${C.brandDark}}::-webkit-scrollbar-corner{background:transparent}input,select,textarea{font-size:16px}input:focus,select:focus,textarea:focus{border-color:${C.brand}!important;box-shadow:0 0 0 3px ${C.brandLight}!important;outline:none}button{touch-action:manipulation}@media(max-width:768px){button{min-height:36px}input,select,textarea{min-height:40px;font-size:16px!important}input[type=checkbox],input[type=radio]{min-height:auto}table{font-size:12px}::-webkit-scrollbar{width:8px;height:8px}::-webkit-scrollbar-thumb{border-width:1px}}@media(max-width:480px){h1,h2,h3{letter-spacing:-.2px!important}}`;
